#[allow(clippy::type_complexity)]
fn hgetall(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HGETALL"));
    }
    let pairs = store.hgetall(&argv[1], now_ms)?;
    // Upstream Redis 7.2 returns an Array (alternating k/v) in RESP2
    // and a Map (k → v) in RESP3 — see networking.c::addReplyMap*.
    // Mirror that here. (br-frankenredis-9itc partial)
    if store.dispatch_client_ctx.resp_protocol_version == 3 {
        let mut entries = Vec::with_capacity(pairs.len());
        for (field, value) in pairs {
            entries.push((
                RespFrame::BulkString(Some(field)),
                RespFrame::BulkString(Some(value)),
            ));
        }
        Ok(RespFrame::Map(Some(entries)))
    } else {
        let mut frames = Vec::with_capacity(pairs.len() * 2);
        for (field, value) in pairs {
            frames.push(RespFrame::BulkString(Some(field)));
            frames.push(RespFrame::BulkString(Some(value)));
        }
        Ok(RespFrame::Array(Some(frames)))
    }
}

fn hkeys(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HKEYS"));
    }
    let keys = store.hkeys(&argv[1], now_ms)?;
    let frames = keys
        .into_iter()
        .map(|k| RespFrame::BulkString(Some(k)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn hvals(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("HVALS"));
    }
    let vals = store.hvals(&argv[1], now_ms)?;
    let frames = vals
        .into_iter()
        .map(|v| RespFrame::BulkString(Some(v)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn hmget(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("HMGET"));
    }
    let fields: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    let values = store.hmget(&argv[1], &fields, now_ms)?;
    let frames = values.into_iter().map(RespFrame::BulkString).collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn hmset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 || !(argv.len() - 2).is_multiple_of(2) {
        return Err(CommandError::WrongArity("HMSET"));
    }
    let mut i = 2;
    while i + 1 < argv.len() {
        store.hset(&argv[1], argv[i].clone(), argv[i + 1].clone(), now_ms)?;
        i += 2;
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn hincrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("HINCRBY"));
    }
    let delta = parse_i64_arg(&argv[3])?;
    let value = store.hincrby(&argv[1], &argv[2], delta, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn hsetnx_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("HSETNX"));
    }
    let set = store.hsetnx(&argv[1], argv[2].clone(), argv[3].clone(), now_ms)?;
    Ok(RespFrame::Integer(if set { 1 } else { 0 }))
}

fn hstrlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("HSTRLEN"));
    }
    let len = store.hstrlen(&argv[1], &argv[2], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

// ── HEXPIRE family (Redis 7.4) ──────────────────────────────────────
//
// Part 2 of br-frankenredis-rv89. Implements the 9 hash field TTL
// commands on top of the fr-store primitives landed in
// br-frankenredis-wwz3.

/// Whether an HEXPIRE-style argument is seconds or milliseconds.
#[derive(Clone, Copy, Debug)]
enum HExpireForm {
    Seconds,
    Milliseconds,
}

fn hexpire_command_name(form: HExpireForm, absolute: bool) -> &'static str {
    match (form, absolute) {
        (HExpireForm::Seconds, false) => "HEXPIRE",
        (HExpireForm::Milliseconds, false) => "HPEXPIRE",
        (HExpireForm::Seconds, true) => "HEXPIREAT",
        (HExpireForm::Milliseconds, true) => "HPEXPIREAT",
    }
}

fn httl_command_name(unit: HashFieldTtlUnit, absolute: bool) -> &'static str {
    match (unit, absolute) {
        (HashFieldTtlUnit::Seconds, false) => "HTTL",
        (HashFieldTtlUnit::Milliseconds, false) => "HPTTL",
        (HashFieldTtlUnit::Seconds, true) => "HEXPIRETIME",
        (HashFieldTtlUnit::Milliseconds, true) => "HPEXPIRETIME",
    }
}

/// Parse `[NX|XX|GT|LT]` optional flag + mandatory `FIELDS numfields` prefix.
/// Returns `(condition, field_start_index, numfields)`.
fn parse_hash_field_ttl_flags_and_fields_header(
    argv: &[Vec<u8>],
    after_value_idx: usize,
    command_name: &'static str,
) -> Result<(HashFieldTtlCondition, usize, usize), CommandError> {
    let mut cond = HashFieldTtlCondition::None;
    let mut idx = after_value_idx;
    if idx < argv.len() {
        let tok = std::str::from_utf8(&argv[idx]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let matched = if tok.eq_ignore_ascii_case("NX") {
            cond = HashFieldTtlCondition::Nx;
            true
        } else if tok.eq_ignore_ascii_case("XX") {
            cond = HashFieldTtlCondition::Xx;
            true
        } else if tok.eq_ignore_ascii_case("GT") {
            cond = HashFieldTtlCondition::Gt;
            true
        } else if tok.eq_ignore_ascii_case("LT") {
            cond = HashFieldTtlCondition::Lt;
            true
        } else {
            false
        };
        if matched {
            idx += 1;
        }
    }
    // FIELDS <numfields> field [field ...]
    if idx >= argv.len() {
        return Err(CommandError::WrongArity(command_name));
    }
    let token = std::str::from_utf8(&argv[idx]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if !token.eq_ignore_ascii_case("FIELDS") {
        return Err(CommandError::SyntaxError);
    }
    idx += 1;
    if idx >= argv.len() {
        return Err(CommandError::WrongArity(command_name));
    }
    let numfields = parse_i64_arg(&argv[idx])?;
    if numfields < 1 {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` should be greater than 0".to_string(),
        ));
    }
    let numfields = usize::try_from(numfields).map_err(|_| CommandError::InvalidInteger)?;
    idx += 1;
    let remaining = argv.len().saturating_sub(idx);
    if remaining != numfields {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` is more than number of arguments".to_string(),
        ));
    }
    Ok((cond, idx, numfields))
}

fn hexpire_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    form: HExpireForm,
    absolute: bool,
) -> Result<RespFrame, CommandError> {
    let cmd_name = hexpire_command_name(form, absolute);
    // argv[0]=CMD, [1]=key, [2]=N, [3..]=[flag]+FIELDS+numfields+fields...
    // Minimum legal form (fields header present): 5 args + at least 1 field → 6.
    // With 5 args we still enter parsing so the numfields-zero / missing-FIELDS
    // error wins over the generic arity error, matching upstream's error
    // precedence.
    if argv.len() < 5 {
        return Err(CommandError::WrongArity(cmd_name));
    }
    let key = argv[1].as_slice();
    let raw_value = parse_i64_arg(&argv[2])?;
    // Compute absolute deadline in ms.
    let deadline_ms: u64 = match (form, absolute) {
        (HExpireForm::Seconds, false) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hexpire' command".to_string(),
                ));
            }
            now_ms.saturating_add((raw_value as u64).saturating_mul(1000))
        }
        (HExpireForm::Milliseconds, false) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hpexpire' command".to_string(),
                ));
            }
            now_ms.saturating_add(raw_value as u64)
        }
        (HExpireForm::Seconds, true) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hexpireat' command".to_string(),
                ));
            }
            (raw_value as u64).saturating_mul(1000)
        }
        (HExpireForm::Milliseconds, true) => {
            if raw_value < 0 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'hpexpireat' command".to_string(),
                ));
            }
            raw_value as u64
        }
    };

    let (cond, fields_start, numfields) =
        parse_hash_field_ttl_flags_and_fields_header(argv, 3, cmd_name)?;

    // Upstream emits "hexpire"/"hpexpire"/"hexpireat"/"hpexpireat" events on
    // every successful (including already-expired) per-field TTL set.
    // (br-frankenredis-7jhg)
    let event = match (form, absolute) {
        (HExpireForm::Seconds, false) => "hexpire",
        (HExpireForm::Milliseconds, false) => "hpexpire",
        (HExpireForm::Seconds, true) => "hexpireat",
        (HExpireForm::Milliseconds, true) => "hpexpireat",
    };
    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        let outcome = store.hash_field_set_abs_expiry_with_event(
            key,
            field,
            deadline_ms,
            cond,
            now_ms,
            event,
        );
        let code = match outcome {
            HashFieldTtlSet::Applied => 1,
            HashFieldTtlSet::AppliedAlreadyExpired => 2,
            HashFieldTtlSet::ConditionNotMet => 0,
            HashFieldTtlSet::FieldMissing => -2,
            HashFieldTtlSet::KeyMissing => -2,
            HashFieldTtlSet::WrongType => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
        };
        replies.push(RespFrame::Integer(code));
    }
    Ok(RespFrame::Array(Some(replies)))
}

fn parse_hash_field_ttl_fields_only_header(
    argv: &[Vec<u8>],
    command_name: &'static str,
) -> Result<(usize, usize), CommandError> {
    // argv[0]=CMD, [1]=key, [2]="FIELDS", [3]=numfields, [4..]=fields
    if argv.len() < 5 {
        return Err(CommandError::WrongArity(command_name));
    }
    let token = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if !token.eq_ignore_ascii_case("FIELDS") {
        return Err(CommandError::SyntaxError);
    }
    let numfields = parse_i64_arg(&argv[3])?;
    if numfields < 1 {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` should be greater than 0".to_string(),
        ));
    }
    let numfields = usize::try_from(numfields).map_err(|_| CommandError::InvalidInteger)?;
    let fields_start = 4;
    let remaining = argv.len().saturating_sub(fields_start);
    if remaining != numfields {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` is more than number of arguments".to_string(),
        ));
    }
    Ok((fields_start, numfields))
}

fn httl_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    unit: HashFieldTtlUnit,
    absolute: bool,
) -> Result<RespFrame, CommandError> {
    let cmd_name = httl_command_name(unit, absolute);
    let (fields_start, numfields) = parse_hash_field_ttl_fields_only_header(argv, cmd_name)?;
    let key = argv[1].as_slice();

    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        let ttl = store.hash_field_ttl(key, field, now_ms, unit, absolute);
        let code: i64 = match ttl {
            HashFieldTtl::Remaining(v) => i64::try_from(v).unwrap_or(i64::MAX),
            HashFieldTtl::NoTtl => -1,
            HashFieldTtl::FieldMissing => -2,
            HashFieldTtl::KeyMissing => -2,
            HashFieldTtl::WrongType => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
            // Expired field is surfaced the same as FieldMissing at the wire
            // (upstream reaps the field before reporting); part 3 wires the
            // actual lazy-delete so this branch becomes observable.
            HashFieldTtl::Expired => -2,
        };
        replies.push(RespFrame::Integer(code));
    }
    Ok(RespFrame::Array(Some(replies)))
}

/// HGETEX key [EX sec | PX ms | EXAT unix-s | PXAT unix-ms | PERSIST] FIELDS n ...
///
/// Returns an array of bulk strings: the value of each requested field (or
/// nil for missing / just-reaped fields). When a TTL-modifying flag is
/// present, also updates the per-field TTL for each requested field using
/// the upstream-matching semantics (set to the provided deadline, or drop
/// with PERSIST).
fn hgetex_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Minimum: HGETEX key FIELDS n f1 → 5 args. No TTL flag is allowed too.
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("HGETEX"));
    }
    let key = argv[1].as_slice();

    // Optional TTL modifier at argv[2..]. One of:
    //   EX sec   PX ms   EXAT unix-s   PXAT unix-ms   PERSIST
    #[derive(Clone, Copy)]
    enum TtlAction {
        None,
        SetAbsMs(u64),
        Persist,
    }
    let (ttl_action, fields_token_idx) = {
        if argv.len() >= 5 {
            let tok =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if tok.eq_ignore_ascii_case("FIELDS") {
                (TtlAction::None, 2)
            } else if tok.eq_ignore_ascii_case("PERSIST") {
                (TtlAction::Persist, 3)
            } else if tok.eq_ignore_ascii_case("EX")
                || tok.eq_ignore_ascii_case("PX")
                || tok.eq_ignore_ascii_case("EXAT")
                || tok.eq_ignore_ascii_case("PXAT")
            {
                if argv.len() < 7 {
                    return Err(CommandError::WrongArity("HGETEX"));
                }
                let raw = parse_i64_arg(&argv[3])?;
                if raw < 0 {
                    return Err(CommandError::Custom(
                        "ERR invalid expire time in 'hgetex' command".to_string(),
                    ));
                }
                let deadline = if tok.eq_ignore_ascii_case("EX") {
                    now_ms.saturating_add((raw as u64).saturating_mul(1000))
                } else if tok.eq_ignore_ascii_case("PX") {
                    now_ms.saturating_add(raw as u64)
                } else if tok.eq_ignore_ascii_case("EXAT") {
                    (raw as u64).saturating_mul(1000)
                } else {
                    raw as u64
                };
                (TtlAction::SetAbsMs(deadline), 4)
            } else {
                return Err(CommandError::SyntaxError);
            }
        } else {
            return Err(CommandError::WrongArity("HGETEX"));
        }
    };

    // Parse the mandatory FIELDS numfields header.
    if fields_token_idx >= argv.len() {
        return Err(CommandError::WrongArity("HGETEX"));
    }
    let tok = std::str::from_utf8(&argv[fields_token_idx])
        .map_err(|_| CommandError::InvalidUtf8Argument)?;
    if !tok.eq_ignore_ascii_case("FIELDS") {
        return Err(CommandError::SyntaxError);
    }
    let num_idx = fields_token_idx + 1;
    if num_idx >= argv.len() {
        return Err(CommandError::WrongArity("HGETEX"));
    }
    let numfields = parse_i64_arg(&argv[num_idx])?;
    if numfields < 1 {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` should be greater than 0".to_string(),
        ));
    }
    let numfields = usize::try_from(numfields).map_err(|_| CommandError::InvalidInteger)?;
    let fields_start = num_idx + 1;
    let remaining = argv.len().saturating_sub(fields_start);
    if remaining != numfields {
        return Err(CommandError::Custom(
            "ERR Parameter `numFields` is more than number of arguments".to_string(),
        ));
    }

    // Read each field's value first (before mutating TTL) so the returned
    // vector reflects the pre-modification state per upstream semantics.
    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        match store.hget(key, field, now_ms) {
            Ok(Some(v)) => replies.push(RespFrame::BulkString(Some(v))),
            Ok(None) => replies.push(RespFrame::BulkString(None)),
            Err(StoreError::WrongType) => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
            Err(err) => return Err(err.into()),
        }
    }

    // Apply the TTL action for every field that still exists (hget above
    // may have reaped expired fields; only live ones get the new TTL).
    match ttl_action {
        TtlAction::None => {}
        TtlAction::SetAbsMs(deadline) => {
            for f_idx in 0..numfields {
                let field = argv[fields_start + f_idx].as_slice();
                let _ = store.hash_field_set_abs_expiry_with_event(
                    key,
                    field,
                    deadline,
                    HashFieldTtlCondition::None,
                    now_ms,
                    "hexpire",
                );
            }
        }
        TtlAction::Persist => {
            for f_idx in 0..numfields {
                let field = argv[fields_start + f_idx].as_slice();
                let _ = store.hash_field_persist_with_event(key, field);
            }
        }
    }

    Ok(RespFrame::Array(Some(replies)))
}

/// HGETDEL key FIELDS n field ...
///
/// Returns an array of bulk strings with the value of each field (or nil
/// for missing fields), then deletes each specified field from the hash.
/// Equivalent to atomic HMGET + HDEL over the same field set.
fn hgetdel_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let (fields_start, numfields) = parse_hash_field_ttl_fields_only_header(argv, "HGETDEL")?;
    let key = argv[1].as_slice();

    let mut replies = Vec::with_capacity(numfields);
    let mut owned_fields: Vec<Vec<u8>> = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        match store.hget(key, field, now_ms) {
            Ok(Some(v)) => replies.push(RespFrame::BulkString(Some(v))),
            Ok(None) => replies.push(RespFrame::BulkString(None)),
            Err(StoreError::WrongType) => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
            Err(err) => return Err(err.into()),
        }
        owned_fields.push(field.to_vec());
    }
    let refs: Vec<&[u8]> = owned_fields.iter().map(Vec::as_slice).collect();
    match store.hdel(key, &refs, now_ms) {
        Ok(_) | Err(StoreError::WrongType) => {}
        Err(err) => return Err(err.into()),
    }
    Ok(RespFrame::Array(Some(replies)))
}

fn hpersist_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let (fields_start, numfields) = parse_hash_field_ttl_fields_only_header(argv, "HPERSIST")?;
    let key = argv[1].as_slice();

    let mut replies = Vec::with_capacity(numfields);
    for f_idx in 0..numfields {
        let field = argv[fields_start + f_idx].as_slice();
        // hash_field_persist_with_event emits "hpersist" NOTIFY_HASH on
        // the Persisted branch. (br-frankenredis-7jhg)
        let outcome = store.hash_field_persist_with_event(key, field);
        let code: i64 = match outcome {
            HashFieldPersistResult::Persisted => 1,
            HashFieldPersistResult::NoTtl => -1,
            HashFieldPersistResult::FieldMissing => -2,
            HashFieldPersistResult::KeyMissing => -2,
            HashFieldPersistResult::WrongType => {
                return Err(CommandError::Custom(
                    "WRONGTYPE Operation against a key holding the wrong kind of value".to_string(),
                ));
            }
        };
        replies.push(RespFrame::Integer(code));
    }
    Ok(RespFrame::Array(Some(replies)))
}

fn lpush(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("LPUSH"));
    }
    let len = store.lpush(&argv[1], &argv[2..], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn rpush(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("RPUSH"));
    }
    let len = store.rpush(&argv[1], &argv[2..], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn lpop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 || argv.len() > 3 {
        return Err(CommandError::WrongArity("LPOP"));
    }
    if argv.len() == 3 {
        let count = parse_list_pop_count_arg(&argv[2])?;
        let values = match store.lpop_count(&argv[1], count, now_ms)? {
            None => return Ok(RespFrame::Array(None)),
            Some(values) => values,
        };
        let frames = values
            .into_iter()
            .map(|v| RespFrame::BulkString(Some(v)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    let value = store.lpop(&argv[1], now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn rpop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 || argv.len() > 3 {
        return Err(CommandError::WrongArity("RPOP"));
    }
    if argv.len() == 3 {
        let count = parse_list_pop_count_arg(&argv[2])?;
        let values = match store.rpop_count(&argv[1], count, now_ms)? {
            None => return Ok(RespFrame::Array(None)),
            Some(values) => values,
        };
        let frames = values
            .into_iter()
            .map(|v| RespFrame::BulkString(Some(v)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    let value = store.rpop(&argv[1], now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn parse_list_pop_count_arg(arg: &[u8]) -> Result<usize, CommandError> {
    // Upstream t_list.c::popGenericCommand emits the same
    // "value is out of range, must be positive" error for both
    // unparseable integers and explicit-negative counts.
    // (br-frankenredis-lpopary)
    let bad = || CommandError::Custom("ERR value is out of range, must be positive".to_string());
    match parse_i64_arg(arg).map_err(|_| bad())? {
        count if count >= 0 => usize::try_from(count).map_err(|_| bad()),
        _ => Err(bad()),
    }
}

fn llen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("LLEN"));
    }
    let len = store.llen(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn lrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("LRANGE"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let stop = parse_i64_arg(&argv[3])?;
    let values = store.lrange(&argv[1], start, stop, now_ms)?;
    let frames = values
        .into_iter()
        .map(|v| RespFrame::BulkString(Some(v)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn lindex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("LINDEX"));
    }
    if !store.exists_no_touch(&argv[1], now_ms) {
        return Ok(RespFrame::BulkString(None));
    }
    let index = parse_i64_arg(&argv[2])?;
    let value = store.lindex(&argv[1], index, now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn lset_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("LSET"));
    }
    let index = parse_i64_arg(&argv[2])?;
    store.lset(&argv[1], index, argv[3].clone(), now_ms)?;
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn sadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SADD"));
    }
    let added = store.sadd(&argv[1], &argv[2..], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(added).unwrap_or(i64::MAX)))
}

fn srem(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SREM"));
    }
    let members: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    let removed = store.srem(&argv[1], &members, now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn smembers(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("SMEMBERS"));
    }
    let members = store.smembers(&argv[1], now_ms)?;
    let frames = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn scard(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("SCARD"));
    }
    let len = store.scard(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn sismember(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("SISMEMBER"));
    }
    let is_member = store.sismember(&argv[1], &argv[2], now_ms)?;
    Ok(RespFrame::Integer(if is_member { 1 } else { 0 }))
}

fn parse_f64_arg(arg: &[u8]) -> Result<f64, CommandError> {
    let text = std::str::from_utf8(arg)
        .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
    let bytes = text.as_bytes();
    if bytes.is_empty()
        || bytes[0].is_ascii_whitespace()
        || bytes[bytes.len() - 1].is_ascii_whitespace()
    {
        return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
    }
    let val = text
        .parse::<f64>()
        .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
    if val.is_nan() {
        return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
    }
    // Mirror upstream util.c::string2d, which rejects overflow-to-
    // HUGE_VAL (errno == ERANGE) cases. Rust's parse::<f64> silently
    // saturates "1e500" to f64::INFINITY without indicating overflow,
    // so reject any value that lands on ±infinity unless the original
    // text was an explicit infinity literal ('inf', '+inf', '-inf',
    // 'infinity', etc.). (br-frankenredis-floatovf)
    if val.is_infinite() {
        let lc = text.to_ascii_lowercase();
        let stripped = lc
            .strip_prefix('+')
            .or_else(|| lc.strip_prefix('-'))
            .unwrap_or(&lc);
        if stripped != "inf" && stripped != "infinity" {
            return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
        }
    }
    Ok(val)
}

const GEO_STEP_MAX: u8 = 26;
const GEO_LONG_MIN: f64 = -180.0;
const GEO_LONG_MAX: f64 = 180.0;
const GEO_LAT_MIN: f64 = -85.051_128_78;
const GEO_LAT_MAX: f64 = 85.051_128_78;
const GEO_STANDARD_LAT_MIN: f64 = -90.0;
const GEO_STANDARD_LAT_MAX: f64 = 90.0;
const GEO_EARTH_RADIUS_IN_METERS: f64 = 6_372_797.560_856;
const GEO_BASE32_ALPHABET: &[u8; 32] = b"0123456789bcdefghjkmnpqrstuvwxyz";

#[inline]
fn geo_interleave64(xlo: u32, ylo: u32) -> u64 {
    const B: [u64; 5] = [
        0x5555_5555_5555_5555,
        0x3333_3333_3333_3333,
        0x0F0F_0F0F_0F0F_0F0F,
        0x00FF_00FF_00FF_00FF,
        0x0000_FFFF_0000_FFFF,
    ];
    let mut x = u64::from(xlo);
    let mut y = u64::from(ylo);

    x = (x | (x << 16)) & B[4];
    y = (y | (y << 16)) & B[4];
    x = (x | (x << 8)) & B[3];
    y = (y | (y << 8)) & B[3];
    x = (x | (x << 4)) & B[2];
    y = (y | (y << 4)) & B[2];
    x = (x | (x << 2)) & B[1];
    y = (y | (y << 2)) & B[1];
    x = (x | (x << 1)) & B[0];
    y = (y | (y << 1)) & B[0];

    x | (y << 1)
}

#[inline]
fn geo_deinterleave64(interleaved: u64) -> u64 {
    const B: [u64; 6] = [
        0x5555_5555_5555_5555,
        0x3333_3333_3333_3333,
        0x0F0F_0F0F_0F0F_0F0F,
        0x00FF_00FF_00FF_00FF,
        0x0000_FFFF_0000_FFFF,
        0x0000_0000_FFFF_FFFF,
    ];
    let mut x = interleaved;
    let mut y = interleaved >> 1;

    x &= B[0];
    y &= B[0];
    x = (x | (x >> 1)) & B[1];
    y = (y | (y >> 1)) & B[1];
    x = (x | (x >> 2)) & B[2];
    y = (y | (y >> 2)) & B[2];
    x = (x | (x >> 4)) & B[3];
    y = (y | (y >> 4)) & B[3];
    x = (x | (x >> 8)) & B[4];
    y = (y | (y >> 8)) & B[4];
    x = (x | (x >> 16)) & B[5];
    y = (y | (y >> 16)) & B[5];

    x | (y << 32)
}

#[inline]
fn geo_encode(
    longitude: f64,
    latitude: f64,
    long_min: f64,
    long_max: f64,
    lat_min: f64,
    lat_max: f64,
    step: u8,
) -> Option<u64> {
    if step == 0 || step > 32 {
        return None;
    }
    if longitude < long_min || longitude > long_max || latitude < lat_min || latitude > lat_max {
        return None;
    }

    let scale = (1_u64 << u32::from(step)) as f64;
    let lat_offset = ((latitude - lat_min) / (lat_max - lat_min) * scale) as u32;
    let long_offset = ((longitude - long_min) / (long_max - long_min) * scale) as u32;
    Some(geo_interleave64(lat_offset, long_offset))
}

#[inline]
fn geo_encode_wgs84(longitude: f64, latitude: f64) -> Option<u64> {
    geo_encode(
        longitude,
        latitude,
        GEO_LONG_MIN,
        GEO_LONG_MAX,
        GEO_LAT_MIN,
        GEO_LAT_MAX,
        GEO_STEP_MAX,
    )
}

#[inline]
fn geo_decode(bits: u64, long_min: f64, long_max: f64, lat_min: f64, lat_max: f64) -> (f64, f64) {
    let step = u32::from(GEO_STEP_MAX);
    let scale = (1_u64 << step) as f64;
    let hash_sep = geo_deinterleave64(bits);

    let ilato = hash_sep as u32;
    let ilono = (hash_sep >> 32) as u32;
    let lat_scale = lat_max - lat_min;
    let long_scale = long_max - long_min;

    let lat_lo = lat_min + (f64::from(ilato) / scale) * lat_scale;
    let lat_hi = lat_min + (f64::from(ilato.saturating_add(1)) / scale) * lat_scale;
    let long_lo = long_min + (f64::from(ilono) / scale) * long_scale;
    let long_hi = long_min + (f64::from(ilono.saturating_add(1)) / scale) * long_scale;

    let longitude = ((long_lo + long_hi) / 2.0).clamp(long_min, long_max);
    let latitude = ((lat_lo + lat_hi) / 2.0).clamp(lat_min, lat_max);
    (longitude, latitude)
}

#[inline]
fn geo_decode_score(score: f64) -> Option<(f64, f64)> {
    if !score.is_finite() {
        return None;
    }
    Some(geo_decode(
        score as u64,
        GEO_LONG_MIN,
        GEO_LONG_MAX,
        GEO_LAT_MIN,
        GEO_LAT_MAX,
    ))
}

#[inline]
fn parse_geo_f64(arg: &[u8]) -> Result<f64, RespFrame> {
    parse_geo_f64_with_msg(arg, "value is not a valid float")
}

/// Parse a Redis-compatible f64 with caller-supplied error message
/// body (mirrors upstream's `getDoubleFromObjectOrReply(c,obj,&out,msg)`).
/// The "ERR " prefix is added here so callers can pass the bare msg
/// (e.g. "need numeric radius"). (br-frankenredis-geosearch)
fn parse_geo_f64_with_msg(arg: &[u8], msg: &str) -> Result<f64, RespFrame> {
    let err = || RespFrame::Error(format!("ERR {msg}"));
    let text = std::str::from_utf8(arg).map_err(|_| err())?;
    let bytes = text.as_bytes();
    if bytes.is_empty()
        || bytes[0].is_ascii_whitespace()
        || bytes[bytes.len() - 1].is_ascii_whitespace()
    {
        return Err(err());
    }
    let val = text.parse::<f64>().map_err(|_| err())?;
    if val.is_nan() {
        return Err(err());
    }
    Ok(val)
}

#[inline]
fn geo_invalid_pair_error(longitude: f64, latitude: f64) -> RespFrame {
    RespFrame::Error(format!(
        "ERR invalid longitude,latitude pair {longitude:.6},{latitude:.6}"
    ))
}

/// Formats an f64 the way upstream's GEOPOS / GEOSEARCH WITHCOORD do:
/// snprintf("%.17Lf", ...) followed by trailing-zero trimming
/// (LD_STR_HUMAN — see legacy_redis_code/redis/src/util.c::ld2string).
/// f64 doubles get implicitly promoted to long double in upstream and
/// then printed with 17 fractional digits; on platforms where long
/// double == double the value space is identical and the 17-digit
/// expansion is exactly the round-to-nearest decimal of the IEEE-754
/// bit pattern. Rust's {:.17} on f64 matches this expansion. The trim
/// matches the upstream behavior of dropping trailing zeros and the
/// dangling '.', plus normalizing "-0" to "0". (br-frankenredis-nz2v)
fn format_coord_human(value: f64) -> String {
    if value.is_nan() {
        return "nan".to_string();
    }
    if value.is_infinite() {
        return if value.is_sign_positive() {
            "inf".to_string()
        } else {
            "-inf".to_string()
        };
    }
    let mut s = format!("{value:.17}");
    if s.contains('.') {
        let trimmed = s.trim_end_matches('0').trim_end_matches('.');
        s.truncate(trimmed.len());
    }
    if s == "-0" {
        s = "0".to_string();
    }
    s
}

#[inline]
fn geo_unit_to_meters(unit: &[u8]) -> Option<f64> {
    if eq_ascii_command(unit, b"M") {
        Some(1.0)
    } else if eq_ascii_command(unit, b"KM") {
        Some(1000.0)
    } else if eq_ascii_command(unit, b"FT") {
        Some(0.3048)
    } else if eq_ascii_command(unit, b"MI") {
        Some(1609.34)
    } else {
        None
    }
}

#[inline]
fn geo_lat_distance_m(lat1: f64, lat2: f64) -> f64 {
    GEO_EARTH_RADIUS_IN_METERS * (lat2.to_radians() - lat1.to_radians()).abs()
}

#[inline]
fn geo_distance_m(lon1: f64, lat1: f64, lon2: f64, lat2: f64) -> f64 {
    let lon1r = lon1.to_radians();
    let lon2r = lon2.to_radians();
    let v = ((lon2r - lon1r) / 2.0).sin();
    if v == 0.0 {
        return geo_lat_distance_m(lat1, lat2);
    }
    let lat1r = lat1.to_radians();
    let lat2r = lat2.to_radians();
    let u = ((lat2r - lat1r) / 2.0).sin();
    let a = (u * u + lat1r.cos() * lat2r.cos() * v * v).clamp(0.0, 1.0);
    2.0 * GEO_EARTH_RADIUS_IN_METERS * a.sqrt().asin()
}

#[inline]
fn geo_distance_reply(distance: f64) -> RespFrame {
    let normalized = if distance == 0.0 { 0.0 } else { distance };
    RespFrame::BulkString(Some(format!("{normalized:.4}").into_bytes()))
}

#[inline]
fn geo_hash_string_from_score(score: f64) -> Option<Vec<u8>> {
    let (longitude, latitude) = geo_decode_score(score)?;
    let bits = geo_encode(
        longitude,
        latitude,
        GEO_LONG_MIN,
        GEO_LONG_MAX,
        GEO_STANDARD_LAT_MIN,
        GEO_STANDARD_LAT_MAX,
        GEO_STEP_MAX,
    )?;

    let mut buf = [0_u8; 11];
    for (i, slot) in buf.iter_mut().enumerate() {
        let shift = 52_i32 - ((i as i32 + 1) * 5);
        let idx = if shift >= 0 {
            ((bits >> shift as u32) & 0x1f) as usize
        } else {
            ((bits << (-shift) as u32) & 0x1f) as usize
        };
        *slot = GEO_BASE32_ALPHABET[idx];
    }
    Some(buf.to_vec())
}

fn zadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // ZADD key [NX|XX] [GT|LT] [CH] [INCR] score member [score member ...]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZADD"));
    }

    let mut nx = false;
    let mut xx = false;
    let mut gt = false;
    let mut lt = false;
    let mut ch = false;
    let mut incr = false;
    let mut i = 2;

    // Parse option flags
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("NX") {
            nx = true;
        } else if opt.eq_ignore_ascii_case("XX") {
            xx = true;
        } else if opt.eq_ignore_ascii_case("GT") {
            gt = true;
        } else if opt.eq_ignore_ascii_case("LT") {
            lt = true;
        } else if opt.eq_ignore_ascii_case("CH") {
            ch = true;
        } else if opt.eq_ignore_ascii_case("INCR") {
            incr = true;
        } else {
            break; // Start of score-member pairs
        }
        i += 1;
    }

    // Upstream t_zset.c::zaddGenericCommand checks the score/member
    // tail arity BEFORE checking flag conflicts, so a payload like
    // 'ZADD z NX XX' (no score/member pair) emits the generic
    // syntax error rather than the conflict-specific wording.
    // (br-frankenredis-zaddorder)
    let remaining = argv.len() - i;
    // Upstream returns 'ERR syntax error' when the score/member
    // tail count is zero or odd, NOT a wrong-arity reply.
    // (br-frankenredis-zaddary)
    if remaining < 2 || !remaining.is_multiple_of(2) {
        return Err(CommandError::SyntaxError);
    }

    // NX and XX are mutually exclusive
    if nx && xx {
        return Ok(RespFrame::Error(
            "ERR XX and NX options at the same time are not compatible".to_string(),
        ));
    }
    // GT/LT/NX combinations share the same Redis error wording.
    if (nx && (gt || lt)) || (gt && lt) {
        return Ok(RespFrame::Error(
            "ERR GT, LT, and/or NX options at the same time are not compatible".to_string(),
        ));
    }

    if incr && remaining != 2 {
        return Ok(RespFrame::Error(
            "ERR INCR option supports a single increment-element pair".to_string(),
        ));
    }

    let opts = fr_store::ZaddOptions { nx, xx, gt, lt, ch };

    if incr {
        let score_delta = parse_f64_arg(&argv[i])?;
        let member = argv[i + 1].clone();
        let result = store
            .zincrby_with_options(&argv[1], member, score_delta, opts, now_ms)
            .map_err(|e| match e {
                // (br-frankenredis-zinaN)
                StoreError::IncrFloatNaN => {
                    CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
                }
                other => other.into(),
            })?;
        match result {
            Some(new_score) => Ok(RespFrame::BulkString(Some(
                new_score.to_string().into_bytes(),
            ))),
            None => Ok(RespFrame::BulkString(None)),
        }
    } else {
        let mut pairs = Vec::with_capacity(remaining / 2);
        while i + 1 < argv.len() {
            let score = parse_f64_arg(&argv[i])?;
            pairs.push((score, argv[i + 1].clone()));
            i += 2;
        }

        let (count, _changed) = store.zadd_with_options(&argv[1], &pairs, opts, now_ms)?;
        Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
    }
}

fn zrem(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("ZREM"));
    }
    let members: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    let removed = store.zrem(&argv[1], &members, now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn zscore(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("ZSCORE"));
    }
    match store.zscore(&argv[1], &argv[2], now_ms)? {
        Some(score) => Ok(RespFrame::BulkString(Some(score.to_string().into_bytes()))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn zcard(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("ZCARD"));
    }
    let len = store.zcard(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn zrank_generic(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    reverse: bool,
) -> Result<RespFrame, CommandError> {
    // ZRANK/ZREVRANK key member [WITHSCORE]
    // Upstream t_zset.c::zrankGenericCommand accepts argc==3 or
    // argc==4 (with WITHSCORE), >4 = WrongArity, unknown 4th arg
    // = syntax error. (br-frankenredis-zrankws)
    let cmd_name = if reverse { "ZREVRANK" } else { "ZRANK" };
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(if reverse {
            "ZREVRANK"
        } else {
            "ZRANK"
        }));
    }
    if argv.len() > 4 {
        return Err(CommandError::WrongArity(if reverse {
            "ZREVRANK"
        } else {
            "ZRANK"
        }));
    }
    let withscore = if argv.len() == 4 {
        let opt = std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if !opt.eq_ignore_ascii_case("WITHSCORE") {
            return Err(CommandError::SyntaxError);
        }
        true
    } else {
        false
    };
    let _ = cmd_name;
    let rank_opt = if reverse {
        store.zrevrank(&argv[1], &argv[2], now_ms)?
    } else {
        store.zrank(&argv[1], &argv[2], now_ms)?
    };
    match rank_opt {
        Some(rank) => {
            let rank_i = i64::try_from(rank).unwrap_or(i64::MAX);
            if withscore {
                let score = store.zscore(&argv[1], &argv[2], now_ms)?.unwrap_or(0.0);
                Ok(RespFrame::Array(Some(vec![
                    RespFrame::Integer(rank_i),
                    RespFrame::BulkString(Some(score.to_string().into_bytes())),
                ])))
            } else {
                Ok(RespFrame::Integer(rank_i))
            }
        }
        None => {
            if withscore {
                Ok(RespFrame::Array(None))
            } else {
                Ok(RespFrame::BulkString(None))
            }
        }
    }
}

fn zrank(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    zrank_generic(argv, store, now_ms, false)
}

fn zrevrank(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    zrank_generic(argv, store, now_ms, true)
}

fn zrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // ZRANGE key min max [BYSCORE | BYLEX] [REV] [LIMIT offset count] [WITHSCORES]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZRANGE"));
    }

    let mut byscore = false;
    let mut bylex = false;
    let mut rev = false;
    let mut withscores = false;
    let mut limit_offset: Option<usize> = None;
    let mut limit_count: Option<usize> = None;

    let mut i = 4;
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("BYSCORE") {
            // Upstream t_zset.c::zrangeGenericCommand only matches
            // BYSCORE when rangetype is still AUTO; a second BYSCORE
            // (or BYLEX after BYSCORE) falls through to syntax error.
            // (br-frankenredis-zrangedup)
            if byscore || bylex {
                return Err(CommandError::SyntaxError);
            }
            byscore = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("BYLEX") {
            if byscore || bylex {
                return Err(CommandError::SyntaxError);
            }
            bylex = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("REV") {
            // Upstream only matches REV when direction is AUTO; a
            // duplicate REV falls through to syntax error.
            // (br-frankenredis-zrangedup)
            if rev {
                return Err(CommandError::SyntaxError);
            }
            rev = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("WITHSCORES") {
            withscores = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            limit_offset = Some(
                usize::try_from(parse_u64_arg(&argv[i + 1])?)
                    .map_err(|_| CommandError::InvalidInteger)?,
            );
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    // Upstream t_zset.c::zrangeGenericCommand uses verbose syntax-error
    // wording for LIMIT-without-shape and WITHSCORES+BYLEX, matching
    // these exact strings. (br-frankenredis-zrangeshape)
    // The check uses opt_limit != -1, so a sentinel `LIMIT offset -1`
    // (limit_count=None) is allowed even in rank mode.
    if limit_count.is_some() && !byscore && !bylex {
        return Err(CommandError::Custom(
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string(),
        ));
    }
    if withscores && bylex {
        return Err(CommandError::Custom(
            "ERR syntax error, WITHSCORES not supported in combination with BYLEX".to_string(),
        ));
    }

    if byscore {
        let min = parse_score_bound(&argv[2])?;
        let max = parse_score_bound(&argv[3])?;
        let (lo, hi) = if rev { (max, min) } else { (min, max) };
        let mut pairs = store.zrangebyscore_withscores(&argv[1], lo, hi, now_ms)?;
        if rev {
            pairs.reverse();
        }
        if let Some(offset) = limit_offset {
            if let Some(count) = limit_count {
                pairs = pairs.into_iter().skip(offset).take(count).collect();
            } else {
                pairs = pairs.into_iter().skip(offset).collect();
            }
        }
        zrange_emit_with_resp(pairs, withscores, store.dispatch_client_ctx.resp_protocol_version)
    } else if bylex {
        let min_lex = &argv[2];
        let max_lex = &argv[3];
        // Upstream t_zset.c::zrangeGenericCommand validates the lex
        // bounds via zslParseLexRange before any range walk. (br-frankenredis-zrangeshape)
        validate_lex_bound(min_lex)?;
        validate_lex_bound(max_lex)?;
        let (lo, hi) = if rev {
            (max_lex.as_slice(), min_lex.as_slice())
        } else {
            (min_lex.as_slice(), max_lex.as_slice())
        };
        let mut members = store.zrangebylex(&argv[1], lo, hi, now_ms)?;
        if rev {
            members.reverse();
        }
        if let Some(offset) = limit_offset {
            if let Some(count) = limit_count {
                members = members.into_iter().skip(offset).take(count).collect();
            } else {
                members = members.into_iter().skip(offset).collect();
            }
        }
        if withscores {
            // (frankenredis-jnf53) Lex ranges look up scores individually
            // and feed the (member, score) pairs through the same shape
            // helper so RESP3 emits Array<[member, score]>.
            let mut pairs: Vec<(Vec<u8>, f64)> = Vec::with_capacity(members.len());
            for m in members {
                let score = store.zscore(&argv[1], &m, now_ms)?.unwrap_or(0.0);
                pairs.push((m, score));
            }
            zrange_emit_with_resp(pairs, true, store.dispatch_client_ctx.resp_protocol_version)
        } else {
            let frames = members
                .into_iter()
                .map(|m| RespFrame::BulkString(Some(m)))
                .collect();
            Ok(RespFrame::Array(Some(frames)))
        }
    } else {
        // Default: by rank (index)
        let start = parse_i64_arg(&argv[2])?;
        let stop = parse_i64_arg(&argv[3])?;
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        if rev {
            let pairs = store.zrevrange_withscores(&argv[1], start, stop, now_ms)?;
            zrange_emit_with_resp(pairs, withscores, resp)
        } else if withscores {
            let pairs = store.zrange_withscores(&argv[1], start, stop, now_ms)?;
            zrange_emit_with_resp(pairs, true, resp)
        } else {
            let members = store.zrange(&argv[1], start, stop, now_ms)?;
            let frames = members
                .into_iter()
                .map(|m| RespFrame::BulkString(Some(m)))
                .collect();
            Ok(RespFrame::Array(Some(frames)))
        }
    }
}

/// (frankenredis-jnf53) Upstream t_zset.c::zrangeResultEmitCBufferToClient
/// wraps each (member, score) pair in `addReplyArrayLen(c, 2)` when
/// `c->resp > 2` and skips that wrapper under RESP2 — so the wire under
/// RESP3 is Array<[member, score]> while under RESP2 it stays flat
/// alternating. Mirror that here.
fn zrange_emit_with_resp(
    pairs: Vec<(Vec<u8>, f64)>,
    withscores: bool,
    resp_protocol_version: i64,
) -> Result<RespFrame, CommandError> {
    if !withscores {
        let frames = pairs
            .into_iter()
            .map(|(m, _)| RespFrame::BulkString(Some(m)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    if resp_protocol_version == 3 {
        let frames = pairs
            .into_iter()
            .map(|(member, score)| {
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(member)),
                    RespFrame::BulkString(Some(score.to_string().into_bytes())),
                ]))
            })
            .collect();
        Ok(RespFrame::Array(Some(frames)))
    } else {
        let mut frames = Vec::with_capacity(pairs.len() * 2);
        for (member, score) in pairs {
            frames.push(RespFrame::BulkString(Some(member)));
            frames.push(RespFrame::BulkString(Some(score.to_string().into_bytes())));
        }
        Ok(RespFrame::Array(Some(frames)))
    }
}

fn zrevrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 || argv.len() > 5 {
        return Err(CommandError::WrongArity("ZREVRANGE"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let stop = parse_i64_arg(&argv[3])?;
    let withscores = argv.len() == 5
        && std::str::from_utf8(&argv[4])
            .map(|s| s.eq_ignore_ascii_case("WITHSCORES"))
            .unwrap_or(false);
    if argv.len() == 5 && !withscores {
        return Err(CommandError::SyntaxError);
    }
    let members = store.zrevrange(&argv[1], start, stop, now_ms)?;
    if withscores {
        // (frankenredis-jnf53) Route through zrange_emit_with_resp so the
        // RESP3 wire is Array<[member, score]> and RESP2 stays flat.
        let mut pairs: Vec<(Vec<u8>, f64)> = Vec::with_capacity(members.len());
        for m in members {
            let score = store.zscore(&argv[1], &m, now_ms)?.unwrap_or(0.0);
            pairs.push((m, score));
        }
        zrange_emit_with_resp(pairs, true, store.dispatch_client_ctx.resp_protocol_version)
    } else {
        let frames = members
            .into_iter()
            .map(|m| RespFrame::BulkString(Some(m)))
            .collect();
        Ok(RespFrame::Array(Some(frames)))
    }
}

/// Parse optional WITHSCORES / LIMIT offset count from argv starting at `start_idx`.
fn parse_zrangebyscore_opts(
    argv: &[Vec<u8>],
    start_idx: usize,
) -> Result<(bool, Option<usize>, Option<usize>), CommandError> {
    let mut withscores = false;
    let mut limit_offset = None;
    let mut limit_count = None;
    let mut i = start_idx;
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("WITHSCORES") {
            withscores = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            limit_offset = Some(parse_limit_offset_arg(&argv[i + 1])?);
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    Ok((withscores, limit_offset, limit_count))
}

fn zrangebyscore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANGEBYSCORE key min max [WITHSCORES] [LIMIT offset count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZRANGEBYSCORE"));
    }
    let min = parse_score_bound(&argv[2])?;
    let max = parse_score_bound(&argv[3])?;
    let (withscores, limit_offset, limit_count) = parse_zrangebyscore_opts(argv, 4)?;
    let mut pairs = store.zrangebyscore_withscores(&argv[1], min, max, now_ms)?;
    if let Some(offset) = limit_offset {
        if let Some(count) = limit_count {
            pairs = pairs.into_iter().skip(offset).take(count).collect();
        } else {
            pairs = pairs.into_iter().skip(offset).collect();
        }
    }
    zrange_emit_with_resp(pairs, withscores, store.dispatch_client_ctx.resp_protocol_version)
}

fn zcount(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("ZCOUNT"));
    }
    let min = parse_score_bound(&argv[2])?;
    let max = parse_score_bound(&argv[3])?;
    let count = store.zcount(&argv[1], min, max, now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

fn zincrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("ZINCRBY"));
    }
    let delta = parse_f64_arg(&argv[2])?;
    let new_score = store
        .zincrby(&argv[1], argv[3].clone(), delta, now_ms)
        .map_err(|e| {
            // Upstream t_zset.c uses 'resulting score is not a number
            // (NaN)' for any zset increment that yields NaN, distinct
            // from INCRBYFLOAT's 'increment would produce NaN or
            // Infinity' wording. (br-frankenredis-zinaN)
            match e {
                StoreError::IncrFloatNaN => {
                    CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
                }
                other => other.into(),
            }
        })?;
    Ok(RespFrame::BulkString(Some(
        new_score.to_string().into_bytes(),
    )))
}

fn parse_zpop_count(arg: &[u8]) -> Result<usize, CommandError> {
    match parse_i64_arg(arg) {
        Ok(count) if count >= 0 => usize::try_from(count).map_err(|_| CommandError::InvalidInteger),
        _ => Err(CommandError::Custom(
            "ERR value is out of range, must be positive".to_string(),
        )),
    }
}

/// (frankenredis-1g3ao) Upstream zpopMinMaxCommand sets
/// use_nested_array = (c->resp > 2 && count != -1). Under RESP3 with the
/// COUNT form, each (member, score) is wrapped in a 2-Array; under RESP2
/// or the no-COUNT form, the wire stays flat.
fn zpop_count_emit(
    pairs: Vec<(Vec<u8>, f64)>,
    resp_protocol_version: i64,
) -> RespFrame {
    if resp_protocol_version == 3 {
        let frames = pairs
            .into_iter()
            .map(|(member, score)| {
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(member)),
                    RespFrame::BulkString(Some(score.to_string().into_bytes())),
                ]))
            })
            .collect();
        RespFrame::Array(Some(frames))
    } else {
        let mut frames = Vec::with_capacity(pairs.len() * 2);
        for (member, score) in pairs {
            frames.push(RespFrame::BulkString(Some(member)));
            frames.push(RespFrame::BulkString(Some(score.to_string().into_bytes())));
        }
        RespFrame::Array(Some(frames))
    }
}

fn zpopmin(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 || argv.len() > 3 {
        return Err(CommandError::WrongArity("ZPOPMIN"));
    }
    if argv.len() == 3 {
        let count = parse_i64_arg(&argv[2])?;
        if count < 0 {
            return Err(CommandError::Custom(
                "ERR value is out of range, must be positive".to_string(),
            ));
        }
        if count == 0 {
            return Ok(RespFrame::Array(Some(vec![])));
        }
        let count = count as usize;
        let pairs = store.zpopmin_count(&argv[1], count, now_ms)?;
        return Ok(zpop_count_emit(
            pairs,
            store.dispatch_client_ctx.resp_protocol_version,
        ));
    }
    match store.zpopmin(&argv[1], now_ms)? {
        Some((member, score)) => Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(member)),
            RespFrame::BulkString(Some(score.to_string().into_bytes())),
        ]))),
        None => Ok(RespFrame::Array(Some(vec![]))),
    }
}

fn zpopmax(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 || argv.len() > 3 {
        return Err(CommandError::WrongArity("ZPOPMAX"));
    }
    if argv.len() == 3 {
        let count = parse_zpop_count(&argv[2])?;
        let pairs = store.zpopmax_count(&argv[1], count, now_ms)?;
        return Ok(zpop_count_emit(
            pairs,
            store.dispatch_client_ctx.resp_protocol_version,
        ));
    }
    match store.zpopmax(&argv[1], now_ms)? {
        Some((member, score)) => Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(member)),
            RespFrame::BulkString(Some(score.to_string().into_bytes())),
        ]))),
        None => Ok(RespFrame::Array(Some(vec![]))),
    }
}

fn geoadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("GEOADD"));
    }

    let mut xx = false;
    let mut nx = false;
    let mut ch = false;
    let mut long_idx = 2;
    while long_idx < argv.len() {
        if eq_ascii_command(&argv[long_idx], b"NX") {
            nx = true;
        } else if eq_ascii_command(&argv[long_idx], b"XX") {
            xx = true;
        } else if eq_ascii_command(&argv[long_idx], b"CH") {
            ch = true;
        } else {
            break;
        }
        long_idx += 1;
    }

    if xx && nx {
        return Err(CommandError::SyntaxError);
    }

    let remaining = argv.len().saturating_sub(long_idx);
    if remaining == 0 {
        return Err(CommandError::WrongArity("GEOADD"));
    }
    if !remaining.is_multiple_of(3) {
        return Err(CommandError::SyntaxError);
    }

    let mut pairs = Vec::with_capacity(remaining / 3);
    let mut idx = long_idx;
    while idx + 2 < argv.len() {
        let longitude = match parse_geo_f64(&argv[idx]) {
            Ok(value) => value,
            Err(reply) => return Ok(reply),
        };
        let latitude = match parse_geo_f64(&argv[idx + 1]) {
            Ok(value) => value,
            Err(reply) => return Ok(reply),
        };
        if !(GEO_LONG_MIN..=GEO_LONG_MAX).contains(&longitude)
            || !(GEO_LAT_MIN..=GEO_LAT_MAX).contains(&latitude)
        {
            return Ok(geo_invalid_pair_error(longitude, latitude));
        }
        let Some(bits) = geo_encode_wgs84(longitude, latitude) else {
            return Ok(geo_invalid_pair_error(longitude, latitude));
        };
        pairs.push((bits as f64, argv[idx + 2].clone()));
        idx += 3;
    }

    let (total_changed, _only_updated) = store.zadd_with_options(
        &argv[1],
        &pairs,
        fr_store::ZaddOptions {
            xx,
            nx,
            ch,
            ..Default::default()
        },
        now_ms,
    )?;

    Ok(RespFrame::Integer(total_changed as i64))
}

fn geohash(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("GEOHASH"));
    }
    let mut frames = Vec::with_capacity(argv.len().saturating_sub(2));
    for member in &argv[2..] {
        let frame = match store.zscore(&argv[1], member, now_ms)? {
            Some(score) => match geo_hash_string_from_score(score) {
                Some(hash) => RespFrame::BulkString(Some(hash)),
                None => RespFrame::BulkString(None),
            },
            None => RespFrame::BulkString(None),
        };
        frames.push(frame);
    }
    Ok(RespFrame::Array(Some(frames)))
}

fn geopos(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("GEOPOS"));
    }
    let mut frames = Vec::with_capacity(argv.len().saturating_sub(2));
    for member in &argv[2..] {
        let frame = match store.zscore(&argv[1], member, now_ms)? {
            Some(score) => match geo_decode_score(score) {
                Some((longitude, latitude)) => RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(format_coord_human(longitude).into_bytes())),
                    RespFrame::BulkString(Some(format_coord_human(latitude).into_bytes())),
                ])),
                None => RespFrame::Array(None),
            },
            None => RespFrame::Array(None),
        };
        frames.push(frame);
    }
    Ok(RespFrame::Array(Some(frames)))
}

fn geodist(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream commands.def declares GEODIST with arity = -4, so
    // the table-level check fires for argc<4. Trailing args after
    // the optional unit hit geo.c::geodistCommand's syntaxerr
    // branch. (br-frankenredis-geodist)
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("GEODIST"));
    }
    if argv.len() > 5 {
        return Err(CommandError::SyntaxError);
    }
    let to_meter = if argv.len() == 5 {
        match geo_unit_to_meters(&argv[4]) {
            Some(unit) => unit,
            None => {
                return Ok(RespFrame::Error(
                    "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                ));
            }
        }
    } else {
        1.0
    };

    let score1 = store.zscore(&argv[1], &argv[2], now_ms)?;
    let score2 = store.zscore(&argv[1], &argv[3], now_ms)?;
    let (Some(score1), Some(score2)) = (score1, score2) else {
        return Ok(RespFrame::BulkString(None));
    };

    let Some((lon1, lat1)) = geo_decode_score(score1) else {
        return Ok(RespFrame::BulkString(None));
    };
    let Some((lon2, lat2)) = geo_decode_score(score2) else {
        return Ok(RespFrame::BulkString(None));
    };

    let distance = geo_distance_m(lon1, lat1, lon2, lat2) / to_meter;
    Ok(geo_distance_reply(distance))
}

/// Shared core for GEORADIUS, GEORADIUSBYMEMBER, GEOSEARCH, GEOSEARCHSTORE.
/// Returns filtered (member, score, distance, lon, lat) tuples sorted by distance.
#[allow(clippy::too_many_arguments, clippy::type_complexity)]
fn geo_search_core(
    store: &mut Store,
    key: &[u8],
    center_lon: f64,
    center_lat: f64,
    radius_m: f64,
    count: Option<usize>,
    asc: bool,
    now_ms: u64,
) -> Result<Vec<(Vec<u8>, f64, f64, f64, f64)>, CommandError> {
    let members = store.zrange_withscores(key, 0, -1, now_ms)?;
    let mut results: Vec<(Vec<u8>, f64, f64, f64, f64)> = Vec::new();
    for (member, score) in members {
        let Some((lon, lat)) = geo_decode_score(score) else {
            continue;
        };
        let dist = geo_distance_m(center_lon, center_lat, lon, lat);
        if dist <= radius_m {
            results.push((member, score, dist, lon, lat));
        }
    }
    if asc {
        results.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal));
    } else {
        results.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
    }
    if let Some(limit) = count {
        results.truncate(limit);
    }
    Ok(results)
}

/// Formats GEOSEARCH-family results as RESP frames.
fn geo_search_reply(
    results: &[(Vec<u8>, f64, f64, f64, f64)],
    withcoord: bool,
    withdist: bool,
    withhash: bool,
    to_meter: f64,
) -> RespFrame {
    let frames: Vec<RespFrame> = results
        .iter()
        .map(|(member, score, dist, lon, lat)| {
            if !withcoord && !withdist && !withhash {
                return RespFrame::BulkString(Some(member.clone()));
            }
            let mut parts = vec![RespFrame::BulkString(Some(member.clone()))];
            if withdist {
                let d = dist / to_meter;
                let normalized = if d == 0.0 { 0.0 } else { d };
                parts.push(RespFrame::BulkString(Some(
                    format!("{normalized:.4}").into_bytes(),
                )));
            }
            if withhash {
                parts.push(RespFrame::Integer(*score as i64));
            }
            if withcoord {
                parts.push(RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(format_coord_human(*lon).into_bytes())),
                    RespFrame::BulkString(Some(format_coord_human(*lat).into_bytes())),
                ])));
            }
            RespFrame::Array(Some(parts))
        })
        .collect();
    RespFrame::Array(Some(frames))
}

/// Parse optional flags WITHCOORD, WITHDIST, WITHHASH, COUNT N [ANY], ASC, DESC from argv starting
/// at `start`. STORE/STOREDIST key pairs are consumed and skipped (they are handled by callers).
#[allow(clippy::type_complexity)]
fn parse_geo_search_flags(
    argv: &[Vec<u8>],
    start: usize,
    default_unit: f64,
) -> Result<(bool, bool, bool, Option<usize>, bool, bool, f64), CommandError> {
    let mut withcoord = false;
    let mut withdist = false;
    let mut withhash = false;
    let mut count: Option<usize> = None;
    let mut any = false;
    let mut asc = true;
    let mut to_meter = default_unit;
    let mut i = start;
    while i < argv.len() {
        if eq_ascii_command(&argv[i], b"WITHCOORD") {
            withcoord = true;
        } else if eq_ascii_command(&argv[i], b"WITHDIST") {
            withdist = true;
        } else if eq_ascii_command(&argv[i], b"WITHHASH") {
            withhash = true;
        } else if eq_ascii_command(&argv[i], b"COUNT") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let n = parse_i64_arg(&argv[i])?;
            // Upstream geo.c::geoSearchGeneric uses the literal
            // wording 'COUNT must be > 0'. (br-frankenredis-geocount)
            if n <= 0 {
                return Err(CommandError::Custom("ERR COUNT must be > 0".to_string()));
            }
            count = Some(usize::try_from(n).map_err(|_| CommandError::InvalidInteger)?);
        } else if eq_ascii_command(&argv[i], b"ANY") {
            any = true;
        } else if eq_ascii_command(&argv[i], b"ASC") {
            asc = true;
        } else if eq_ascii_command(&argv[i], b"DESC") {
            asc = false;
        } else if eq_ascii_command(&argv[i], b"STORE") {
            // Skip STORE key (consumed by georadius/georadiusbymember callers)
            i += 1;
        } else if eq_ascii_command(&argv[i], b"STOREDIST") {
            // In GEORADIUS context, STOREDIST has a key arg; in GEOSEARCHSTORE context it's standalone.
            // Peek ahead: if next arg doesn't look like a known flag/unit, consume it as a key.
            if i + 1 < argv.len()
                && !is_geo_flag(&argv[i + 1])
                && geo_unit_to_meters(&argv[i + 1]).is_none()
            {
                i += 1; // skip the key
            }
        } else if let Some(m) = geo_unit_to_meters(&argv[i]) {
            to_meter = m;
        } else {
            // Mirror upstream geo.c::geoSearchGeneric which falls
            // through to addReplyErrorObject(c, shared.syntaxerr) for
            // any unrecognised token in the trailing-flags loop.
            // (br-frankenredis-geounknown)
            return Err(CommandError::SyntaxError);
        }
        i += 1;
    }
    Ok((withcoord, withdist, withhash, count, any, asc, to_meter))
}

/// Check whether a byte slice is a recognized geo search flag keyword.
fn is_geo_flag(arg: &[u8]) -> bool {
    eq_ascii_command(arg, b"WITHCOORD")
        || eq_ascii_command(arg, b"WITHDIST")
        || eq_ascii_command(arg, b"WITHHASH")
        || eq_ascii_command(arg, b"COUNT")
        || eq_ascii_command(arg, b"ANY")
        || eq_ascii_command(arg, b"ASC")
        || eq_ascii_command(arg, b"DESC")
        || eq_ascii_command(arg, b"STORE")
        || eq_ascii_command(arg, b"STOREDIST")
}

/// Extract STORE/STOREDIST destination key from GEORADIUS/GEORADIUSBYMEMBER argv.
/// Returns (store_key, is_storedist).
fn extract_geo_store(argv: &[Vec<u8>], start: usize) -> (Option<Vec<u8>>, bool) {
    let mut store_key: Option<Vec<u8>> = None;
    let mut storedist = false;
    let mut i = start;
    while i < argv.len() {
        if eq_ascii_command(&argv[i], b"STOREDIST") && i + 1 < argv.len() {
            store_key = Some(argv[i + 1].clone());
            storedist = true;
            i += 2;
        } else if eq_ascii_command(&argv[i], b"STORE") && i + 1 < argv.len() {
            store_key = Some(argv[i + 1].clone());
            storedist = false;
            i += 2;
        } else {
            i += 1;
        }
    }
    (store_key, storedist)
}

/// Store geo search results into a destination sorted set. With `storedist`, scores are
/// distances in `unit_mult`; otherwise scores are geohash values.
fn geo_store_results(
    store: &mut Store,
    dest: &Vec<u8>,
    results: &[(Vec<u8>, f64, f64, f64, f64)],
    unit_mult: f64,
    storedist: bool,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let count_result = results.len() as i64;
    if results.is_empty() {
        store.del(std::slice::from_ref(dest), now_ms);
    } else {
        let pairs: Vec<(f64, Vec<u8>)> = results
            .iter()
            .map(|(member, score, dist, _, _)| {
                if storedist {
                    (*dist / unit_mult, member.clone())
                } else {
                    (*score, member.clone())
                }
            })
            .collect();
        store.del(std::slice::from_ref(dest), now_ms);
        store.zadd(dest, &pairs, now_ms)?;
    }
    Ok(RespFrame::Integer(count_result))
}

fn georadius(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // GEORADIUS key longitude latitude radius m|km|ft|mi [WITHCOORD] [WITHDIST] [WITHHASH] [COUNT count [ANY]] [ASC|DESC] [STORE key] [STOREDIST key]
    if argv.len() < 6 {
        return Err(CommandError::WrongArity("GEORADIUS"));
    }
    let center_lon = match parse_geo_f64(&argv[2]) {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    let center_lat = match parse_geo_f64(&argv[3]) {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    let radius = match parse_geo_f64(&argv[4]) {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    if radius < 0.0 {
        return Ok(RespFrame::Error(
            "ERR radius cannot be negative".to_string(),
        ));
    }
    let unit_mult = match geo_unit_to_meters(&argv[5]) {
        Some(m) => m,
        None => {
            return Ok(RespFrame::Error(
                "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
            ));
        }
    };
    let radius_m = radius * unit_mult;
    let (withcoord, withdist, withhash, count, _any, asc, _) =
        parse_geo_search_flags(argv, 6, unit_mult)?;
    let (store_key, storedist) = extract_geo_store(argv, 6);
    let results = geo_search_core(
        store, &argv[1], center_lon, center_lat, radius_m, count, asc, now_ms,
    )?;
    if let Some(dest) = store_key {
        geo_store_results(store, &dest, &results, unit_mult, storedist, now_ms)
    } else {
        Ok(geo_search_reply(
            &results, withcoord, withdist, withhash, unit_mult,
        ))
    }
}

fn georadiusbymember(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // GEORADIUSBYMEMBER key member radius m|km|ft|mi [WITHCOORD] [WITHDIST] [WITHHASH] [COUNT count [ANY]] [ASC|DESC] [STORE key] [STOREDIST key]
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("GEORADIUSBYMEMBER"));
    }
    // Upstream geo.c::georadiusbymemberCommand only emits 'could
    // not decode requested zset member' when the source key exists
    // but the member is missing. A missing source key returns an
    // empty array. (br-frankenredis-geofromnonexistent)
    let score = store.zscore(&argv[1], &argv[2], now_ms)?;
    let Some(score) = score else {
        if !store.exists(&argv[1], now_ms) {
            return Ok(RespFrame::Array(Some(Vec::new())));
        }
        return Ok(RespFrame::Error(
            "ERR could not decode requested zset member".to_string(),
        ));
    };
    let Some((center_lon, center_lat)) = geo_decode_score(score) else {
        return Ok(RespFrame::Array(Some(Vec::new())));
    };
    let radius = match parse_geo_f64(&argv[3]) {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    if radius < 0.0 {
        return Ok(RespFrame::Error(
            "ERR radius cannot be negative".to_string(),
        ));
    }
    let unit_mult = match geo_unit_to_meters(&argv[4]) {
        Some(m) => m,
        None => {
            return Ok(RespFrame::Error(
                "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
            ));
        }
    };
    let radius_m = radius * unit_mult;
    let (withcoord, withdist, withhash, count, _any, asc, _) =
        parse_geo_search_flags(argv, 5, unit_mult)?;
    let (store_key, storedist) = extract_geo_store(argv, 5);
    let results = geo_search_core(
        store, &argv[1], center_lon, center_lat, radius_m, count, asc, now_ms,
    )?;
    if let Some(dest) = store_key {
        geo_store_results(store, &dest, &results, unit_mult, storedist, now_ms)
    } else {
        Ok(geo_search_reply(
            &results, withcoord, withdist, withhash, unit_mult,
        ))
    }
}

fn geosearch(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // GEOSEARCH key FROMMEMBER member | FROMLONLAT lon lat BYRADIUS radius m|km|ft|mi | BYBOX width height m|km|ft|mi
    //   [ASC|DESC] [COUNT count [ANY]] [WITHCOORD] [WITHDIST] [WITHHASH]
    // Upstream commands.def declares GEOSEARCH with arity -7
    // (minimum: GEOSEARCH key FROM... BY... + radius/box args).
    // (br-frankenredis-geosearcharity)
    if argv.len() < 7 {
        return Err(CommandError::WrongArity("GEOSEARCH"));
    }
    let mut i = 2;
    let mut center_lon: Option<f64> = None;
    let mut center_lat: Option<f64> = None;
    let mut has_center = false;
    let mut radius_m: Option<f64> = None;
    let mut box_width_m: Option<f64> = None;
    let mut box_height_m: Option<f64> = None;
    let mut has_shape = false;
    let mut unit_mult = 1.0_f64;

    // Parse FROMMEMBER/FROMLONLAT and BYRADIUS/BYBOX.
    //
    // Error-reply wording MUST match upstream geo.c::geosearchCommand
    // (br-frankenredis-kro2). Upstream uses two distinct signals:
    //  - Duplicate FROM/BY clauses (e.g. two FROMMEMBERs) → plain
    //    "ERR syntax error".
    //  - Missing FROM or BY clause once parsing returns → WrongArity.
    while i < argv.len() {
        if eq_ascii_command(&argv[i], b"FROMMEMBER") {
            if has_center {
                return Err(CommandError::SyntaxError);
            }
            has_center = true;
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let score = store.zscore(&argv[1], &argv[i], now_ms)?;
            if let Some(score) = score
                && let Some((lon, lat)) = geo_decode_score(score)
            {
                center_lon = Some(lon);
                center_lat = Some(lat);
            }
            // Upstream geo.c::geoSearchGeneric only emits 'could not
            // decode requested zset member' when the source key
            // exists but the member does not. A missing source key
            // proceeds with frommember set, then returns an empty
            // result. (br-frankenredis-geofromnonexistent)
            if center_lon.is_none() && store.exists(&argv[1], now_ms) {
                return Ok(RespFrame::Error(
                    "ERR could not decode requested zset member".to_string(),
                ));
            }
        } else if eq_ascii_command(&argv[i], b"FROMLONLAT") {
            if has_center {
                return Err(CommandError::SyntaxError);
            }
            has_center = true;
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            center_lon = Some(match parse_geo_f64(&argv[i + 1]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            });
            center_lat = Some(match parse_geo_f64(&argv[i + 2]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            });
            i += 2;
        } else if eq_ascii_command(&argv[i], b"BYRADIUS") {
            if has_shape {
                return Err(CommandError::SyntaxError);
            }
            has_shape = true;
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream geo.c::extractDistanceOrReply: non-numeric →
            // 'need numeric radius', explicit-negative → 'radius
            // cannot be negative'. (br-frankenredis-geosearch)
            let r = match parse_geo_f64_with_msg(&argv[i + 1], "need numeric radius") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if r < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR radius cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&argv[i + 2]) {
                Some(m) => m,
                None => {
                    return Ok(RespFrame::Error(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            radius_m = Some(r * um);
            i += 2;
        } else if eq_ascii_command(&argv[i], b"BYBOX") {
            if has_shape {
                return Err(CommandError::SyntaxError);
            }
            has_shape = true;
            if i + 3 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream geo.c::extractBoxOrReply: non-numeric →
            // 'need numeric width' / 'need numeric height',
            // negative → 'height or width cannot be negative'.
            // (br-frankenredis-geosearch)
            let w = match parse_geo_f64_with_msg(&argv[i + 1], "need numeric width") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            let h = match parse_geo_f64_with_msg(&argv[i + 2], "need numeric height") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if w < 0.0 || h < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR height or width cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&argv[i + 3]) {
                Some(m) => m,
                None => {
                    return Ok(RespFrame::Error(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            box_width_m = Some(w * um);
            box_height_m = Some(h * um);
            i += 3;
        } else {
            break;
        }
        i += 1;
    }

    if !has_center || !has_shape {
        return Err(CommandError::WrongArity("GEOSEARCH"));
    }
    // Parse remaining flags (must run even when the source key is
    // missing so that syntax errors in the trailing options still
    // surface). (br-frankenredis-geofromnonexistent)
    let (withcoord, withdist, withhash, count, _any, asc, _) =
        parse_geo_search_flags(argv, i, unit_mult)?;
    let (Some(cx), Some(cy)) = (center_lon, center_lat) else {
        // Missing source key with FROMMEMBER — return empty set.
        return Ok(RespFrame::Array(Some(Vec::new())));
    };

    if let Some(rm) = radius_m {
        let results = geo_search_core(store, &argv[1], cx, cy, rm, count, asc, now_ms)?;
        Ok(geo_search_reply(
            &results, withcoord, withdist, withhash, unit_mult,
        ))
    } else if let (Some(w), Some(h)) = (box_width_m, box_height_m) {
        // BYBOX: filter by bounding box
        let members = store.zrange_withscores(&argv[1], 0, -1, now_ms)?;
        let half_w = w / 2.0;
        let half_h = h / 2.0;
        let mut results: Vec<(Vec<u8>, f64, f64, f64, f64)> = Vec::new();
        for (member, score) in members {
            let Some((lon, lat)) = geo_decode_score(score) else {
                continue;
            };
            let dist = geo_distance_m(cx, cy, lon, lat);
            // Approximate box check using lat/lon distance components
            let lat_dist = geo_distance_m(cx, cy, cx, lat);
            let lon_dist = geo_distance_m(cx, cy, lon, cy);
            if lat_dist <= half_h && lon_dist <= half_w {
                results.push((member, score, dist, lon, lat));
            }
        }
        if asc {
            results.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal));
        } else {
            results.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
        }
        if let Some(limit) = count {
            results.truncate(limit);
        }
        Ok(geo_search_reply(
            &results, withcoord, withdist, withhash, unit_mult,
        ))
    } else {
        Ok(RespFrame::Error(
            "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
        ))
    }
}

fn geosearchstore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // GEOSEARCHSTORE destination source FROMMEMBER member | FROMLONLAT lon lat BYRADIUS radius m|km|ft|mi | BYBOX width height m|km|ft|mi
    //   [ASC|DESC] [COUNT count [ANY]] [STOREDIST]
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("GEOSEARCHSTORE"));
    }
    let dest = argv[1].clone();
    let source = argv[2].clone();
    let mut storedist = false;

    // Check for STOREDIST flag
    for arg in &argv[3..] {
        if eq_ascii_command(arg, b"STOREDIST") {
            storedist = true;
        }
    }

    // Build a synthetic GEOSEARCH argv: [GEOSEARCH, source, ...rest]
    let mut synth = vec![b"GEOSEARCH".to_vec(), source];
    synth.extend_from_slice(&argv[3..]);

    // Parse the geosearch args to get center and radius/box
    let mut i = 2;
    let mut center_lon: Option<f64> = None;
    let mut center_lat: Option<f64> = None;
    let mut has_center = false;
    let mut radius_m: Option<f64> = None;
    let mut box_width_m: Option<f64> = None;
    let mut box_height_m: Option<f64> = None;
    let mut has_shape = false;
    let mut unit_mult = 1.0_f64;

    while i < synth.len() {
        if eq_ascii_command(&synth[i], b"FROMMEMBER") {
            if has_center {
                return Ok(RespFrame::Error(
                    "ERR exactly one of FROMMEMBER or FROMLONLAT must be provided".to_string(),
                ));
            }
            has_center = true;
            i += 1;
            if i >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            let score = store.zscore(&synth[1], &synth[i], now_ms)?;
            if let Some(score) = score
                && let Some((lon, lat)) = geo_decode_score(score)
            {
                center_lon = Some(lon);
                center_lat = Some(lat);
            }
            // (br-frankenredis-geofromnonexistent) — missing source
            // key proceeds with frommember set; only error when the
            // key exists but the member is missing.
            if center_lon.is_none() && store.exists(&synth[1], now_ms) {
                return Ok(RespFrame::Error(
                    "ERR could not decode requested zset member".to_string(),
                ));
            }
        } else if eq_ascii_command(&synth[i], b"FROMLONLAT") {
            if has_center {
                return Ok(RespFrame::Error(
                    "ERR exactly one of FROMMEMBER or FROMLONLAT must be provided".to_string(),
                ));
            }
            has_center = true;
            if i + 2 >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            center_lon = Some(match parse_geo_f64(&synth[i + 1]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            });
            center_lat = Some(match parse_geo_f64(&synth[i + 2]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            });
            i += 2;
        } else if eq_ascii_command(&synth[i], b"BYRADIUS") {
            if has_shape {
                return Ok(RespFrame::Error(
                    "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
                ));
            }
            has_shape = true;
            if i + 2 >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            // (br-frankenredis-geosearch)
            let r = match parse_geo_f64_with_msg(&synth[i + 1], "need numeric radius") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if r < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR radius cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&synth[i + 2]) {
                Some(m) => m,
                None => {
                    return Ok(RespFrame::Error(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            radius_m = Some(r * um);
            i += 2;
        } else if eq_ascii_command(&synth[i], b"BYBOX") {
            if has_shape {
                return Ok(RespFrame::Error(
                    "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
                ));
            }
            has_shape = true;
            if i + 3 >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            // (br-frankenredis-geosearch)
            let w = match parse_geo_f64_with_msg(&synth[i + 1], "need numeric width") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            let h = match parse_geo_f64_with_msg(&synth[i + 2], "need numeric height") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if w < 0.0 || h < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR height or width cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&synth[i + 3]) {
                Some(m) => m,
                None => {
                    return Ok(RespFrame::Error(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            box_width_m = Some(w * um);
            box_height_m = Some(h * um);
            i += 3;
        } else {
            break;
        }
        i += 1;
    }

    // (br-frankenredis-geofromnonexistent) — parse trailing flags
    // before the missing-center check so syntax errors surface even
    // when the source key is absent.
    let (_, _, _, count, _any, asc, _) = parse_geo_search_flags(&synth, i, unit_mult)?;

    let (Some(cx), Some(cy)) = (center_lon, center_lat) else {
        if !has_center {
            return Ok(RespFrame::Error(
                "ERR exactly one of FROMMEMBER or FROMLONLAT must be provided".to_string(),
            ));
        }
        // FROMMEMBER with missing source key: store nothing,
        // return 0.
        store.del(std::slice::from_ref(&synth[0]), now_ms);
        return Ok(RespFrame::Integer(0));
    };

    let results = if let Some(rm) = radius_m {
        geo_search_core(store, &synth[1], cx, cy, rm, count, asc, now_ms)?
    } else if let (Some(w), Some(h)) = (box_width_m, box_height_m) {
        let members = store.zrange_withscores(&synth[1], 0, -1, now_ms)?;
        let half_w = w / 2.0;
        let half_h = h / 2.0;
        let mut res: Vec<(Vec<u8>, f64, f64, f64, f64)> = Vec::new();
        for (member, score) in members {
            let Some((lon, lat)) = geo_decode_score(score) else {
                continue;
            };
            let dist = geo_distance_m(cx, cy, lon, lat);
            let lat_dist = geo_distance_m(cx, cy, cx, lat);
            let lon_dist = geo_distance_m(cx, cy, lon, cy);
            if lat_dist <= half_h && lon_dist <= half_w {
                res.push((member, score, dist, lon, lat));
            }
        }
        if asc {
            res.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal));
        } else {
            res.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
        }
        if let Some(limit) = count {
            res.truncate(limit);
        }
        res
    } else {
        return Ok(RespFrame::Error(
            "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
        ));
    };

    geo_store_results(store, &dest, &results, unit_mult, storedist, now_ms)
}

/// Parse a stream ID matching upstream Redis 7.2 strict semantics.
///
/// Accepted strict forms:
/// - `ms-seq` -> `(ms, seq)`
/// - `ms` -> `(ms, 0)`, matching upstream's common `missing_seq=0`
///
/// Dedicated range-parsing helpers handle non-strict `+` and `-` special IDs.
/// (br-frankenredis-s0v0)
fn parse_stream_id(arg: &[u8]) -> Result<StreamId, RespFrame> {
    let invalid = || {
        RespFrame::Error("ERR Invalid stream ID specified as stream command argument".to_string())
    };
    let text = std::str::from_utf8(arg).map_err(|_| invalid())?;
    let (ms_text, seq) = match text.split_once('-') {
        Some((ms, seq)) => (ms, seq.parse::<u64>().map_err(|_| invalid())?),
        None => (text, 0),
    };
    let ms = ms_text.parse::<u64>().map_err(|_| invalid())?;
    Ok((ms, seq))
}

/// Parse a partial auto-ID like "1000-*" → Some(1000).
/// Returns None if the format doesn't match "ms-*".
fn parse_partial_auto_id(arg: &[u8]) -> Option<u64> {
    let text = std::str::from_utf8(arg).ok()?;
    let (ms_str, seq_str) = text.split_once('-')?;
    if seq_str != "*" {
        return None;
    }
    ms_str.parse::<u64>().ok()
}

#[inline]
fn format_stream_id(id: StreamId) -> Vec<u8> {
    format!("{}-{}", id.0, id.1).into_bytes()
}

#[inline]
fn next_auto_stream_id(last_id: Option<StreamId>, now_ms: u64) -> StreamId {
    let mut id = match last_id {
        Some((last_ms, last_seq)) => {
            if now_ms > last_ms {
                (now_ms, 0)
            } else {
                (last_ms, last_seq.saturating_add(1))
            }
        }
        None => (now_ms, 0),
    };
    if id == (0, 0) {
        id.1 = 1;
    }
    id
}

fn parse_stream_range_bound(arg: &[u8], is_start: bool) -> Result<StreamId, RespFrame> {
    if arg == b"-" {
        return Ok((0, 0));
    }
    if arg == b"+" {
        return Ok((u64::MAX, u64::MAX));
    }

    if let Some((ms, seq)) = std::str::from_utf8(arg)
        .ok()
        .and_then(|text| text.split_once('-'))
    {
        let ms = ms.parse::<u64>().map_err(|_| {
            RespFrame::Error(
                "ERR Invalid stream ID specified as stream command argument".to_string(),
            )
        })?;
        let seq = seq.parse::<u64>().map_err(|_| {
            RespFrame::Error(
                "ERR Invalid stream ID specified as stream command argument".to_string(),
            )
        })?;
        return Ok((ms, seq));
    }

    let ms = parse_u64_arg(arg).map_err(|_| {
        RespFrame::Error("ERR Invalid stream ID specified as stream command argument".to_string())
    })?;
    Ok((ms, if is_start { 0 } else { u64::MAX }))
}

fn parse_xread_id(arg: &[u8]) -> Result<StreamId, RespFrame> {
    if arg == b"-" || arg == b"+" || arg == b"$" {
        return Err(RespFrame::Error(
            "ERR Invalid stream ID specified as stream command argument".to_string(),
        ));
    }
    parse_stream_range_bound(arg, true)
}

fn xadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("XADD"));
    }

    // Parse optional flags before the ID: NOMKSTREAM, MAXLEN/MINID, LIMIT.
    // Upstream t_stream.c::streamParseAddOrTrimArgsOrReply mandates:
    //   * MAXLEN and MINID are mutually exclusive
    //   * LIMIT requires a trimming strategy AND the approximate (~) form
    //   * LIMIT must be >= 0
    // (br-frankenredis-r71v)
    let mut idx = 2;
    let mut nomkstream = false;
    let mut trim_maxlen: Option<usize> = None;
    let mut trim_minid: Option<StreamId> = None;
    let mut trim_approx = false;
    let mut limit_given = false;
    let mut trim_limit: Option<i64> = None;

    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"NOMKSTREAM") {
            nomkstream = true;
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"MAXLEN") {
            if trim_maxlen.is_some() || trim_minid.is_some() {
                return Ok(RespFrame::Error(
                    "ERR syntax error, MAXLEN and MINID options at the same time are not compatible"
                        .to_string(),
                ));
            }
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            if eq_ascii_command(&argv[idx], b"=") || eq_ascii_command(&argv[idx], b"~") {
                trim_approx = eq_ascii_command(&argv[idx], b"~");
                idx += 1;
                if idx >= argv.len() {
                    return Err(CommandError::SyntaxError);
                }
            }
            let n = parse_i64_arg(&argv[idx])?;
            if n < 0 {
                return Ok(RespFrame::Error(
                    "ERR The MAXLEN argument must be >= 0.".to_string(),
                ));
            }
            trim_maxlen = Some(usize::try_from(n).map_err(|_| CommandError::InvalidInteger)?);
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"MINID") {
            if trim_maxlen.is_some() || trim_minid.is_some() {
                return Ok(RespFrame::Error(
                    "ERR syntax error, MAXLEN and MINID options at the same time are not compatible"
                        .to_string(),
                ));
            }
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            if eq_ascii_command(&argv[idx], b"=") || eq_ascii_command(&argv[idx], b"~") {
                trim_approx = eq_ascii_command(&argv[idx], b"~");
                idx += 1;
                if idx >= argv.len() {
                    return Err(CommandError::SyntaxError);
                }
            }
            let min_id = match parse_stream_id(&argv[idx]) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            trim_minid = Some(min_id);
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"LIMIT") && idx + 1 < argv.len() {
            // Upstream t_stream.c::streamParseAddOrTrimArgsOrReply
            // only consumes LIMIT when a value follows; otherwise the
            // token falls through and becomes the candidate stream ID,
            // which fails ID parsing. (br-frankenredis-xaddlimit)
            idx += 1;
            let n = parse_i64_arg(&argv[idx])?;
            if n < 0 {
                return Ok(RespFrame::Error(
                    "ERR The LIMIT argument must be >= 0.".to_string(),
                ));
            }
            trim_limit = Some(n);
            limit_given = true;
            idx += 1;
        } else {
            break;
        }
    }

    if limit_given && trim_maxlen.is_none() && trim_minid.is_none() {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                .to_string(),
        ));
    }
    if limit_given && !trim_approx {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string(),
        ));
    }
    let trim_limit_usize: Option<usize> = trim_limit.and_then(|n| {
        if n == 0 {
            None
        } else {
            Some(usize::try_from(n).unwrap_or(usize::MAX))
        }
    });

    // argv[idx] should now be the ID, followed by field-value pairs
    if idx >= argv.len() {
        return Err(CommandError::WrongArity("XADD"));
    }
    let id_idx = idx;
    idx += 1;

    // Upstream t_stream.c::xaddCommand validates the explicit
    // stream-id BEFORE checking field-value pair arity, so a token
    // like 'LIMIT' that fell through option parsing emits
    // 'Invalid stream ID specified...' rather than wrong-arity.
    // (br-frankenredis-xaddidvalid)
    if !eq_ascii_command(&argv[id_idx], b"*") && parse_partial_auto_id(&argv[id_idx]).is_none() {
        match parse_stream_id(&argv[id_idx]) {
            Ok((0, 0)) => {
                // Upstream xaddCommand also requires the ID to be
                // strictly greater than 0-0. (br-frankenredis-xaddorder)
                return Ok(RespFrame::Error(
                    "ERR The ID specified in XADD must be greater than 0-0".to_string(),
                ));
            }
            Ok(_) => {}
            Err(reply) => return Ok(reply),
        }
    }

    // Must have at least one field-value pair after the ID
    if idx >= argv.len() || !(argv.len() - idx).is_multiple_of(2) {
        return Err(CommandError::WrongArity("XADD"));
    }

    let mut fields = Vec::with_capacity((argv.len() - idx) / 2);
    while idx + 1 < argv.len() {
        fields.push((argv[idx].clone(), argv[idx + 1].clone()));
        idx += 2;
    }

    let (stream_exists, last_id) = if nomkstream {
        store.xlast_id_with_existence(&argv[1], now_ms)?
    } else {
        (true, store.xlast_id(&argv[1], now_ms)?)
    };
    // NOMKSTREAM: if key doesn't exist, return nil (but proceed if key exists, even empty)
    if nomkstream && !stream_exists {
        return Ok(RespFrame::BulkString(None));
    }
    let id = if eq_ascii_command(&argv[id_idx], b"*") {
        next_auto_stream_id(last_id, now_ms)
    } else if let Some(partial_ms) = parse_partial_auto_id(&argv[id_idx]) {
        // "ms-*" format: explicit timestamp, auto-generate sequence
        let seq = match last_id {
            Some((last_ms, last_seq)) if partial_ms == last_ms => last_seq.saturating_add(1),
            Some((last_ms, _)) if partial_ms < last_ms => {
                return Ok(RespFrame::Error(
                    "ERR The ID specified in XADD is equal or smaller than the target stream top item"
                        .to_string(),
                ));
            }
            _ => 0,
        };
        let id = (partial_ms, seq);
        if id == (0, 0) {
            (0, 1) // minimum allowed ID
        } else {
            id
        }
    } else {
        let id = match parse_stream_id(&argv[id_idx]) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        if id == (0, 0) {
            return Ok(RespFrame::Error(
                "ERR The ID specified in XADD must be greater than 0-0".to_string(),
            ));
        }
        if let Some(last_id) = last_id
            && id <= last_id
        {
            return Ok(RespFrame::Error(
                "ERR The ID specified in XADD is equal or smaller than the target stream top item"
                    .to_string(),
            ));
        }
        id
    };

    store.xadd(&argv[1], id, &fields, now_ms)?;

    // Apply inline trimming after the add. Approximate trimming
    // (~) without LIMIT is best-effort: upstream lazily skips trimming
    // when the trailing radix-tree node isn't full, and we model that
    // as a no-op. Approximate trimming WITH `LIMIT n` (Redis 6.2+
    // dialect) executes through the store cap path; LIMIT 0 means no
    // cap, matching upstream streamAddTrimArgs::limit. Exact trimming
    // (= or absent qualifier) always executes and rejects LIMIT
    // upstream of this block. (br-frankenredis-r71v + LIMIT clause
    // follow-up)
    let should_run_inline_trim = !trim_approx || limit_given;
    if let Some(max_len) = trim_maxlen
        && should_run_inline_trim
    {
        let _ = store.xtrim(&argv[1], max_len, trim_limit_usize, now_ms);
    }
    if let Some(min_id) = trim_minid
        && should_run_inline_trim
    {
        let _ = store.xtrim_minid(&argv[1], min_id, trim_limit_usize, now_ms);
    }

    Ok(RespFrame::BulkString(Some(format_stream_id(id))))
}

fn xlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("XLEN"));
    }
    let len = store.xlen(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn xdel(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("XDEL"));
    }

    let (stream_exists, _) = store.xlast_id_with_existence(&argv[1], now_ms)?;
    if !stream_exists {
        return Ok(RespFrame::Integer(0));
    }

    let mut ids = Vec::with_capacity(argv.len() - 2);
    for arg in &argv[2..] {
        let id = match parse_stream_id(arg) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        ids.push(id);
    }

    let removed = store.xdel(&argv[1], &ids, now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn xtrim(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream t_stream.c::xtrimCommand → streamParseAddOrTrimArgsOrReply:
    //   XTRIM key (MAXLEN | MINID) [= | ~] threshold [LIMIT count]
    //
    // LIMIT requires the approximate (`~`) modifier and a trimming
    // strategy. The exact (`=`) form rejects LIMIT, and the bare
    // form (no = / ~) defaults to exact and likewise rejects LIMIT.
    // argc inclusive of the command name ranges 4..=7:
    //   4 → key + STRAT + threshold
    //   5 → key + STRAT + (= | ~) + threshold
    //   6 → key + STRAT + threshold + LIMIT count           (= → error)
    //   7 → key + STRAT + (= | ~) + threshold + LIMIT count
    if argv.len() < 4 || argv.len() > 7 {
        return Err(CommandError::WrongArity("XTRIM"));
    }

    let is_maxlen = eq_ascii_command(&argv[2], b"MAXLEN");
    let is_minid = eq_ascii_command(&argv[2], b"MINID");
    if !is_maxlen && !is_minid {
        // (frankenredis-d5y9h) Upstream
        // streamParseAddOrTrimArgsOrReply (t_stream.c lines 968-1000)
        // recognises LIMIT iteratively and, after the loop, emits a
        // specific error when LIMIT was set but no trimming strategy
        // was selected. fr's restrictive 'argv[2] must be MAXLEN or
        // MINID' check otherwise falls through to a generic
        // SyntaxError that hides the clearer LIMIT-specific message.
        if eq_ascii_command(&argv[2], b"LIMIT") {
            return Ok(RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                    .to_string(),
            ));
        }
        return Err(CommandError::SyntaxError);
    }

    let mut idx = 3usize;
    let mut approx = false;
    if idx < argv.len()
        && (eq_ascii_command(&argv[idx], b"=") || eq_ascii_command(&argv[idx], b"~"))
    {
        approx = eq_ascii_command(&argv[idx], b"~");
        idx += 1;
    }

    if idx >= argv.len() {
        return Err(CommandError::SyntaxError);
    }
    let threshold_idx = idx;
    idx += 1;

    let mut limit: Option<usize> = None;
    let mut limit_given = false;
    if idx < argv.len() {
        if !eq_ascii_command(&argv[idx], b"LIMIT") {
            return Err(CommandError::SyntaxError);
        }
        idx += 1;
        if idx >= argv.len() {
            return Err(CommandError::SyntaxError);
        }
        let n = parse_i64_arg(&argv[idx])?;
        if n < 0 {
            return Ok(RespFrame::Error(
                "ERR The LIMIT argument must be >= 0.".to_string(),
            ));
        }
        if !approx {
            return Ok(RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string(),
            ));
        }
        limit_given = true;
        if n != 0 {
            limit = Some(usize::try_from(n).unwrap_or(usize::MAX));
        }
        idx += 1;
        if idx != argv.len() {
            return Err(CommandError::SyntaxError);
        }
    }

    // Approximate (~) without LIMIT mirrors the XADD inline-trim
    // path: upstream lazily skips trimming when the trailing
    // radix-tree node isn't full, which we model as a no-op (return
    // 0 removed). Exact (=, or no qualifier) always trims fully.
    // Approximate WITH LIMIT honors the cap. LIMIT 0 is still an
    // explicit LIMIT and means no cap, not no work. A precondition
    // the XTRIM-specific oracle gate codifies vs vendored Redis 7.2.
    let approx_noop = approx && !limit_given;

    if is_maxlen {
        let max_len_raw = parse_i64_arg(&argv[threshold_idx])?;
        // Upstream streamParseAddOrTrimArgsOrReply emits the
        // bespoke 'The MAXLEN argument must be >= 0.' wording for
        // negative MAXLEN, not the generic integer-out-of-range.
        // (br-frankenredis-xtrimmaxlenneg)
        if max_len_raw < 0 {
            return Ok(RespFrame::Error(
                "ERR The MAXLEN argument must be >= 0.".to_string(),
            ));
        }
        let max_len = usize::try_from(max_len_raw).unwrap_or(usize::MAX);
        if approx_noop {
            // Touch type validation by calling xlen — this matches
            // upstream's "syntax was valid, the stream key resolves,
            // but the approximate trim chose to skip" path.
            store.xlen(&argv[1], now_ms)?;
            return Ok(RespFrame::Integer(0));
        }
        let removed = store.xtrim(&argv[1], max_len, limit, now_ms)?;
        Ok(RespFrame::Integer(
            i64::try_from(removed).unwrap_or(i64::MAX),
        ))
    } else {
        let min_id = match parse_stream_id(&argv[threshold_idx]) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        if approx_noop {
            store.xlen(&argv[1], now_ms)?;
            return Ok(RespFrame::Integer(0));
        }
        let removed = store.xtrim_minid(&argv[1], min_id, limit, now_ms)?;
        Ok(RespFrame::Integer(
            i64::try_from(removed).unwrap_or(i64::MAX),
        ))
    }
}

fn stream_record_to_frame(id: StreamId, fields: Vec<(Vec<u8>, Vec<u8>)>) -> RespFrame {
    let mut field_frames = Vec::with_capacity(fields.len().saturating_mul(2));
    for (field, value) in fields {
        field_frames.push(RespFrame::BulkString(Some(field)));
        field_frames.push(RespFrame::BulkString(Some(value)));
    }
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(format_stream_id(id))),
        RespFrame::Array(Some(field_frames)),
    ]))
}

/// Build the per-group info frame. Upstream Redis 7.2
/// t_stream.c::xinfoCommand emits this as a Map in RESP3 and an
/// alternating-array in RESP2. (br-frankenredis-f6z6)
fn stream_group_info_to_frame(
    name: Vec<u8>,
    consumers: usize,
    pending: usize,
    last_delivered_id: StreamId,
    entries_read: Option<u64>,
    lag: RespFrame,
    resp_protocol_version: i64,
) -> RespFrame {
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(name)),
        ),
        (
            RespFrame::BulkString(Some(b"consumers".to_vec())),
            RespFrame::Integer(i64::try_from(consumers).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Integer(i64::try_from(pending).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
            RespFrame::BulkString(Some(format_stream_id(last_delivered_id))),
        ),
        (
            RespFrame::BulkString(Some(b"entries-read".to_vec())),
            stream_entries_read_frame(entries_read),
        ),
        (RespFrame::BulkString(Some(b"lag".to_vec())), lag),
    ];
    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

/// (br-frankenredis-f6z6)
fn stream_consumer_info_to_frame(
    info: (Vec<u8>, usize, u64),
    resp_protocol_version: i64,
) -> RespFrame {
    let (name, pending_count, idle_ms) = info;
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(name)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Integer(i64::try_from(pending_count).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"idle".to_vec())),
            RespFrame::Integer(i64::try_from(idle_ms).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"inactive".to_vec())),
            RespFrame::Integer(i64::try_from(idle_ms).unwrap_or(i64::MAX)),
        ),
    ];
    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

/// Consumer rows nested under `XINFO STREAM ... FULL`.
///
/// Upstream t_stream.c::xinfoReplyWithStreamInfo emits these as maps with
/// seen/active timestamps and per-consumer PEL details.
/// (frankenredis-hgqc, frankenredis-xjmm)
fn stream_full_consumer_info_to_frame(
    info: (Vec<u8>, usize, u64),
    pending: Vec<RespFrame>,
    now_ms: u64,
    resp_protocol_version: i64,
) -> RespFrame {
    let (name, pending_count, idle_ms) = info;
    let seen_time = now_ms.saturating_sub(idle_ms);
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(name)),
        ),
        (
            RespFrame::BulkString(Some(b"seen-time".to_vec())),
            RespFrame::Integer(i64::try_from(seen_time).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"active-time".to_vec())),
            RespFrame::Integer(i64::try_from(seen_time).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pel-count".to_vec())),
            RespFrame::Integer(i64::try_from(pending_count).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Array(Some(pending)),
        ),
    ];

    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

struct StreamFullGroupFrameInfo {
    name: Vec<u8>,
    pending_count: usize,
    last_delivered_id: StreamId,
    entries_read: Option<u64>,
    lag: RespFrame,
}

fn stream_full_group_info_to_frame(
    info: StreamFullGroupFrameInfo,
    pending_frames: Vec<RespFrame>,
    consumer_frames: Vec<RespFrame>,
    resp_protocol_version: i64,
) -> RespFrame {
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(info.name)),
        ),
        (
            RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
            RespFrame::BulkString(Some(format_stream_id(info.last_delivered_id))),
        ),
        (
            RespFrame::BulkString(Some(b"entries-read".to_vec())),
            stream_entries_read_frame(info.entries_read),
        ),
        (RespFrame::BulkString(Some(b"lag".to_vec())), info.lag),
        (
            RespFrame::BulkString(Some(b"pel-count".to_vec())),
            RespFrame::Integer(i64::try_from(info.pending_count).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Array(Some(pending_frames)),
        ),
        (
            RespFrame::BulkString(Some(b"consumers".to_vec())),
            RespFrame::Array(Some(consumer_frames)),
        ),
    ];

    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

fn stream_full_count_limit(full_count: usize) -> usize {
    if full_count == 0 {
        usize::MAX
    } else {
        full_count
    }
}

fn stream_entries_read_frame(entries_read: Option<u64>) -> RespFrame {
    entries_read.map_or(RespFrame::BulkString(None), |read| {
        RespFrame::Integer(i64::try_from(read).unwrap_or(i64::MAX))
    })
}

fn stream_lag_range_has_tombstones(
    stream_len: usize,
    first_id: Option<StreamId>,
    max_deleted_id: StreamId,
    start_id: StreamId,
) -> bool {
    if stream_len == 0 || max_deleted_id == (0, 0) {
        return false;
    }
    let Some(first_id) = first_id else {
        return false;
    };
    if first_id > max_deleted_id {
        return false;
    }
    start_id <= max_deleted_id
}

fn stream_full_group_lag_frame(
    stream_entries_added: u64,
    stream_len: usize,
    first_id: Option<StreamId>,
    last_id: Option<StreamId>,
    max_deleted_id: StreamId,
    last_delivered_id: StreamId,
    entries_read: Option<u64>,
) -> RespFrame {
    if let Some(entries_read) = entries_read
        && !stream_lag_range_has_tombstones(stream_len, first_id, max_deleted_id, last_delivered_id)
    {
        let len = i64::try_from(stream_entries_added).unwrap_or(i64::MAX);
        let read = i64::try_from(entries_read).unwrap_or(i64::MAX);
        return RespFrame::Integer(len.saturating_sub(read));
    }
    let Some(first_id) = first_id else {
        return RespFrame::Integer(0);
    };
    let Some(last_id) = last_id else {
        return RespFrame::Integer(0);
    };
    if last_delivered_id > last_id {
        return RespFrame::BulkString(None);
    }
    if last_delivered_id == last_id {
        return RespFrame::Integer(0);
    }
    if max_deleted_id != (0, 0) && max_deleted_id >= first_id {
        return RespFrame::BulkString(None);
    }
    let lag = if last_delivered_id < first_id {
        stream_len
    } else if last_delivered_id == first_id {
        stream_len.saturating_sub(1)
    } else {
        return RespFrame::BulkString(None);
    };
    RespFrame::Integer(i64::try_from(lag).unwrap_or(i64::MAX))
}

fn stream_pending_delivery_time(now_ms: u64, idle_ms: u64) -> i64 {
    i64::try_from(now_ms.saturating_sub(idle_ms)).unwrap_or(i64::MAX)
}

fn stream_full_group_pending_to_frame(
    (id, consumer, idle_ms, deliveries): StreamPendingRecord,
    now_ms: u64,
) -> RespFrame {
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(format_stream_id(id))),
        RespFrame::BulkString(Some(consumer)),
        RespFrame::Integer(stream_pending_delivery_time(now_ms, idle_ms)),
        RespFrame::Integer(i64::try_from(deliveries).unwrap_or(i64::MAX)),
    ]))
}

fn stream_full_consumer_pending_to_frame(record: StreamPendingRecord, now_ms: u64) -> RespFrame {
    let (id, _consumer, idle_ms, deliveries) = record;
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(format_stream_id(id))),
        RespFrame::Integer(stream_pending_delivery_time(now_ms, idle_ms)),
        RespFrame::Integer(i64::try_from(deliveries).unwrap_or(i64::MAX)),
    ]))
}

fn xread(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XREAD"));
    }

    let mut idx = 1usize;
    let mut count: Option<usize> = None;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"COUNT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREAD"));
            }
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            if parsed < 0 {
                return Err(CommandError::InvalidInteger);
            }
            count = Some(usize::try_from(parsed).unwrap_or(usize::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"BLOCK") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREAD"));
            }
            if store.script_nesting_level >= 1 {
                return Err(CommandError::Custom(
                    "XREAD command is not allowed with BLOCK option from scripts".to_string(),
                ));
            }
            // Validate the timeout but ignore it (non-blocking only)
            let _deadline_ms = parse_blocking_deadline_milliseconds(&argv[idx + 1], now_ms)?;
            idx += 2;
            continue;
        }
        break;
    }

    if idx >= argv.len() || !eq_ascii_command(&argv[idx], b"STREAMS") {
        return Err(CommandError::SyntaxError);
    }
    idx += 1;

    let tail = argv.len().saturating_sub(idx);
    // Upstream t_stream.c::xreadCommand emits the dedicated
    // 'Unbalanced ... list of streams' error when the trailing
    // STREAMS arg count is not even or is empty. (br-frankenredis-xreadbal)
    if tail < 2 || !tail.is_multiple_of(2) {
        return Err(CommandError::Custom(
            "ERR Unbalanced 'xread' list of streams: for each stream key an ID or '$' must be specified.".to_string(),
        ));
    }
    let stream_count = tail / 2;
    let keys = &argv[idx..idx + stream_count];
    let ids = &argv[idx + stream_count..];

    let mut out = Vec::new();
    for (key, id_arg) in keys.iter().zip(ids.iter()) {
        let cursor = if id_arg.as_slice() == b"$" {
            store.xlast_id(key, now_ms)?.unwrap_or((u64::MAX, u64::MAX))
        } else {
            match parse_xread_id(id_arg) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            }
        };

        let records = store.xread(key, cursor, count, now_ms)?;
        if records.is_empty() {
            continue;
        }

        let mut entry_frames = Vec::with_capacity(records.len());
        for (id, fields) in records {
            entry_frames.push(stream_record_to_frame(id, fields));
        }

        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(key.clone())),
            RespFrame::Array(Some(entry_frames)),
        ])));
    }

    if out.is_empty() {
        Ok(RespFrame::Array(None))
    } else {
        Ok(RespFrame::Array(Some(out)))
    }
}

fn xreadgroup(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 7 {
        return Err(CommandError::WrongArity("XREADGROUP"));
    }
    if !eq_ascii_command(&argv[1], b"GROUP") {
        return Err(CommandError::SyntaxError);
    }

    let group = &argv[2];
    let consumer = &argv[3];

    let mut idx = 4usize;
    let mut count: Option<usize> = None;
    let mut noack = false;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"COUNT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREADGROUP"));
            }
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            if parsed < 0 {
                return Err(CommandError::InvalidInteger);
            }
            count = Some(usize::try_from(parsed).unwrap_or(usize::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"BLOCK") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREADGROUP"));
            }
            if store.script_nesting_level >= 1 {
                return Err(CommandError::Custom(
                    "XREADGROUP command is not allowed with BLOCK option from scripts".to_string(),
                ));
            }
            // Validate the timeout but ignore it (non-blocking only)
            let _deadline_ms = parse_blocking_deadline_milliseconds(&argv[idx + 1], now_ms)?;
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"NOACK") {
            noack = true;
            idx += 1;
            continue;
        }
        break;
    }

    if idx >= argv.len() || !eq_ascii_command(&argv[idx], b"STREAMS") {
        return Err(CommandError::SyntaxError);
    }
    idx += 1;

    let tail = argv.len().saturating_sub(idx);
    // (br-frankenredis-xreadbal)
    if tail < 2 || !tail.is_multiple_of(2) {
        return Err(CommandError::Custom(
            // Upstream t_stream.c::xreadCommand uses '>' for the XREADGROUP
            // sentinel (vs '$' for plain XREAD); pin the matching wording.
            // (br-frankenredis-xreadbal)
            "ERR Unbalanced 'xreadgroup' list of streams: for each stream key an ID or '>' must be specified.".to_string(),
        ));
    }
    let stream_count = tail / 2;
    let keys = &argv[idx..idx + stream_count];
    let ids = &argv[idx + stream_count..];

    let mut out = Vec::new();
    for (key, id_arg) in keys.iter().zip(ids.iter()) {
        let cursor = if id_arg.as_slice() == b">" {
            StreamGroupReadCursor::NewEntries
        } else {
            let parsed = match parse_xread_id(id_arg) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            StreamGroupReadCursor::Id(parsed)
        };

        let read_options = StreamGroupReadOptions {
            cursor,
            noack,
            count,
        };
        let Some(records) = store.xreadgroup(key, group, consumer, read_options, now_ms)? else {
            return Ok(xreadgroup_nogroup_error(key, group));
        };
        if records.is_empty() {
            continue;
        }

        let mut entry_frames = Vec::with_capacity(records.len());
        for (id, fields) in records {
            entry_frames.push(stream_record_to_frame(id, fields));
        }

        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(key.clone())),
            RespFrame::Array(Some(entry_frames)),
        ])));
    }

    if out.is_empty() {
        Ok(RespFrame::Array(None))
    } else {
        Ok(RespFrame::Array(Some(out)))
    }
}

fn xclaim(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 6 {
        return Err(CommandError::WrongArity("XCLAIM"));
    }

    // Upstream t_stream.c::xclaimCommand looks up the stream key + the
    // consumer group BEFORE parsing min-idle-time or any trailing
    // options, so a missing-key/group call replies NOGROUP regardless
    // of how mangled the rest of the argv is. The other XCLAIM-family
    // commands (XPENDING, XAUTOCLAIM) parse args first per upstream;
    // only XCLAIM short-circuits early. (frankenredis-3qrt)
    match store.key_type(&argv[1], now_ms) {
        None => return Ok(xclaim_nogroup_error(&argv[1], &argv[2])),
        Some("stream") => {
            let group_exists = store
                .stream_consumer_groups(&argv[1])
                .is_some_and(|groups| groups.contains_key(argv[2].as_slice()));
            if !group_exists {
                return Ok(xclaim_nogroup_error(&argv[1], &argv[2]));
            }
        }
        Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
    }

    // Upstream t_stream.c::xclaimCommand parses min-idle-time via
    // getLongLongFromObjectOrReply with the 'Invalid min-idle-time
    // argument for XCLAIM' error string, then clamps negative values
    // silently to 0. (br-frankenredis-xclaim)
    let min_idle_raw = parse_i64_arg(&argv[4]).map_err(|_| {
        CommandError::Custom("ERR Invalid min-idle-time argument for XCLAIM".to_string())
    })?;
    let min_idle_time_ms = if min_idle_raw < 0 {
        0
    } else {
        u64::try_from(min_idle_raw).unwrap_or(u64::MAX)
    };

    // Upstream's ID-collection loop breaks on the first arg that
    // doesn't parse as a stream ID, then continues to option parsing
    // (the NULL client passed to streamParseStrictIDOrReply suppresses
    // the parse-time error reply). So an unrecognised trailing token
    // surfaces as 'Unrecognized XCLAIM option <X>', not as 'Invalid
    // stream ID …'. (br-frankenredis-xclaim)
    let mut ids = Vec::new();
    let mut idx = 5usize;
    while idx < argv.len() {
        match parse_stream_id(&argv[idx]) {
            Ok(id) => {
                ids.push(id);
                idx += 1;
            }
            Err(_) => break,
        }
    }
    // Upstream tolerates an empty IDs vector — the for-loop break
    // simply hands the first unparseable token to the option parser
    // for the 'Unrecognized XCLAIM option …' fallthrough.

    let mut idle_ms: Option<u64> = None;
    let mut time_ms: Option<u64> = None;
    let mut retry_count: Option<u64> = None;
    let mut force = false;
    let mut justid = false;
    let mut last_id: Option<StreamId> = None;

    // Upstream's option parser emits 'Unrecognized XCLAIM option <opt>'
    // for any unknown token AND for known options without a value
    // (the `&& moreargs` guards mean IDLE/TIME/RETRYCOUNT/LASTID
    // without an arg fall through to the catch-all). The numeric
    // option arguments use the per-option 'Invalid X option argument
    // for XCLAIM' wording. (br-frankenredis-xclaim)
    let unrecognized = |opt: &[u8]| {
        CommandError::Custom(format!(
            "ERR Unrecognized XCLAIM option '{}'",
            String::from_utf8_lossy(opt)
        ))
    };
    let invalid_opt_arg = |label: &str| {
        CommandError::Custom(format!("ERR Invalid {label} option argument for XCLAIM"))
    };
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"IDLE") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed = parse_i64_arg(&argv[idx + 1]).map_err(|_| invalid_opt_arg("IDLE"))?;
            if parsed < 0 {
                return Err(invalid_opt_arg("IDLE"));
            }
            idle_ms = Some(u64::try_from(parsed).unwrap_or(u64::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"TIME") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed = parse_i64_arg(&argv[idx + 1]).map_err(|_| invalid_opt_arg("TIME"))?;
            if parsed < 0 {
                return Err(invalid_opt_arg("TIME"));
            }
            time_ms = Some(u64::try_from(parsed).unwrap_or(u64::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"RETRYCOUNT") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed =
                parse_i64_arg(&argv[idx + 1]).map_err(|_| invalid_opt_arg("RETRYCOUNT"))?;
            if parsed < 0 {
                return Err(invalid_opt_arg("RETRYCOUNT"));
            }
            retry_count = Some(u64::try_from(parsed).unwrap_or(u64::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"FORCE") {
            force = true;
            idx += 1;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"JUSTID") {
            justid = true;
            idx += 1;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"LASTID") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed = match parse_stream_id(&argv[idx + 1]) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            last_id = Some(parsed);
            idx += 2;
            continue;
        }
        return Err(unrecognized(&argv[idx]));
    }

    if idle_ms.is_some() && time_ms.is_some() {
        return Err(CommandError::SyntaxError);
    }

    let Some(reply) = store.xclaim(
        &argv[1],
        &argv[2],
        &argv[3],
        &ids,
        StreamClaimOptions {
            min_idle_time_ms,
            idle_ms,
            time_ms,
            retry_count,
            force,
            justid,
            last_id,
        },
        now_ms,
    )?
    else {
        return Ok(xclaim_nogroup_error(&argv[1], &argv[2]));
    };

    match reply {
        StreamClaimReply::Entries(entries) => Ok(RespFrame::Array(Some(
            entries
                .into_iter()
                .map(|(id, fields)| stream_record_to_frame(id, fields))
                .collect(),
        ))),
        StreamClaimReply::Ids(ids) => Ok(RespFrame::Array(Some(
            ids.into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect(),
        ))),
    }
}

fn xautoclaim(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 6 {
        return Err(CommandError::WrongArity("XAUTOCLAIM"));
    }

    // Upstream t_stream.c::xautoclaimCommand parses min-idle-time
    // via getLongLongFromObjectOrReply with the dedicated wording
    // 'Invalid min-idle-time argument for XAUTOCLAIM'. Negative
    // values are rejected. (br-frankenredis-xautoclaim)
    let min_idle_raw = parse_i64_arg(&argv[4]).map_err(|_| {
        CommandError::Custom("ERR Invalid min-idle-time argument for XAUTOCLAIM".to_string())
    })?;
    // Upstream silently clamps negative min-idle-time to 0.
    let min_idle_time_ms = if min_idle_raw < 0 {
        0
    } else {
        u64::try_from(min_idle_raw).unwrap_or(u64::MAX)
    };

    let start = match parse_stream_id(&argv[5]) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };

    let mut count = 100usize;
    let mut justid = false;
    let mut idx = 6usize;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"COUNT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream uses getRangeLongFromObjectOrReply that
            // returns 'COUNT must be > 0' for any non-positive or
            // unparseable value. (br-frankenredis-xautoclaim)
            let bad_count = || CommandError::Custom("ERR COUNT must be > 0".to_string());
            let parsed = parse_i64_arg(&argv[idx + 1]).map_err(|_| bad_count())?;
            if parsed <= 0 {
                return Err(bad_count());
            }
            count = usize::try_from(parsed).unwrap_or(usize::MAX);
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"JUSTID") {
            justid = true;
            idx += 1;
            continue;
        }
        return Err(CommandError::SyntaxError);
    }

    let Some(reply) = store.xautoclaim(
        &argv[1],
        &argv[2],
        &argv[3],
        start,
        StreamAutoClaimOptions {
            min_idle_time_ms,
            count,
            justid,
        },
        now_ms,
    )?
    else {
        return Ok(xautoclaim_nogroup_error(&argv[1], &argv[2]));
    };

    match reply {
        StreamAutoClaimReply::Entries {
            next_start,
            entries,
            deleted_ids,
        } => {
            let mut entry_frames = Vec::with_capacity(entries.len());
            for (id, fields) in entries {
                entry_frames.push(stream_record_to_frame(id, fields));
            }
            let deleted_frames = deleted_ids
                .into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect();
            Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(format_stream_id(next_start))),
                RespFrame::Array(Some(entry_frames)),
                RespFrame::Array(Some(deleted_frames)),
            ])))
        }
        StreamAutoClaimReply::Ids {
            next_start,
            ids,
            deleted_ids,
        } => {
            let id_frames = ids
                .into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect();
            let deleted_frames = deleted_ids
                .into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect();
            Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(format_stream_id(next_start))),
                RespFrame::Array(Some(id_frames)),
                RespFrame::Array(Some(deleted_frames)),
            ])))
        }
    }
}

fn xpending(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream commands.def declares XPENDING with arity = -3, so the
    // table-level WrongArity check fires for argc < 3. (br-frankenredis-xpending)
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("XPENDING"));
    }
    if argv.len() == 3 {
        let Some((total, min_id, max_id, per_consumer)) =
            store.xpending_summary(&argv[1], &argv[2], now_ms)?
        else {
            return Ok(xpending_nogroup_error(&argv[1], &argv[2]));
        };

        let mut consumer_frames = Vec::with_capacity(per_consumer.len());
        for (consumer, pending_count) in per_consumer {
            consumer_frames.push(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(consumer)),
                RespFrame::Integer(i64::try_from(pending_count).unwrap_or(i64::MAX)),
            ])));
        }

        return Ok(RespFrame::Array(Some(vec![
            RespFrame::Integer(i64::try_from(total).unwrap_or(i64::MAX)),
            min_id
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .unwrap_or(RespFrame::BulkString(None)),
            max_id
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .unwrap_or(RespFrame::BulkString(None)),
            RespFrame::Array(Some(consumer_frames)),
        ])));
    }

    // Extended form: XPENDING key group [[IDLE min-idle-time] start end count [consumer]]
    // Upstream allows argc ∈ {3, 6, 7, 8, 9} and emits SyntaxError
    // for anything else. Trailing args past the canonical positions
    // are silently ignored. (br-frankenredis-xpending)
    if !matches!(argv.len(), 3 | 6 | 7 | 8 | 9) {
        return Err(CommandError::SyntaxError);
    }
    let mut min_idle_ms: u64 = 0;
    let (start_idx, consumer_idx) = if argv.len() >= 4 && eq_ascii_command(&argv[3], b"IDLE") {
        // IDLE form: argv[3]=IDLE, argv[4]=min-idle-time, argv[5]=start, argv[6]=end, argv[7]=count, [argv[8]=consumer]
        if argv.len() < 8 {
            return Err(CommandError::SyntaxError);
        }
        min_idle_ms = parse_i64_arg(&argv[4]).map(|v| v.max(0) as u64)?;
        (5, if argv.len() >= 9 { Some(8) } else { None })
    } else {
        (3, if argv.len() >= 7 { Some(6) } else { None })
    };

    let start = match parse_stream_range_bound(&argv[start_idx], true) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };
    let end = match parse_stream_range_bound(&argv[start_idx + 1], false) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };

    let count_raw = parse_i64_arg(&argv[start_idx + 2])?;
    if count_raw < 0 {
        return Err(CommandError::InvalidInteger);
    }
    let count = usize::try_from(count_raw).unwrap_or(usize::MAX);
    let consumer = consumer_idx.map(|idx| argv[idx].as_slice());

    let Some(entries) = store.xpending_entries(
        &argv[1],
        &argv[2],
        (start, end),
        count,
        consumer,
        now_ms,
        min_idle_ms,
    )?
    else {
        return Ok(xpending_nogroup_error(&argv[1], &argv[2]));
    };

    let mut out = Vec::with_capacity(entries.len());
    for (id, owner, idle_ms, deliveries) in entries {
        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(format_stream_id(id))),
            RespFrame::BulkString(Some(owner)),
            RespFrame::Integer(i64::try_from(idle_ms).unwrap_or(i64::MAX)),
            RespFrame::Integer(i64::try_from(deliveries).unwrap_or(i64::MAX)),
        ])));
    }
    Ok(RespFrame::Array(Some(out)))
}

fn xgroup(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("XGROUP"));
    }
    let sub = match std::str::from_utf8(&argv[1]) {
        Ok(s) => s,
        Err(_) => return Err(CommandError::InvalidUtf8Argument),
    };

    if sub.eq_ignore_ascii_case("CREATE") {
        // XGROUP CREATE key groupname id|$ [MKSTREAM] [ENTRIESREAD entries-read]
        // Upstream xgroupCommand parses MKSTREAM and ENTRIESREAD as
        // independent option tokens (in any order) and dispatches
        // addReplySubcommandSyntaxError for any unrecognised tail.
        // (br-frankenredis-xgroupcreate)
        let create_subcommand_syntax = || {
            CommandError::Custom(format!(
                "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try XGROUP HELP."
            ))
        };
        // XGROUP CREATE has arity -5 in upstream commands.def, so
        // argc<5 emits the table-level 'wrong number of arguments
        // for xgroup|create command' wording. Bad option tokens
        // with argc>=5 still reach the subcommand-syntax-error
        // catch-all below. (br-frankenredis-xgrouparity)
        if argv.len() < 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        let mut mkstream = false;
        let mut entries_read = None;
        let mut i = 5;
        while i < argv.len() {
            if eq_ascii_command(&argv[i], b"MKSTREAM") {
                mkstream = true;
                i += 1;
            } else if eq_ascii_command(&argv[i], b"ENTRIESREAD") {
                if i + 1 >= argv.len() {
                    return Err(create_subcommand_syntax());
                }
                let parsed = parse_i64_arg(&argv[i + 1])?;
                if parsed < 0 && parsed != -1 {
                    return Err(CommandError::Custom(
                        "ERR value for ENTRIESREAD must be positive or -1".to_string(),
                    ));
                }
                entries_read = u64::try_from(parsed).ok();
                i += 2;
            } else {
                return Err(create_subcommand_syntax());
            }
        }

        let start_id = if eq_ascii_command(&argv[4], b"$") {
            store.xlast_id(&argv[2], now_ms)?.unwrap_or((0, 0))
        } else {
            if eq_ascii_command(&argv[4], b"-") || eq_ascii_command(&argv[4], b"+") {
                return Ok(RespFrame::Error(
                    "ERR Invalid stream ID specified as stream command argument".to_string(),
                ));
            }
            match parse_stream_range_bound(&argv[4], true) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            }
        };

        return match store.xgroup_create_with_entries_read(
            &argv[2],
            &argv[3],
            start_id,
            entries_read,
            mkstream,
            now_ms,
        ) {
            Ok(true) => Ok(RespFrame::SimpleString("OK".to_string())),
            Ok(false) => Ok(RespFrame::Error(
                "BUSYGROUP Consumer Group name already exists".to_string(),
            )),
            // Upstream xgroupCommand emits the verbose "requires the
            // key to exist" message for every XGROUP subcommand on a
            // missing stream key (see legacy_redis_code/redis/src/
            // t_stream.c::xgroupCommand). (br-frankenredis-qcmh)
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("DESTROY") {
        if argv.len() != 4 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        // Upstream xgroupCommand DESTROY rejects missing keys with
        // the verbose "requires the key to exist" error rather than
        // silently returning 0. Store::xlen returns Ok(0) on a missing
        // key (same as the user-facing XLEN contract), so it can't be
        // used to distinguish absent-vs-empty here — Store::key_type
        // is the right probe. (frankenredis-n4qd, supersedes qcmh)
        match store.key_type(&argv[2], now_ms) {
            None => return Ok(xgroup_key_required_error()),
            Some("stream") => {}
            Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
        }
        return match store.xgroup_destroy(&argv[2], &argv[3], now_ms) {
            Ok(removed) => Ok(RespFrame::Integer(if removed { 1 } else { 0 })),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("SETID") {
        // XGROUP SETID key groupname id|$ [ENTRIESREAD entries-read]
        // XGROUP SETID has arity -5 in upstream commands.def, so
        // argc<5 emits the table-level 'wrong number of arguments
        // for xgroup|setid command' wording. Other shape errors
        // (argc=6 or unknown trailing token at argc=7) still reach
        // the addReplySubcommandSyntaxError catch-all in
        // xgroupCommand. (br-frankenredis-xgrouparity)
        let setid_subcommand_syntax = || {
            CommandError::Custom(format!(
                "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try XGROUP HELP."
            ))
        };
        if argv.len() < 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        if argv.len() != 5 && argv.len() != 7 {
            return Err(setid_subcommand_syntax());
        }
        if argv.len() == 7 && !eq_ascii_command(&argv[5], b"ENTRIESREAD") {
            return Err(setid_subcommand_syntax());
        }
        let entries_read = if argv.len() == 7 {
            let parsed = parse_i64_arg(&argv[6])?;
            if parsed < 0 && parsed != -1 {
                return Err(CommandError::Custom(
                    "ERR value for ENTRIESREAD must be positive or -1".to_string(),
                ));
            }
            u64::try_from(parsed).ok()
        } else {
            None
        };
        let last_delivered_id = if eq_ascii_command(&argv[4], b"$") {
            store.xlast_id(&argv[2], now_ms)?.unwrap_or((0, 0))
        } else {
            if eq_ascii_command(&argv[4], b"-") || eq_ascii_command(&argv[4], b"+") {
                return Ok(RespFrame::Error(
                    "ERR Invalid stream ID specified as stream command argument".to_string(),
                ));
            }
            match parse_stream_range_bound(&argv[4], true) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            }
        };
        return match store.xgroup_setid_with_entries_read(
            &argv[2],
            &argv[3],
            last_delivered_id,
            entries_read,
            now_ms,
        ) {
            Ok(true) => Ok(RespFrame::SimpleString("OK".to_string())),
            Ok(false) => Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            // (br-frankenredis-qcmh)
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("CREATECONSUMER") {
        if argv.len() != 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        // (br-frankenredis-qcmh)
        match store.xlen(&argv[2], now_ms) {
            Ok(0) => return Ok(xgroup_key_required_error()),
            Ok(_) => {}
            Err(StoreError::KeyNotFound) => return Ok(xgroup_key_required_error()),
            Err(err) => return Err(CommandError::Store(err)),
        }
        return match store.xgroup_createconsumer(&argv[2], &argv[3], &argv[4], now_ms) {
            Ok(Some(created)) => Ok(RespFrame::Integer(if created { 1 } else { 0 })),
            Ok(None) => Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("DELCONSUMER") {
        if argv.len() != 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        // Same dead-code shape as XGROUP DESTROY: Store::xlen returns
        // Ok(0) for a missing key (matching the user-facing XLEN
        // contract), so the KeyNotFound arm never fired and dispatch
        // fell through to xgroup_delconsumer → NOGROUP error wording
        // instead of upstream's key-required ERR. Replace the probe
        // with Store::key_type. (frankenredis-n4g5, supersedes qcmh)
        match store.key_type(&argv[2], now_ms) {
            None => return Ok(xgroup_key_required_error()),
            Some("stream") => {}
            Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
        }
        return match store.xgroup_delconsumer(&argv[2], &argv[3], &argv[4], now_ms) {
            Ok(Some(deleted_pending)) => Ok(RespFrame::Integer(
                i64::try_from(deleted_pending).unwrap_or(i64::MAX),
            )),
            Ok(None) => Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: "HELP".to_string(),
            });
        }
        // (frankenredis-s574p) Mirror upstream t_stream.c::xgroupCommand
        // HELP body line-for-line (vendored Redis 7.2.4). Frames are
        // SimpleString (was BulkString — same divergence as 0o9vo /
        // vtege / kuthf). Placeholders use upstream syntax (`<id|$>`,
        // `<consumer>`) and the CREATE entry surfaces the MKSTREAM /
        // ENTRIESREAD option detail; SETID surfaces the
        // [ENTRIESREAD entries_read] option.
        return Ok(RespFrame::Array(Some(vec![
            hello_simple("XGROUP <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("CREATE <key> <groupname> <id|$> [option]"),
            hello_simple("    Create a new consumer group. Options are:"),
            hello_simple("    * MKSTREAM"),
            hello_simple("      Create the empty stream if it does not exist."),
            hello_simple("    * ENTRIESREAD entries_read"),
            hello_simple(
                "      Set the group's entries_read counter (internal use).",
            ),
            hello_simple("CREATECONSUMER <key> <groupname> <consumer>"),
            hello_simple("    Create a new consumer in the specified group."),
            hello_simple("DELCONSUMER <key> <groupname> <consumer>"),
            hello_simple("    Remove the specified consumer."),
            hello_simple("DESTROY <key> <groupname>"),
            hello_simple("    Remove the specified group."),
            hello_simple("SETID <key> <groupname> <id|$> [ENTRIESREAD entries_read]"),
            hello_simple("    Set the current group ID and entries_read counter."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])));
    }

    Err(CommandError::UnknownSubcommand {
        command: "XGROUP",
        subcommand: sub.to_string(),
    })
}

/// Upstream Redis 7.2 XREADGROUP / XCLAIM / XAUTOCLAIM / XPENDING /
/// XACK emit "NOGROUP No such key '<k>' or consumer group '<g>'"
/// from their shared streamCG-lookup error path (see
/// legacy_redis_code/redis/src/t_stream.c lines 2275, 2945, 3136,
/// 3388, 3880). The text is identical regardless of whether it
/// was the key or the group that was actually missing.
/// (br-frankenredis-ud94)
fn xstream_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    let key = String::from_utf8_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such key '{key}' or consumer group '{group}'"
    ))
}

fn xreadgroup_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    // XREADGROUP appends " in XREADGROUP with GROUP option" to the
    // shared NOGROUP wording (legacy_redis_code/redis/src/t_stream.c
    // around line 4495 where the streamLookupCG failure is reported
    // for XREADGROUP specifically). (br-frankenredis-ud94)
    let key = String::from_utf8_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such key '{key}' or consumer group '{group}' in XREADGROUP with GROUP option"
    ))
}

fn xgroup_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    // XGROUP SETID / DELCONSUMER / CREATECONSUMER report
    // "No such consumer group" because the key existence check has
    // already passed by the time the lookup is hit. (Upstream
    // t_stream.c:2632, 3880 in nested branches.)
    let key = String::from_utf8_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such consumer group '{group}' for key name '{key}'"
    ))
}

fn xgroup_key_required_error() -> RespFrame {
    RespFrame::Error(
        "ERR The XGROUP subcommand requires the key to exist. Note that for CREATE you may want to use the MKSTREAM option to create an empty stream automatically.".to_string(),
    )
}

fn xclaim_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    xstream_nogroup_error(key, group)
}

fn xautoclaim_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    xstream_nogroup_error(key, group)
}

fn xpending_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    xstream_nogroup_error(key, group)
}

fn xinfo_nogroup_consumers_error(key: &[u8], group: &[u8]) -> RespFrame {
    let key = String::from_utf8_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such consumer group '{group}' for key name '{key}'"
    ))
}

fn xinfo(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("XINFO"));
    }
    let sub = match std::str::from_utf8(&argv[1]) {
        Ok(s) => s,
        Err(_) => return Err(CommandError::InvalidUtf8Argument),
    };
    if sub.eq_ignore_ascii_case("CONSUMERS") {
        if argv.len() != 4 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XINFO",
                subcommand: sub.to_string(),
            });
        }
        let consumers = match store.xinfo_consumers(&argv[2], &argv[3], now_ms) {
            Ok(Some(consumers)) => consumers,
            Ok(None) => return Ok(xinfo_nogroup_consumers_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => return Err(CommandError::NoSuchKey),
            Err(err) => return Err(CommandError::Store(err)),
        };
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let out = consumers
            .into_iter()
            .map(|info| stream_consumer_info_to_frame(info, resp))
            .collect();
        return Ok(RespFrame::Array(Some(out)));
    }
    if sub.eq_ignore_ascii_case("GROUPS") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XINFO",
                subcommand: sub.to_string(),
            });
        }
        let Some(groups) = store.xinfo_groups(&argv[2], now_ms)? else {
            return Err(CommandError::NoSuchKey);
        };
        let Some((len, first, last)) = store.xinfo_stream(&argv[2], now_ms)? else {
            return Err(CommandError::NoSuchKey);
        };
        let entries_added = store.stream_entries_added(&argv[2], len);
        let max_deleted_id = store.stream_max_deleted_id(&argv[2]).unwrap_or((0, 0));
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let mut out = Vec::with_capacity(groups.len());
        for (name, consumers, pending, last_delivered_id, entries_read) in groups {
            out.push(stream_group_info_to_frame(
                name,
                consumers,
                pending,
                last_delivered_id,
                entries_read,
                stream_full_group_lag_frame(
                    entries_added,
                    len,
                    first.as_ref().map(|(id, _)| *id),
                    last.as_ref().map(|(id, _)| *id),
                    max_deleted_id,
                    last_delivered_id,
                    entries_read,
                ),
                resp,
            ));
        }
        return Ok(RespFrame::Array(Some(out)));
    }
    if !sub.eq_ignore_ascii_case("STREAM") {
        if sub.eq_ignore_ascii_case("HELP") {
            if argv.len() != 2 {
                return Err(CommandError::WrongSubcommandArity {
                    command: "XINFO",
                    subcommand: "HELP".to_string(),
                });
            }
            // (frankenredis-tnscz) Mirror upstream t_stream.c::xinfo
            // Command HELP body line-for-line (vendored Redis 7.2.4).
            // Frames are SimpleString (was BulkString — same as the
            // 0o9vo / vtege / kuthf / s574p HELP cluster). The
            // STREAM line preserves upstream's missing-closing-bracket
            // typo ('[FULL [COUNT <count>]' — one ']' instead of two)
            // for byte-for-byte wire parity.
            return Ok(RespFrame::Array(Some(vec![
                hello_simple("XINFO <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
                hello_simple("CONSUMERS <key> <groupname>"),
                hello_simple("    Show consumers of <groupname>."),
                hello_simple("GROUPS <key>"),
                hello_simple("    Show the stream consumer groups."),
                hello_simple("STREAM <key> [FULL [COUNT <count>]"),
                hello_simple("    Show information about the stream."),
                hello_simple("HELP"),
                hello_simple("    Print this help."),
            ])));
        }
        return Err(CommandError::UnknownSubcommand {
            command: "XINFO",
            subcommand: sub.to_string(),
        });
    }

    // XINFO STREAM key [FULL [COUNT count]]
    if argv.len() < 3 {
        return Err(CommandError::WrongSubcommandArity {
            command: "XINFO",
            subcommand: sub.to_string(),
        });
    }
    // Upstream t_stream.c::xinfoCommand looks up the key BEFORE
    // dispatching to the STREAM/FULL branch, so any missing key
    // (or wrong-type key) replies with 'no such key' /
    // 'WRONGTYPE…' regardless of any unrecognised trailing args.
    // (br-frankenredis-xinfokey)
    let Some((len, first, last)) = store.xinfo_stream(&argv[2], now_ms)? else {
        return Err(CommandError::NoSuchKey);
    };
    // Upstream xinfoReplyWithStreamInfo uses addReplySubcommandSyntaxError
    // for any unrecognised tail, which renders as 'unknown subcommand
    // or wrong number of arguments for <SUB>. Try XINFO HELP.'.
    // (br-frankenredis-xinfokey)
    let xinfo_subcommand_syntax_error = || {
        CommandError::Custom(format!(
            "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try XINFO HELP."
        ))
    };
    let full_mode = argv.len() >= 4 && eq_ascii_command(&argv[3], b"FULL");
    if !full_mode && argv.len() != 3 {
        return Err(xinfo_subcommand_syntax_error());
    }
    if full_mode && argv.len() != 4 && argv.len() != 6 {
        return Err(xinfo_subcommand_syntax_error());
    }
    let full_count: usize = if full_mode && argv.len() == 6 {
        if !eq_ascii_command(&argv[4], b"COUNT") {
            return Err(xinfo_subcommand_syntax_error());
        }
        // Upstream parses COUNT via getLongLongFromObjectOrReply
        // (which uses 'value is not an integer or out of range')
        // and silently treats negative counts as the default 10.
        let n = parse_i64_arg(&argv[5])?;
        if n < 0 {
            10
        } else {
            usize::try_from(n).map_err(|_| CommandError::InvalidInteger)?
        }
    } else {
        10 // Redis default COUNT for FULL is 10
    };

    let stream_watermark = store.stream_watermark(&argv[2])?;
    let last_generated_id = stream_watermark
        .map(format_stream_id)
        .unwrap_or_else(|| b"0-0".to_vec());
    let recorded_first_entry_id = first
        .as_ref()
        .map(|(id, _)| format_stream_id(*id))
        .unwrap_or_else(|| b"0-0".to_vec());
    let len_i64 = i64::try_from(len).unwrap_or(i64::MAX);
    let entries_added = store.stream_entries_added(&argv[2], len);
    let entries_added_i64 = i64::try_from(entries_added).unwrap_or(i64::MAX);
    let radix_tree_keys = i64::try_from(len).unwrap_or(i64::MAX);
    let radix_tree_nodes = i64::try_from(len.saturating_add(1)).unwrap_or(i64::MAX);
    let max_deleted_id = store.stream_max_deleted_id(&argv[2]).unwrap_or((0, 0));
    let max_deleted_entry_id = format_stream_id(max_deleted_id);

    if full_mode {
        // FULL mode: include entries and detailed group info
        let count_limit = stream_full_count_limit(full_count);
        let entries_frames: Vec<RespFrame> = store
            .xrange(&argv[2], (0, 0), (u64::MAX, u64::MAX), None, now_ms)?
            .into_iter()
            .take(count_limit)
            .map(|(id, fields)| stream_record_to_frame(id, fields))
            .collect();

        let groups = store.xinfo_groups(&argv[2], now_ms)?.unwrap_or_default();
        let mut group_frames = Vec::with_capacity(groups.len());
        for (name, _consumers_count, pending_count, last_delivered_id, entries_read) in &groups {
            let group_pending = store
                .xpending_entries(
                    &argv[2],
                    name,
                    ((0, 0), (u64::MAX, u64::MAX)),
                    count_limit,
                    None,
                    now_ms,
                    0,
                )?
                .unwrap_or_default()
                .into_iter()
                .map(|record| stream_full_group_pending_to_frame(record, now_ms))
                .collect();
            let consumers_info = store
                .xinfo_consumers(&argv[2], name, now_ms)
                .ok()
                .flatten()
                .unwrap_or_default();
            let resp_v = store.dispatch_client_ctx.resp_protocol_version;
            let mut consumer_frames = Vec::with_capacity(consumers_info.len());
            for info in consumers_info {
                let consumer = info.0.clone();
                let pending = store
                    .xpending_entries(
                        &argv[2],
                        name,
                        ((0, 0), (u64::MAX, u64::MAX)),
                        count_limit,
                        Some(&consumer),
                        now_ms,
                        0,
                    )?
                    .unwrap_or_default()
                    .into_iter()
                    .map(|record| stream_full_consumer_pending_to_frame(record, now_ms))
                    .collect();
                consumer_frames.push(stream_full_consumer_info_to_frame(
                    info, pending, now_ms, resp_v,
                ));
            }
            group_frames.push(stream_full_group_info_to_frame(
                StreamFullGroupFrameInfo {
                    name: name.clone(),
                    pending_count: *pending_count,
                    last_delivered_id: *last_delivered_id,
                    entries_read: *entries_read,
                    lag: stream_full_group_lag_frame(
                        entries_added,
                        len,
                        first.as_ref().map(|(id, _)| *id),
                        last.as_ref().map(|(id, _)| *id),
                        max_deleted_id,
                        *last_delivered_id,
                        *entries_read,
                    ),
                },
                group_pending,
                consumer_frames,
                resp_v,
            ));
        }

        // Upstream t_stream.c::xinfoFullCommand uses addReplyMapLen for
        // the FULL form (same as the non-FULL one). Emit RespFrame::Map
        // for RESP3 callers, alternating-array for RESP2.
        // (br-frankenredis-f6z6)
        let pairs: Vec<(RespFrame, RespFrame)> = vec![
            (
                RespFrame::BulkString(Some(b"length".to_vec())),
                RespFrame::Integer(len_i64),
            ),
            (
                RespFrame::BulkString(Some(b"radix-tree-keys".to_vec())),
                RespFrame::Integer(radix_tree_keys),
            ),
            (
                RespFrame::BulkString(Some(b"radix-tree-nodes".to_vec())),
                RespFrame::Integer(radix_tree_nodes),
            ),
            (
                RespFrame::BulkString(Some(b"last-generated-id".to_vec())),
                RespFrame::BulkString(Some(last_generated_id)),
            ),
            (
                RespFrame::BulkString(Some(b"max-deleted-entry-id".to_vec())),
                RespFrame::BulkString(Some(max_deleted_entry_id)),
            ),
            (
                RespFrame::BulkString(Some(b"entries-added".to_vec())),
                RespFrame::Integer(entries_added_i64),
            ),
            (
                RespFrame::BulkString(Some(b"recorded-first-entry-id".to_vec())),
                RespFrame::BulkString(Some(recorded_first_entry_id)),
            ),
            (
                RespFrame::BulkString(Some(b"entries".to_vec())),
                RespFrame::Array(Some(entries_frames)),
            ),
            (
                RespFrame::BulkString(Some(b"groups".to_vec())),
                RespFrame::Array(Some(group_frames)),
            ),
        ];
        if store.dispatch_client_ctx.resp_protocol_version == 3 {
            return Ok(RespFrame::Map(Some(pairs)));
        }
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        return Ok(RespFrame::Array(Some(flat)));
    }

    let group_count = store
        .xinfo_groups(&argv[2], now_ms)?
        .map(|groups| i64::try_from(groups.len()).unwrap_or(i64::MAX))
        .unwrap_or(0);

    let first_entry = first
        .map(|(id, fields)| stream_record_to_frame(id, fields))
        .unwrap_or(RespFrame::BulkString(None));
    let last_entry = last
        .map(|(id, fields)| stream_record_to_frame(id, fields))
        .unwrap_or(RespFrame::BulkString(None));

    // Upstream t_stream.c::xinfoCommand uses addReplyMapLen for
    // the non-FULL form. Emit RespFrame::Map for RESP3 callers,
    // alternating-array for RESP2. (br-frankenredis-f6z6)
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"length".to_vec())),
            RespFrame::Integer(len_i64),
        ),
        (
            RespFrame::BulkString(Some(b"radix-tree-keys".to_vec())),
            RespFrame::Integer(radix_tree_keys),
        ),
        (
            RespFrame::BulkString(Some(b"radix-tree-nodes".to_vec())),
            RespFrame::Integer(radix_tree_nodes),
        ),
        (
            RespFrame::BulkString(Some(b"last-generated-id".to_vec())),
            RespFrame::BulkString(Some(last_generated_id)),
        ),
        (
            RespFrame::BulkString(Some(b"max-deleted-entry-id".to_vec())),
            RespFrame::BulkString(Some(max_deleted_entry_id)),
        ),
        (
            RespFrame::BulkString(Some(b"entries-added".to_vec())),
            RespFrame::Integer(entries_added_i64),
        ),
        (
            RespFrame::BulkString(Some(b"recorded-first-entry-id".to_vec())),
            RespFrame::BulkString(Some(recorded_first_entry_id)),
        ),
        (
            RespFrame::BulkString(Some(b"groups".to_vec())),
            RespFrame::Integer(group_count),
        ),
        (
            RespFrame::BulkString(Some(b"first-entry".to_vec())),
            first_entry,
        ),
        (
            RespFrame::BulkString(Some(b"last-entry".to_vec())),
            last_entry,
        ),
    ];
    if store.dispatch_client_ctx.resp_protocol_version == 3 {
        Ok(RespFrame::Map(Some(pairs)))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        Ok(RespFrame::Array(Some(flat)))
    }
}

fn xrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XRANGE"));
    }
    // Upstream t_stream.c::xrangeGenericCommand emits 'syntax error'
    // (not wrong-arity) when the optional COUNT segment is malformed
    // or the trailing args don't fit the expected pattern.
    // (br-frankenredis-xrangearity)
    if argv.len() != 4 && argv.len() != 6 {
        return Err(CommandError::SyntaxError);
    }

    let start = match parse_stream_range_bound(&argv[2], true) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };
    let end = match parse_stream_range_bound(&argv[3], false) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };

    let count = if argv.len() == 6 {
        if !eq_ascii_command(&argv[4], b"COUNT") {
            return Err(CommandError::SyntaxError);
        }
        let parsed = parse_i64_arg(&argv[5])?;
        // Upstream parses COUNT via getLongFromObjectOrReply, clamps
        // negative values to 0, then emits a null array when count is 0.
        // (br-frankenredis-xrangenegcount)
        if parsed <= 0 {
            return Ok(RespFrame::Array(None));
        }
        Some(usize::try_from(parsed).unwrap_or(usize::MAX))
    } else {
        None
    };

    let records = store.xrange(&argv[1], start, end, count, now_ms)?;
    let mut out = Vec::with_capacity(records.len());
    for (id, fields) in records {
        let mut field_frames = Vec::with_capacity(fields.len().saturating_mul(2));
        for (field, value) in fields {
            field_frames.push(RespFrame::BulkString(Some(field)));
            field_frames.push(RespFrame::BulkString(Some(value)));
        }
        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(format_stream_id(id))),
            RespFrame::Array(Some(field_frames)),
        ])));
    }
    Ok(RespFrame::Array(Some(out)))
}

fn xrevrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XREVRANGE"));
    }
    // (br-frankenredis-xrangearity) — match upstream syntax-error
    // wording for malformed COUNT trailer.
    if argv.len() != 4 && argv.len() != 6 {
        return Err(CommandError::SyntaxError);
    }

    let end = match parse_stream_range_bound(&argv[2], false) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };
    let start = match parse_stream_range_bound(&argv[3], true) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };

    let count = if argv.len() == 6 {
        if !eq_ascii_command(&argv[4], b"COUNT") {
            return Err(CommandError::SyntaxError);
        }
        let parsed = parse_i64_arg(&argv[5])?;
        // (br-frankenredis-xrangenegcount) — see xrange.
        if parsed <= 0 {
            return Ok(RespFrame::Array(None));
        }
        Some(usize::try_from(parsed).unwrap_or(usize::MAX))
    } else {
        None
    };

    let records = store.xrevrange(&argv[1], end, start, count, now_ms)?;
    let mut out = Vec::with_capacity(records.len());
    for (id, fields) in records {
        let mut field_frames = Vec::with_capacity(fields.len().saturating_mul(2));
        for (field, value) in fields {
            field_frames.push(RespFrame::BulkString(Some(field)));
            field_frames.push(RespFrame::BulkString(Some(value)));
        }
        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(format_stream_id(id))),
            RespFrame::Array(Some(field_frames)),
        ])));
    }
    Ok(RespFrame::Array(Some(out)))
}

// ── XACK ────────────────────────────────────────────────────────────

fn xack_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XACK"));
    }
    let key = &argv[1];
    let group = &argv[2];
    // Upstream t_stream.c::xackCommand looks up the key + group
    // BEFORE validating IDs and short-circuits to 0 when either is
    // missing. The IDs are only parsed once both exist, so an
    // invalid ID against a missing key/group reports 0 rather than
    // 'Invalid stream ID specified...'. (br-frankenredis-xackorder)
    match store.xpending_summary(key, group, now_ms) {
        Ok(None) => return Ok(RespFrame::Integer(0)),
        Ok(Some(_)) => {}
        Err(e) => return Err(CommandError::Store(e)),
    }
    let mut ids = Vec::with_capacity(argv.len() - 3);
    for arg in &argv[3..] {
        let id = match parse_stream_id(arg) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        ids.push(id);
    }
    let acked = store.xack(key, group, &ids, now_ms)?;
    Ok(RespFrame::Integer(acked as i64))
}

// ── XSETID ──────────────────────────────────────────────────────────

fn xsetid_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // XSETID key last-id [ENTRIESADDED entries-added] [MAXDELETEDID max-deleted-id]
    //
    // Upstream t_stream.c::xsetidCommand parses both options strictly,
    // requires ENTRIESADDED >= 0, validates MAXDELETEDID as a stream
    // ID, and rejects when last-id < max_deleted_entry_id. The
    // missing-key case routes to `shared.nokeyerr` ("ERR no such key"),
    // not the prior FrankenRedis-specific "not present in the target
    // stream" wording. (br-frankenredis-r71v)
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("XSETID"));
    }
    let key = &argv[1];
    let last_id = match parse_stream_id(&argv[2]) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };

    let mut entries_added: Option<u64> = None;
    let mut max_deleted_id: Option<StreamId> = None;
    let mut i = 3;
    while i < argv.len() {
        let kw = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let moreargs = argv.len().saturating_sub(i + 1);
        if kw.eq_ignore_ascii_case("ENTRIESADDED") && moreargs > 0 {
            let value = parse_i64_arg(&argv[i + 1])?;
            if value < 0 {
                return Ok(RespFrame::Error(
                    "ERR entries_added must be positive".to_string(),
                ));
            }
            entries_added = Some(u64::try_from(value).unwrap_or(u64::MAX));
            i += 2;
        } else if kw.eq_ignore_ascii_case("MAXDELETEDID") && moreargs > 0 {
            let parsed = match parse_stream_id(&argv[i + 1]) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            if last_id < parsed {
                return Ok(RespFrame::Error(
                    "ERR The ID specified in XSETID is smaller than the provided max_deleted_entry_id"
                        .to_string(),
                ));
            }
            max_deleted_id = Some(parsed);
            i += 2;
        } else {
            return Ok(RespFrame::Error("ERR syntax error".to_string()));
        }
    }
    if let Some(current_max_deleted_id) = store.stream_max_deleted_id(key)
        && last_id < current_max_deleted_id
    {
        return Ok(RespFrame::Error(
            "ERR The ID specified in XSETID is smaller than current max_deleted_entry_id"
                .to_string(),
        ));
    }
    // Upstream t_stream.c::xsetidCommand rejects with the verbose
    // 'smaller than the target stream top item' wording when
    // last-id < current top stream id. (br-frankenredis-xsetid-top)
    if let Ok(Some(top)) = store.xlast_id(key, now_ms)
        && last_id < top
    {
        return Ok(RespFrame::Error(
            "ERR The ID specified in XSETID is smaller than the target stream top item".to_string(),
        ));
    }
    if let Some(entries_added) = entries_added {
        let live_len = store.xlen(key, now_ms)?;
        if entries_added < u64::try_from(live_len).unwrap_or(u64::MAX) {
            return Ok(RespFrame::Error(
                "ERR The entries_added specified in XSETID is smaller than the target stream length"
                    .to_string(),
            ));
        }
    }
    match store.xsetid_with_metadata(key, last_id, entries_added, max_deleted_id, now_ms) {
        Ok(true) => Ok(RespFrame::SimpleString("OK".to_string())),
        Ok(false) => Ok(RespFrame::Error("ERR no such key".to_string())),
        Err(e) => Err(e.into()),
    }
}

// ── LOLWUT ──────────────────────────────────────────────────────────

fn lolwut_cmd(argv: &[Vec<u8>]) -> Result<RespFrame, CommandError> {
    // LOLWUT [VERSION version]
    // Upstream Redis 7.2 dispatches via REDIS_VERSION major:
    //   5.x → lolwut5 (Schotter), 6.x → lolwut6 (braille),
    //   otherwise (incl. 7.x) → lolwutUnstableCommand which emits
    //   "Redis ver. <REDIS_VERSION>\n".
    // fr currently ports only the unstable branch; VERSION 5/6
    // arguments are accepted (so clients don't error out) but emit
    // the same single-line body. (br-frankenredis-m5nf)
    if argv.len() >= 2 {
        let ver_kw =
            std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if ver_kw.eq_ignore_ascii_case("VERSION") {
            if argv.len() < 3 {
                return Err(CommandError::WrongArity("LOLWUT"));
            }
            // Validate the version integer and any version-specific
            // trailing args, matching upstream's getLongFromObject
            // path.
            parse_i64_arg(&argv[2])?;
            for arg in &argv[3..] {
                parse_i64_arg(arg)?;
            }
        } else {
            for arg in &argv[1..] {
                parse_i64_arg(arg)?;
            }
        }
    }
    let body = format!("Redis ver. {}\n", fr_store::REDIS_COMPAT_VERSION);
    Ok(RespFrame::BulkString(Some(body.into_bytes())))
}

// ── WAITAOF ─────────────────────────────────────────────────────────

fn waitaof_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // WAITAOF numlocal numreplicas timeout
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("WAITAOF"));
    }
    // Upstream commands.def declares WAITAOF with CMD_NOSCRIPT, so
    // server.c::processCommand emits the noscript reply BEFORE the
    // handler ever runs. Mirror that order here so a scripted call
    // with bad args surfaces the noscript error rather than the
    // parse error. (frankenredis-d021m)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    let required_local = match parse_i64_arg(&argv[1]) {
        Ok(value @ 0..=1) => value,
        Ok(_) => {
            return Err(CommandError::Custom(
                "ERR value is out of range, value must between 0 and 1".to_string(),
            ));
        }
        Err(_) => return Err(CommandError::InvalidInteger),
    };
    let _required_replicas = match parse_i64_arg(&argv[2]) {
        Ok(value) if value >= 0 => value,
        _ => {
            return Err(CommandError::Custom(
                "ERR value is out of range, must be positive".to_string(),
            ));
        }
    };
    let timeout_ms = parse_i64_arg(&argv[3]).map_err(|_| {
        CommandError::Custom("ERR timeout is not an integer or out of range".to_string())
    })?;
    if timeout_ms < 0 {
        return Err(CommandError::Custom("ERR timeout is negative".to_string()));
    }
    // (frankenredis-0axo9) Upstream replication.c::waitaofCommand
    // gates this error on `numlocal && !server.aof_enabled` — fr was
    // unconditionally rejecting numlocal=1 regardless of the actual
    // AOF state, so a user who turned AOF on still got the
    // 'appendonly is disabled' error.
    if required_local > 0 && !store.aof_enabled {
        return Ok(RespFrame::Error(
            "ERR WAITAOF cannot be used when numlocal is set but appendonly is disabled."
                .to_string(),
        ));
    }
    // Standalone stub: no real fsync/replica ack tracking yet (see
    // project_wait_commands_stub). Return [0, 0] for both numlocal=0
    // and the AOF-enabled numlocal=1 path.
    Ok(RespFrame::Array(Some(vec![
        RespFrame::Integer(0),
        RespFrame::Integer(0),
    ])))
}

fn cluster_disabled_error() -> CommandError {
    CommandError::Custom("ERR This instance has cluster support disabled".to_string())
}

fn cluster_wrong_subcommand_arity(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR wrong number of arguments for 'cluster|{}' command",
        subcommand.to_ascii_lowercase()
    ))
}

fn cluster_unknown_subcommand_error(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR unknown subcommand '{subcommand}'. Try CLUSTER HELP."
    ))
}

fn cluster_subcommand_syntax_error(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR unknown subcommand or wrong number of arguments for '{subcommand}'. Try CLUSTER HELP."
    ))
}

fn cluster_reset_with_keys_error() -> CommandError {
    CommandError::Custom(
        "ERR CLUSTER RESET can't be called with master nodes containing keys".to_string(),
    )
}

fn parse_cluster_slot_arg(arg: &[u8]) -> Result<u16, CommandError> {
    let slot = parse_i64_arg(arg)
        .map_err(|_| CommandError::Custom("ERR Invalid or out of range slot".to_string()))?;
    if !(0..=16383).contains(&slot) {
        return Err(CommandError::Custom(
            "ERR Invalid or out of range slot".to_string(),
        ));
    }
    Ok(slot as u16)
}

fn cluster_slot_specified_multiple_times_error(slot: u16) -> CommandError {
    CommandError::Custom(format!("ERR Slot {slot} specified multiple times"))
}

fn cluster_slot_busy_error(slot: u16) -> CommandError {
    CommandError::Custom(format!("ERR Slot {slot} is already busy"))
}

fn cluster_slot_unassigned_error(slot: u16) -> CommandError {
    CommandError::Custom(format!("ERR Slot {slot} is already unassigned"))
}

fn cluster_invalid_node_address(host: &str, port: &str) -> CommandError {
    CommandError::Custom(format!("ERR Invalid node address specified: {host}:{port}"))
}

fn cluster_invalid_base_port(port: &str) -> CommandError {
    CommandError::Custom(format!("ERR Invalid base port specified: {port}"))
}

fn cluster_invalid_bus_port(port: &str) -> CommandError {
    CommandError::Custom(format!("ERR Invalid bus port specified: {port}"))
}

fn cluster_parse_port_arg(arg: &[u8]) -> Option<i64> {
    let s = std::str::from_utf8(arg).ok()?;
    s.parse::<i64>().ok()
}

fn cluster_collect_explicit_slots(argv: &[Vec<u8>]) -> Result<BTreeSet<u16>, CommandError> {
    let mut slots = BTreeSet::new();
    for slot_arg in argv {
        let slot = parse_cluster_slot_arg(slot_arg)?;
        if !slots.insert(slot) {
            return Err(cluster_slot_specified_multiple_times_error(slot));
        }
    }
    Ok(slots)
}

fn cluster_collect_slot_ranges(argv: &[Vec<u8>]) -> Result<BTreeSet<u16>, CommandError> {
    let mut slots = BTreeSet::new();
    let mut i = 0;
    while i + 1 < argv.len() {
        let start = parse_cluster_slot_arg(&argv[i])?;
        let end = parse_cluster_slot_arg(&argv[i + 1])?;
        if start > end {
            return Err(CommandError::Custom(format!(
                "ERR start slot number {start} is greater than end slot number {end}"
            )));
        }
        for slot in start..=end {
            if !slots.insert(slot) {
                return Err(cluster_slot_specified_multiple_times_error(slot));
            }
        }
        i += 2;
    }
    Ok(slots)
}

fn cluster_slot_range_frames(slots: &BTreeSet<u16>) -> Vec<RespFrame> {
    let mut frames = Vec::new();
    let mut iter = slots.iter().copied();
    let Some(mut start) = iter.next() else {
        return frames;
    };
    let mut end = start;
    for slot in iter {
        if end.checked_add(1) == Some(slot) {
            end = slot;
        } else {
            frames.push(RespFrame::Integer(i64::from(start)));
            frames.push(RespFrame::Integer(i64::from(end)));
            start = slot;
            end = slot;
        }
    }
    frames.push(RespFrame::Integer(i64::from(start)));
    frames.push(RespFrame::Integer(i64::from(end)));
    frames
}

fn cluster_shards_reply(store: &Store) -> RespFrame {
    // Mirror upstream cluster.c — addShardReplyForClusterShards uses
    // addReplyMapLen(c, 2) for the per-shard wrapper and addNodeToNodeReply
    // uses addReplyMapLen(c, length) for the per-node frame. Under RESP3
    // both must be Maps; RESP2 keeps the existing flat Array shape.
    // (frankenredis-ec2rf)
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    let node = if resp3 {
        RespFrame::Map(Some(vec![
            (hello_bulk("id"), RespFrame::BulkString(Some(store.server_run_id.as_bytes().to_vec()))),
            (hello_bulk("port"), RespFrame::Integer(i64::from(store.server_port))),
            (hello_bulk("ip"), hello_bulk("")),
            (hello_bulk("endpoint"), hello_bulk("")),
            (hello_bulk("role"), hello_bulk("master")),
            (hello_bulk("replication-offset"), RespFrame::Integer(0)),
            (hello_bulk("health"), hello_bulk("online")),
        ]))
    } else {
        RespFrame::Array(Some(vec![
            hello_bulk("id"),
            RespFrame::BulkString(Some(store.server_run_id.as_bytes().to_vec())),
            hello_bulk("port"),
            RespFrame::Integer(i64::from(store.server_port)),
            hello_bulk("ip"),
            hello_bulk(""),
            hello_bulk("endpoint"),
            hello_bulk(""),
            hello_bulk("role"),
            hello_bulk("master"),
            hello_bulk("replication-offset"),
            RespFrame::Integer(0),
            hello_bulk("health"),
            hello_bulk("online"),
        ]))
    };
    let slots_frame = RespFrame::Array(Some(cluster_slot_range_frames(
        &store.cluster_assigned_slots,
    )));
    let nodes_frame = RespFrame::Array(Some(vec![node]));
    let shard = if resp3 {
        RespFrame::Map(Some(vec![
            (hello_bulk("slots"), slots_frame),
            (hello_bulk("nodes"), nodes_frame),
        ]))
    } else {
        RespFrame::Array(Some(vec![
            hello_bulk("slots"),
            slots_frame,
            hello_bulk("nodes"),
            nodes_frame,
        ]))
    };
    RespFrame::Array(Some(vec![shard]))
}

// ── CLUSTER ─────────────────────────────────────────────────────────

fn cluster_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("CLUSTER"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("HELP")
        || sub.eq_ignore_ascii_case("INFO")
        || sub.eq_ignore_ascii_case("SLOTS")
        || sub.eq_ignore_ascii_case("NODES")
    {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        return Err(cluster_disabled_error());
    }
    if sub.eq_ignore_ascii_case("LINKS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::Array(Some(vec![])));
    }
    if sub.eq_ignore_ascii_case("MYID") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::BulkString(Some(
            store.server_run_id.as_bytes().to_vec(),
        )));
    }
    if sub.eq_ignore_ascii_case("SHARDS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(cluster_shards_reply(store));
    }
    if sub.eq_ignore_ascii_case("MYSHARDID") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::BulkString(Some(
            store.cluster_shard_id.as_bytes().to_vec(),
        )));
    }
    if sub.eq_ignore_ascii_case("KEYSLOT") {
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = fr_store::crc16_slot(&argv[2]);
        return Ok(RespFrame::Integer(i64::from(slot)));
    }
    if sub.eq_ignore_ascii_case("GETKEYSINSLOT") {
        if argv.len() != 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let count = parse_i64_arg(&argv[3])?;
        if count < 0 {
            return Err(CommandError::InvalidInteger);
        }
        let keys = store.keys_in_slot(slot as u16, count as usize, now_ms);
        let frames: Vec<RespFrame> = keys
            .into_iter()
            .map(|k| RespFrame::BulkString(Some(k)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    if sub.eq_ignore_ascii_case("COUNTKEYSINSLOT") {
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let count = store.count_keys_in_slot(slot as u16, now_ms);
        return Ok(RespFrame::Integer(count as i64));
    }
    if sub.eq_ignore_ascii_case("RESET") {
        if argv.len() > 3 {
            if store.script_nesting_level >= 1 {
                return Err(cluster_subcommand_syntax_error(sub));
            }
            if !store.cluster_enabled {
                return Err(cluster_disabled_error());
            }
            return Err(cluster_subcommand_syntax_error(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if let Some(mode) = argv.get(2) {
            let mode = std::str::from_utf8(mode).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("SOFT") && !mode.eq_ignore_ascii_case("HARD") {
                return Err(CommandError::SyntaxError);
            }
        }
        let db_index = store.dispatch_client_ctx.db_index;
        if store.dbsize_in_db(db_index) != 0 {
            return Err(cluster_reset_with_keys_error());
        }
        store.cluster_assigned_slots.clear();
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    // ── CLUSTER admin subcommands (first-pass per br-frankenredis-jsr7) ──
    //
    // Upstream cluster.c::clusterCommand wires each of these with distinct
    // validation + reply semantics. We implement arity + syntax validation
    // against the upstream shape; for commands that need a real node map
    // (which fr-repl does not yet expose), we accept-OK for no-op admin
    // flows and surface upstream-matching specific errors ("Unknown node X",
    // "DB must be empty ...", etc.) rather than the blanket "cluster
    // support disabled" string. Commands still punted to that blanket
    // error because they need a slot map / config epoch / node registry:
    //   SET-CONFIG-EPOCH, SLOTSTATE.
    if sub.eq_ignore_ascii_case("MEET") {
        // CLUSTER MEET <host> <port> [cluster-bus-port]
        // Upstream commands.def declares arity -4 (min 4, no max),
        // so trailing args still hit the cluster-disabled error
        // before any per-subcommand arity rejection. Once cluster
        // mode is enabled the handler still rejects argc > 5.
        // (br-frankenredis-clustermeetarity)
        if argv.len() < 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if argv.len() > 5 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        let host = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let port = std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let Some(parsed_port) = cluster_parse_port_arg(&argv[3]) else {
            return Err(cluster_invalid_base_port(port));
        };
        if !(1..=65535).contains(&parsed_port) || host.parse::<std::net::IpAddr>().is_err() {
            return Err(cluster_invalid_node_address(host, port));
        }
        if let Some(bus_port) = argv.get(4) {
            let bus_port_str =
                std::str::from_utf8(bus_port).map_err(|_| CommandError::InvalidUtf8Argument)?;
            let Some(parsed_bus_port) = cluster_parse_port_arg(bus_port) else {
                return Err(cluster_invalid_bus_port(bus_port_str));
            };
            if !(1..=65535).contains(&parsed_bus_port) {
                return Err(cluster_invalid_node_address(host, port));
            }
        }
        // Accept but do not yet actually start a cluster handshake — a real
        // node registry is a separate work item.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("FORGET") || sub.eq_ignore_ascii_case("REPLICATE") {
        // CLUSTER FORGET <node-id> / CLUSTER REPLICATE <node-id>
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id =
            std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if sub.eq_ignore_ascii_case("FORGET") && node_id == store.server_run_id {
            return Err(CommandError::Custom(
                "ERR I tried hard but I can't forget myself...".to_string(),
            ));
        }
        if sub.eq_ignore_ascii_case("REPLICATE") && node_id == store.server_run_id {
            return Err(CommandError::Custom(
                "ERR Can't replicate myself".to_string(),
            ));
        }
        return Err(CommandError::Custom(format!("ERR Unknown node {node_id}")));
    }
    if sub.eq_ignore_ascii_case("REPLICAS") || sub.eq_ignore_ascii_case("SLAVES") {
        // CLUSTER REPLICAS <node-id> — upstream returns the replica array or
        // "The specified node is not known or can't be a replica" error.
        // SLAVES is upstream's deprecated alias for REPLICAS — see
        // legacy_redis_code/redis/src/commands/cluster-slaves.json.
        // (br-frankenredis-gcmq)
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id =
            std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if node_id == store.server_run_id {
            return Ok(RespFrame::Array(Some(vec![])));
        }
        return Err(CommandError::Custom(
            "ERR The specified node is not known or can't be a replica".to_string(),
        ));
    }
    if sub.eq_ignore_ascii_case("FAILOVER") {
        // CLUSTER FAILOVER [FORCE | TAKEOVER]+ — upstream accepts
        // either or both flags in any order. The cluster-enabled
        // gate fires BEFORE any subcommand-level arity / option
        // parsing, so excess args still yield 'cluster support
        // disabled' in standalone mode. (br-frankenredis-clusterord)
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if argv.len() > 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        for flag in &argv[2..] {
            let flag_str =
                std::str::from_utf8(flag).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !flag_str.eq_ignore_ascii_case("FORCE") && !flag_str.eq_ignore_ascii_case("TAKEOVER")
            {
                return Err(CommandError::SyntaxError);
            }
        }
        // Upstream: "You should send CLUSTER FAILOVER to a replica" when
        // issued on a master. We treat ourselves as master here (no replica
        // role tracking at the Store layer yet).
        return Err(CommandError::Custom(
            "ERR You should send CLUSTER FAILOVER to a replica".to_string(),
        ));
    }
    if sub.eq_ignore_ascii_case("ADDSLOTS") || sub.eq_ignore_ascii_case("DELSLOTS") {
        // CLUSTER ADDSLOTS <slot> [slot] ... / CLUSTER DELSLOTS ...
        if argv.len() < 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slots = cluster_collect_explicit_slots(&argv[2..])?;
        if sub.eq_ignore_ascii_case("ADDSLOTS") {
            for slot in &slots {
                if store.cluster_assigned_slots.contains(slot) {
                    return Err(cluster_slot_busy_error(*slot));
                }
            }
            for slot in slots {
                store.cluster_assigned_slots.insert(slot);
            }
        } else {
            for slot in &slots {
                if !store.cluster_assigned_slots.contains(slot) {
                    return Err(cluster_slot_unassigned_error(*slot));
                }
            }
            for slot in slots {
                store.cluster_assigned_slots.remove(&slot);
            }
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("ADDSLOTSRANGE") || sub.eq_ignore_ascii_case("DELSLOTSRANGE") {
        // CLUSTER ADDSLOTSRANGE <start> <end> [<start> <end> ...]
        // Upstream commands.def declares arity = -4 (≥4 args incl
        // CLUSTER + sub). The multiple-of-2 pair check happens
        // inside the cluster handler AFTER the cluster-enabled gate
        // — so in standalone mode 'cluster support disabled' fires
        // before the pair check. (br-frankenredis-clusterord)
        if argv.len() < 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if !argv.len().is_multiple_of(2) {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        let slots = cluster_collect_slot_ranges(&argv[2..])?;
        if sub.eq_ignore_ascii_case("ADDSLOTSRANGE") {
            for slot in &slots {
                if store.cluster_assigned_slots.contains(slot) {
                    return Err(cluster_slot_busy_error(*slot));
                }
            }
            for slot in slots {
                store.cluster_assigned_slots.insert(slot);
            }
        } else {
            for slot in &slots {
                if !store.cluster_assigned_slots.contains(slot) {
                    return Err(cluster_slot_unassigned_error(*slot));
                }
            }
            for slot in slots {
                store.cluster_assigned_slots.remove(&slot);
            }
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("FLUSHSLOTS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let db_index = store.dispatch_client_ctx.db_index;
        if store.dbsize_in_db(db_index) != 0 {
            return Err(CommandError::Custom(
                "ERR DB must be empty to perform CLUSTER FLUSHSLOTS.".to_string(),
            ));
        }
        store.cluster_assigned_slots.clear();
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("SAVECONFIG") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Upstream writes cluster.conf; we don't persist cluster state yet,
        // so this is a no-op. Returning OK matches the happy-path reply.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("BUMPEPOCH") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Upstream returns "BUMPED <epoch>" or "STILL <epoch>". We don't
        // track a real config epoch yet; return BUMPED 1 as the smallest
        // advance that still parses for clients that inspect the reply.
        return Ok(RespFrame::SimpleString("BUMPED 1".to_string()));
    }
    if sub.eq_ignore_ascii_case("SET-CONFIG-EPOCH") {
        // Upstream commands.def declares CLUSTER SET-CONFIG-EPOCH
        // with arity = 3, so missing/extra args trigger the
        // table-level WrongArity check before clusterCommand runs.
        // (br-frankenredis-clusterord)
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        return Err(cluster_disabled_error());
    }
    if sub.eq_ignore_ascii_case("SLOTSTATE") {
        return Err(cluster_disabled_error());
    }
    if sub.eq_ignore_ascii_case("SETSLOT") {
        // CLUSTER SETSLOT <slot> STABLE
        // CLUSTER SETSLOT <slot> NODE <node-id>
        // CLUSTER SETSLOT <slot> MIGRATING <node-id>
        // CLUSTER SETSLOT <slot> IMPORTING <node-id>
        // Real slot-migration machinery not yet implemented; mirror
        // upstream's "cluster support disabled" reply when cluster
        // mode is off. (br-frankenredis-nzaw)
        if argv.len() != 4 && argv.len() != 5 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Err(cluster_disabled_error());
    }
    if sub.eq_ignore_ascii_case("COUNT-FAILURE-REPORTS") {
        // Upstream cluster.c::clusterCommand: when cluster mode is on,
        // looks up the node-id and replies with the failure-report
        // count or `-Unknown node <id>`. With cluster mode off the
        // standard "This instance has cluster support disabled" applies.
        // (br-frankenredis-r84v)
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id =
            std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if node_id == store.server_run_id {
            return Ok(RespFrame::Integer(0));
        }
        return Err(CommandError::Custom(format!("ERR Unknown node {node_id}")));
    }
    Err(cluster_unknown_subcommand_error(sub))
}

// ── REPLCONF ────────────────────────────────────────────────────────

fn replconf_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len().is_multiple_of(2) {
        return Err(CommandError::SyntaxError);
    }
    let mut idx = 1;
    while idx < argv.len() {
        let option =
            std::str::from_utf8(&argv[idx]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if option.eq_ignore_ascii_case("ACK") || option.eq_ignore_ascii_case("FACK") {
            let offset = parse_i64_arg(&argv[idx + 1])?;
            if offset < 0 {
                return Err(CommandError::InvalidInteger);
            }
            if store.script_nesting_level >= 1 {
                return Err(script_noscript_command_error());
            }
            return Ok(RespFrame::SimpleString("OK".to_string()));
        }
        if option.eq_ignore_ascii_case("GETACK") {
            if store.script_nesting_level >= 1 {
                return Err(script_noscript_command_error());
            }
            return Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"REPLCONF".to_vec())),
                RespFrame::BulkString(Some(b"ACK".to_vec())),
                RespFrame::BulkString(Some(b"0".to_vec())),
            ])));
        }
        if option.eq_ignore_ascii_case("listening-port") {
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            u16::try_from(parsed).map_err(|_| CommandError::InvalidInteger)?;
        } else if option.eq_ignore_ascii_case("ip-address") || option.eq_ignore_ascii_case("capa") {
            // Accept configuration pairs silently.
        } else {
            return Err(CommandError::Custom(format!(
                "ERR Unrecognized REPLCONF option: {option}"
            )));
        }
        idx += 2;
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

// ── PSYNC ───────────────────────────────────────────────────────────

fn psync_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // PSYNC replid offset
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("PSYNC"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    // In standalone mode, FULLRESYNC with the server's own run_id so
    // subsequent PSYNC retries that echo this replid can be matched. The
    // offset stays at 0 here (a full replication backlog is not yet
    // tracked at this layer — see frankenredis-fcjh for the real
    // handshake pipeline). (br-frankenredis-fcjh, partial)
    let replid = store.server_run_id.clone();
    let offset = 0;
    Ok(RespFrame::SimpleString(format!(
        "FULLRESYNC {replid} {offset}"
    )))
}

// ── REPLICAOF / SLAVEOF ─────────────────────────────────────────────

fn replicaof_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // REPLICAOF host port / REPLICAOF NO ONE
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(replicaof_command_name(argv)));
    }
    // Upstream commands.def declares REPLICAOF/SLAVEOF with
    // CMD_NOSCRIPT. server.c::processCommand emits the noscript
    // reply BEFORE the handler runs, so a scripted call must
    // surface that error rather than the 'Invalid master port'
    // parse error we previously emitted for non-numeric ports.
    // (frankenredis-d021m)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    let host = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    let port = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if host.eq_ignore_ascii_case("NO") && port.eq_ignore_ascii_case("ONE") {
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else {
        let parsed = parse_i64_arg(&argv[2])
            .map_err(|_| CommandError::Custom("ERR Invalid master port".to_string()))?;
        u16::try_from(parsed)
            .map_err(|_| CommandError::Custom("ERR Invalid master port".to_string()))?;
        // Accept but don't actually replicate - standalone mode
        Ok(RespFrame::SimpleString("OK".to_string()))
    }
}

// ── READONLY / READWRITE ────────────────────────────────────────────

fn readonly_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("READONLY"));
    }
    // Upstream cluster.c::readonlyCommand: returns OK when cluster_enabled,
    // errors with "This instance has cluster support disabled" otherwise.
    // The actual per-client CLIENT_READONLY bit-flag is a cluster-routing
    // concern we don't yet honor; returning OK unblocks clients that use
    // READONLY as a preamble to replica-routed reads. (br-frankenredis-jsr7)
    if !store.cluster_enabled {
        return Err(CommandError::Custom(
            "ERR This instance has cluster support disabled".to_string(),
        ));
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn readwrite_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("READWRITE"));
    }
    // Upstream cluster.c::readwriteCommand: mirror of readonly — OK when
    // cluster_enabled, disabled-error otherwise.
    if !store.cluster_enabled {
        return Err(CommandError::Custom(
            "ERR This instance has cluster support disabled".to_string(),
        ));
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

// ── ZRANGESTORE ────────────────────────────────────────────────────

fn zrangestore_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANGESTORE dst src min max [BYSCORE | BYLEX] [REV] [LIMIT offset count]
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("ZRANGESTORE"));
    }
    let dst = &argv[1];
    let src = &argv[2];

    let mut byscore = false;
    let mut bylex = false;
    let mut rev = false;
    let mut limit_offset: Option<usize> = None;
    let mut limit_count: Option<usize> = None;

    let mut i = 5;
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("BYSCORE") {
            byscore = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("BYLEX") {
            bylex = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("REV") {
            rev = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            limit_offset = Some(
                usize::try_from(parse_u64_arg(&argv[i + 1])?)
                    .map_err(|_| CommandError::InvalidInteger)?,
            );
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if byscore && bylex {
        return Err(CommandError::SyntaxError);
    }

    // Mirror upstream t_zset.c::zrangeGenericCommand which rejects LIMIT
    // unless paired with BYSCORE or BYLEX.
    if limit_offset.is_some() && !byscore && !bylex {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string(),
        ));
    }

    let pairs: Vec<(Vec<u8>, f64)> = if byscore {
        let min = parse_score_bound(&argv[3])?;
        let max = parse_score_bound(&argv[4])?;
        let (lo, hi) = if rev { (max, min) } else { (min, max) };
        let mut result = store.zrangebyscore_withscores(src, lo, hi, now_ms)?;
        if rev {
            result.reverse();
        }
        result
    } else if bylex {
        let min_lex = &argv[3];
        let max_lex = &argv[4];
        validate_lex_bound(min_lex)?;
        validate_lex_bound(max_lex)?;
        let (lo, hi) = if rev {
            (max_lex.as_slice(), min_lex.as_slice())
        } else {
            (min_lex.as_slice(), max_lex.as_slice())
        };
        let mut members = store.zrangebylex(src, lo, hi, now_ms)?;
        if rev {
            members.reverse();
        }
        // Look up scores for each member
        let mut result = Vec::with_capacity(members.len());
        for m in members {
            let score = store.zscore(src, &m, now_ms)?.unwrap_or(0.0);
            result.push((m, score));
        }
        result
    } else {
        // Default: by rank (index)
        let start = parse_i64_arg(&argv[3])?;
        let stop = parse_i64_arg(&argv[4])?;
        if rev {
            store.zrevrange_withscores(src, start, stop, now_ms)?
        } else {
            store.zrange_withscores(src, start, stop, now_ms)?
        }
    };

    // Apply LIMIT
    let pairs = if let Some(offset) = limit_offset {
        if let Some(count) = limit_count {
            pairs.into_iter().skip(offset).take(count).collect()
        } else {
            pairs.into_iter().skip(offset).collect()
        }
    } else {
        pairs
    };

    let count = pairs.len() as i64;
    if pairs.is_empty() {
        // Delete dst if it exists
        store.del(std::slice::from_ref(dst), now_ms);
    } else {
        store.zstore_from_pairs(dst.clone(), pairs, now_ms);
    }
    Ok(RespFrame::Integer(count))
}

// ── FUNCTION ────────────────────────────────────────────────────────

fn function_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("FUNCTION"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("LOAD") {
        // FUNCTION LOAD [REPLACE] function-code
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "LOAD".to_string(),
            });
        }
        let mut replace = false;
        let code_idx;
        if argv.len() >= 4 {
            let flag =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if flag.eq_ignore_ascii_case("REPLACE") {
                replace = true;
                code_idx = 3;
            } else {
                code_idx = 2;
            }
        } else {
            code_idx = 2;
        }
        if code_idx >= argv.len() {
            return Err(CommandError::WrongArity("FUNCTION"));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        match store.function_load(&argv[code_idx], replace) {
            Ok(name) => Ok(RespFrame::BulkString(Some(name.into_bytes()))),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("LIST") {
        // FUNCTION LIST [LIBRARYNAME pattern] [WITHCODE]
        // Upstream FUNCTION LIST carries CMD_NOSCRIPT — fire the
        // noscript guard before the option-parsing loop so a
        // scripted bad-arg call surfaces the noscript reply
        // rather than 'Unknown argument <token>' or 'library name
        // argument was not given'. (frankenredis-yrm7e)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let mut pattern = None;
        let mut with_code = false;
        let mut i = 2;
        while i < argv.len() {
            let arg =
                std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if arg.eq_ignore_ascii_case("LIBRARYNAME") {
                i += 1;
                if i >= argv.len() {
                    // Upstream functions.c::functionListCommand emits
                    // 'library name argument was not given' when the
                    // LIBRARYNAME option is missing its argument.
                    // (br-frankenredis-funclist)
                    return Err(CommandError::Custom(
                        "ERR library name argument was not given".to_string(),
                    ));
                }
                let pat =
                    std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
                pattern = Some(pat.to_string());
            } else if arg.eq_ignore_ascii_case("WITHCODE") {
                with_code = true;
            } else {
                // Upstream functions.c::functionListCommand emits
                // 'ERR Unknown argument <token>' for any token
                // outside LIBRARYNAME / WITHCODE. (br-frankenredis-funclist)
                return Err(CommandError::Custom(format!("ERR Unknown argument {arg}")));
            }
            i += 1;
        }
        // (frankenredis-1dfox) Upstream functions.c::functionListCommand
        // emits per-library + per-function as Maps under RESP3
        // (addReplyMapLen(c, with_code ? 4 : 3) for the library and
        // addReplyMapLen(c, 3) for each function). RESP2 stays the
        // existing flat alternating-k/v Array. Same shape pattern
        // as i40x2/e4njz/udl3y/asvh1/5d04d/ndz0j/5h86s/cz712/ec2rf/
        // q11am.
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let libs = store.function_list(pattern.as_deref());
        let mut result = Vec::new();
        for lib in libs {
            let mut entries = vec![
                RespFrame::BulkString(Some(b"library_name".to_vec())),
                RespFrame::BulkString(Some(lib.name.as_bytes().to_vec())),
                RespFrame::BulkString(Some(b"engine".to_vec())),
                // PINNED 2026-04-22 — do NOT lowercase this.
                //
                // Verified against the vendored Redis 7.2.4 source
                // (legacy_redis_code/redis/src/function_lua.c:48 defines
                // `#define LUA_ENGINE_NAME "LUA"` and line 505 registers the
                // Lua engine as `functionsRegisterEngine(LUA_ENGINE_NAME, ...)`).
                // functions.c:551-552 then emits the engine field via
                // `addReplyBulkCBuffer(c, li->ei->name, ...)`, which is the
                // registered `"LUA"` string — i.e. upstream Redis 7.2.4 emits
                // the engine name in its stored case (`"LUA"`, uppercase).
                // The matching pin in the FUNCTION STATS engines map below
                // hardcodes `b"LUA"` for the same reason.
                //
                // Prior agents have flipped this line to
                // `lib.engine.to_ascii_lowercase().into_bytes()` at least
                // four times. The empirical record on the vendored Redis
                // 7.2.4 tree is unambiguous — `to_ascii_lowercase` introduces
                // a parity divergence. The root cause of the repeated flip
                // was that the `function_list_basic` fixture in
                // crates/fr-conformance/fixtures/core_scripting.json briefly
                // expected `"lua"`; that fixture has been corrected to
                // `"LUA"` so the fixture and the code now agree.
                // If a future Redis release changes this, update both the
                // live-oracle fixture and this comment in the same commit.
                RespFrame::BulkString(Some(lib.engine.as_bytes().to_vec())),
                RespFrame::BulkString(Some(b"functions".to_vec())),
            ];
            let funcs: Vec<RespFrame> = lib
                .functions
                .iter()
                .map(|f| {
                    let name_frame =
                        RespFrame::BulkString(Some(f.name.as_bytes().to_vec()));
                    let desc_frame = match &f.description {
                        Some(d) => RespFrame::BulkString(Some(d.as_bytes().to_vec())),
                        None => RespFrame::BulkString(None),
                    };
                    let flags_frame = RespFrame::Array(Some(
                        f.flags
                            .iter()
                            .map(|fl| RespFrame::BulkString(Some(fl.as_bytes().to_vec())))
                            .collect(),
                    ));
                    if resp == 3 {
                        RespFrame::Map(Some(vec![
                            (RespFrame::BulkString(Some(b"name".to_vec())), name_frame),
                            (
                                RespFrame::BulkString(Some(b"description".to_vec())),
                                desc_frame,
                            ),
                            (
                                RespFrame::BulkString(Some(b"flags".to_vec())),
                                flags_frame,
                            ),
                        ]))
                    } else {
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"name".to_vec())),
                            name_frame,
                            RespFrame::BulkString(Some(b"description".to_vec())),
                            desc_frame,
                            RespFrame::BulkString(Some(b"flags".to_vec())),
                            flags_frame,
                        ]))
                    }
                })
                .collect();
            entries.push(RespFrame::Array(Some(funcs)));
            if with_code {
                entries.push(RespFrame::BulkString(Some(b"library_code".to_vec())));
                entries.push(RespFrame::BulkString(Some(lib.code.clone())));
            }
            if resp == 3 {
                assert!(
                    entries.len().is_multiple_of(2),
                    "FUNCTION LIST library entries must be balanced k/v pairs"
                );
                let mut pairs = Vec::with_capacity(entries.len() / 2);
                let mut iter = entries.into_iter();
                while let (Some(k), Some(v)) = (iter.next(), iter.next()) {
                    pairs.push((k, v));
                }
                result.push(RespFrame::Map(Some(pairs)));
            } else {
                result.push(RespFrame::Array(Some(entries)));
            }
        }
        Ok(RespFrame::Array(Some(result)))
    } else if sub.eq_ignore_ascii_case("STATS") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "STATS".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let (lib_count, func_count) = store.function_stats();
        // Mirror upstream functions.c::functionStatsCommand which uses
        // doubly-nested addReplyMapLen — RESP3 wire shape is a Map of
        // 2 pairs at the outer level (running_script, engines), with
        // 'engines' being a Map of (engine_name, per-engine Map). The
        // per-engine inner Map carries (libraries_count, N) and
        // (functions_count, M). RESP2 stays the existing flat Array of
        // alternating k/v entries with the engine details nested as
        // sub-Arrays. (frankenredis-asvh1)
        if store.dispatch_client_ctx.resp_protocol_version == 3 {
            let lua_inner = RespFrame::Map(Some(vec![
                (
                    RespFrame::BulkString(Some(b"libraries_count".to_vec())),
                    RespFrame::Integer(lib_count as i64),
                ),
                (
                    RespFrame::BulkString(Some(b"functions_count".to_vec())),
                    RespFrame::Integer(func_count as i64),
                ),
            ]));
            let engines = RespFrame::Map(Some(vec![(
                RespFrame::BulkString(Some(b"LUA".to_vec())),
                lua_inner,
            )]));
            Ok(RespFrame::Map(Some(vec![
                (
                    RespFrame::BulkString(Some(b"running_script".to_vec())),
                    RespFrame::BulkString(None),
                ),
                (RespFrame::BulkString(Some(b"engines".to_vec())), engines),
            ])))
        } else {
            Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"running_script".to_vec())),
                // PINNED 2026-04-22 — running_script is RESP2 nil (BulkString(None))
                // when no script is executing, NOT Integer(0). Verified against
                // stock `redis:7.4` (version 7.4.8): `FUNCTION STATS` returns
                // `(nil)` in the running_script slot on an idle server. A prior
                // session briefly changed this to `RespFrame::Integer(0)`; that
                // was incorrect and has since been reverted. Leave it as nil.
                RespFrame::BulkString(None),
                RespFrame::BulkString(Some(b"engines".to_vec())),
                RespFrame::Array(Some(vec![
                    // PINNED 2026-04-22 — engine name is emitted in its stored case
                    // (uppercase "LUA") in both FUNCTION STATS and FUNCTION LIST;
                    // see the matching pin at the `lib.engine.as_bytes()` line in
                    // the FUNCTION LIST handler above.
                    RespFrame::BulkString(Some(b"LUA".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"libraries_count".to_vec())),
                        RespFrame::Integer(lib_count as i64),
                        RespFrame::BulkString(Some(b"functions_count".to_vec())),
                        RespFrame::Integer(func_count as i64),
                    ])),
                ])),
            ])))
        }
    } else if sub.eq_ignore_ascii_case("DUMP") {
        // Upstream commands.def declares FUNCTION DUMP with arity = 2,
        // so any extra arg trips the table-level WrongArity check
        // before functions.c::functionDumpCommand runs. (br-frankenredis-funcdump)
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "DUMP".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let data = store.function_dump();
        Ok(RespFrame::BulkString(Some(data)))
    } else if sub.eq_ignore_ascii_case("RESTORE") {
        // FUNCTION RESTORE serialized-value [FLUSH|APPEND|REPLACE]
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "RESTORE".to_string(),
            });
        }
        // Upstream FUNCTION RESTORE carries CMD_NOSCRIPT — fire the
        // noscript guard before the extra-arg / policy parse checks.
        // (frankenredis-yrm7e)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if argv.len() > 4 {
            return Err(CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'RESTORE'. Try FUNCTION HELP."
                    .to_string(),
            ));
        }
        let policy = if argv.len() >= 4 {
            std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?
        } else {
            ""
        };
        match store.function_restore(&argv[2], policy) {
            Ok(()) => Ok(RespFrame::SimpleString("OK".to_string())),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("FLUSH") {
        // (br-frankenredis-ngn0) — upstream functions.c::functionsCommand
        // emits the FLUSH-specific subcommand error, not a generic
        // wrong-arity reply.
        // Upstream FUNCTION FLUSH carries CMD_NOSCRIPT (commands.def
        // line 5140) — the flag is checked at dispatch level before
        // any handler-level extra-arg or mode validation.
        // (frankenredis-yrm7e)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if argv.len() > 3 {
            return Err(CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'FLUSH'. Try FUNCTION HELP.".to_string(),
            ));
        }
        if argv.len() == 3 {
            let mode =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("ASYNC") && !mode.eq_ignore_ascii_case("SYNC") {
                return Ok(RespFrame::Error(
                    "ERR FUNCTION FLUSH only supports SYNC|ASYNC option".to_string(),
                ));
            }
        }
        store.function_flush();
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("KILL") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "KILL".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::Error(
            "NOTBUSY No scripts in execution right now.".to_string(),
        ))
    } else if sub.eq_ignore_ascii_case("DELETE") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "DELETE".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let name = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        match store.function_delete(name) {
            Ok(()) => Ok(RespFrame::SimpleString("OK".to_string())),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "HELP".to_string(),
            });
        }
        Ok(RespFrame::Array(Some(vec![
            hello_simple("FUNCTION <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("LOAD [REPLACE] <FUNCTION CODE>"),
            hello_simple("    Create a new library with the given library name and code."),
            hello_simple("DELETE <LIBRARY NAME>"),
            hello_simple("    Delete the given library."),
            hello_simple("LIST [LIBRARYNAME PATTERN] [WITHCODE]"),
            hello_simple("    Return general information on all the libraries:"),
            hello_simple("    * Library name"),
            hello_simple("    * The engine used to run the Library"),
            hello_simple("    * Library description"),
            hello_simple("    * Functions list"),
            hello_simple("    * Library code (if WITHCODE is given)"),
            hello_simple(
                "    It also possible to get only function that matches a pattern using LIBRARYNAME argument.",
            ),
            hello_simple("STATS"),
            hello_simple("    Return information about the current function running:"),
            hello_simple("    * Function name"),
            hello_simple("    * Command used to run the function"),
            hello_simple("    * Duration in MS that the function is running"),
            hello_simple("    If no function is running, return nil"),
            hello_simple("    In addition, returns a list of available engines."),
            hello_simple("KILL"),
            hello_simple("    Kill the current running function."),
            hello_simple("FLUSH [ASYNC|SYNC]"),
            hello_simple("    Delete all the libraries."),
            hello_simple(
                "    When called without the optional mode argument, the behavior is determined by the",
            ),
            hello_simple("    lazyfree-lazy-user-flush configuration directive. Valid modes are:"),
            hello_simple("    * ASYNC: Asynchronously flush the libraries."),
            hello_simple("    * SYNC: Synchronously flush the libraries."),
            hello_simple("DUMP"),
            hello_simple(
                "    Return a serialized payload representing the current libraries, can be restored using FUNCTION RESTORE command",
            ),
            hello_simple("RESTORE <PAYLOAD> [FLUSH|APPEND|REPLACE]"),
            hello_simple(
                "    Restore the libraries represented by the given payload, it is possible to give a restore policy to",
            ),
            hello_simple("    control how to handle existing libraries (default APPEND):"),
            hello_simple("    * FLUSH: delete all existing libraries."),
            hello_simple(
                "    * APPEND: appends the restored libraries to the existing libraries. On collision, abort.",
            ),
            hello_simple(
                "    * REPLACE: appends the restored libraries to the existing libraries, On collision, replace the old",
            ),
            hello_simple(
                "      libraries with the new libraries (notice that even on this option there is a chance of failure",
            ),
            hello_simple("      in case of functions name collision with another library)."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "FUNCTION",
            subcommand: sub.to_string(),
        })
    }
}

/// Remap parse_eval_args' generic InvalidInteger error into FCALL's
/// upstream-specific 'Bad number of keys provided' wording.
/// (frankenredis-ascgr)
fn fcall_map_eval_arg_error(err: CommandError) -> CommandError {
    if matches!(err, CommandError::InvalidInteger) {
        CommandError::Custom("ERR Bad number of keys provided".to_string())
    } else {
        err
    }
}

fn fcall_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // FCALL function numkeys [key ...] [arg ...]
    let cmd_name = std::str::from_utf8(&argv[0]).unwrap_or("FCALL");
    let is_ro = cmd_name.eq_ignore_ascii_case("FCALL_RO");

    if argv.len() < 3 {
        return Err(CommandError::WrongArity(if is_ro {
            "fcall_ro"
        } else {
            "fcall"
        }));
    }
    // Upstream FCALL/FCALL_RO carry CMD_NOSCRIPT — mirror script.c
    // ordering so scripted calls surface the noscript reply BEFORE
    // any handler-level parsing. The previous code remapped the
    // numkeys parse error via fcall_map_eval_arg_error, masking
    // the canonical noscript wording. (frankenredis-7j2cw)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    let func_name = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;

    // Validate function name contains only safe identifier characters to prevent
    // Lua code injection when constructing the wrapper script.
    if func_name.is_empty()
        || !func_name
            .bytes()
            .all(|b| b.is_ascii_alphanumeric() || b == b'_')
    {
        return Ok(RespFrame::Error("ERR Function not found".to_string()));
    }

    // Look up the function by name
    let (script, has_no_writes) = match store.function_get(func_name) {
        Some((lib, func)) => {
            let no_writes = func
                .flags
                .iter()
                .any(|f| f.eq_ignore_ascii_case("no-writes"));
            (lib.code.clone(), no_writes)
        }
        None => {
            return Ok(RespFrame::Error("ERR Function not found".to_string()));
        }
    };

    if is_ro && !has_no_writes {
        return Ok(RespFrame::Error(
            "ERR Can not execute a script with write flag using *_ro command.".to_string(),
        ));
    }

    // (frankenredis-ascgr) Upstream functions.c::fcallCommandGeneric
    // line 638-641 uses `getLongLongFromObject` (no _OrReply suffix)
    // and emits a bespoke 'Bad number of keys provided' for
    // non-integer numkeys, distinct from EVAL's generic 'value is
    // not an integer' wording. parse_eval_args returns InvalidInteger
    // for that case; remap it to FCALL's specific wording.
    let (_numkeys, keys, args) = parse_eval_args(argv).map_err(fcall_map_eval_arg_error)?;

    // Transform the library code for execution:
    // 1. Strip the #!lua name=... header line (not valid Lua)
    // 2. Convert redis.register_function('name', func) calls into
    //    named function definitions so they can be called directly
    let code_str = String::from_utf8_lossy(&script);
    let mut lua_lines = Vec::new();
    for line in code_str.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with("#!") {
            continue;
        }
        if trimmed.contains("register_function") {
            // Transform: redis.register_function('name', function(k,a) ... end)
            // Into: function name(k,a) ... end
            if let Some(transformed) = transform_register_function(trimmed) {
                lua_lines.push(transformed);
            }
            continue;
        }
        lua_lines.push(line.to_string());
    }
    lua_lines.push(format!("return {func_name}(KEYS, ARGV)"));
    let wrapper_script = lua_lines.join("\n");

    let keys_vec: Vec<Vec<u8>> = keys.to_vec();
    let args_vec: Vec<Vec<u8>> = args.to_vec();
    let previous_read_only = store.script_read_only;
    store.script_read_only = is_ro || has_no_writes;
    store.script_nesting_level += 1;
    let result = match lua_eval::eval_script(
        wrapper_script.as_bytes(),
        &keys_vec,
        &args_vec,
        store,
        now_ms,
    ) {
        Ok(frame) => Ok(frame),
        Err(e) => Ok(RespFrame::Error(format!("ERR Error running function: {e}"))),
    };
    store.script_nesting_level -= 1;
    store.script_read_only = previous_read_only;
    result
}

/// Transform `redis.register_function('name', function(k,a) body end)` into
/// `function name(k,a) body end` so it can be called by name in our Lua evaluator.
fn transform_register_function(line: &str) -> Option<String> {
    // Match: redis.register_function('name', function(...)
    // or:    redis.register_function("name", function(...)
    let after = line
        .find("register_function")
        .map(|i| &line[i + "register_function".len()..])?;
    let after = after.trim_start().strip_prefix('(')?;
    let after = after.trim_start();
    // Extract function name from 'name' or "name"
    let (name, rest) = if let Some(stripped) = after.strip_prefix('\'') {
        let end = stripped.find('\'')?;
        (&stripped[..end], &stripped[end + 1..])
    } else {
        let stripped = after.strip_prefix('"')?;
        let end = stripped.find('"')?;
        (&stripped[..end], &stripped[end + 1..])
    };
    // Skip comma and whitespace to find 'function'
    let rest = rest.trim_start().strip_prefix(',')?;
    let rest = rest.trim_start();
    // Rest should be: function(params) body end)
    // Strip trailing ')' from the register_function call
    let rest = rest.strip_prefix("function")?;
    let rest = rest.trim_end();
    let rest = rest.strip_suffix(')')?;
    Some(format!("function {name}{rest}"))
}

// ── SSUBSCRIBE / SUNSUBSCRIBE / SPUBLISH (shard Pub/Sub) ───────────

fn ssubscribe_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SSUBSCRIBE shardchannel [shardchannel ...]
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SSUBSCRIBE"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    if argv.len() == 2 {
        let count = store.ssubscribe(argv[1].clone()) as i64;
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
            RespFrame::BulkString(Some(argv[1].clone())),
            RespFrame::Integer(count),
        ])));
    }
    let mut replies = Vec::with_capacity(argv.len() - 1);
    for channel in &argv[1..] {
        let count = store.ssubscribe(channel.clone()) as i64;
        replies.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
            RespFrame::BulkString(Some(channel.clone())),
            RespFrame::Integer(count),
        ])));
    }
    Ok(RespFrame::Sequence(replies))
}

fn sunsubscribe_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SUNSUBSCRIBE [shardchannel ...]
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    if argv.len() < 2 {
        // Unsubscribe from all shard channels (sorted for deterministic order)
        let mut channels: Vec<Vec<u8>> = store.subscribed_shard_channels.iter().cloned().collect();
        channels.sort();
        if channels.is_empty() {
            return Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::Integer(0),
            ])));
        }
        let mut replies = Vec::with_capacity(channels.len());
        for channel in channels {
            let count = store.sunsubscribe(&channel) as i64;
            replies.push(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
                RespFrame::BulkString(Some(channel)),
                RespFrame::Integer(count),
            ])));
        }
        return Ok(RespFrame::Sequence(replies));
    }
    if argv.len() == 2 {
        let count = store.sunsubscribe(&argv[1]) as i64;
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
            RespFrame::BulkString(Some(argv[1].clone())),
            RespFrame::Integer(count),
        ])));
    }
    let mut replies = Vec::with_capacity(argv.len() - 1);
    for channel in &argv[1..] {
        let count = store.sunsubscribe(channel) as i64;
        replies.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
            RespFrame::BulkString(Some(channel.clone())),
            RespFrame::Integer(count),
        ])));
    }
    Ok(RespFrame::Sequence(replies))
}

fn spublish_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SPUBLISH shardchannel message
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("SPUBLISH"));
    }
    if store.dispatch_client_ctx.is_pubsub {
        return Err(CommandError::Custom(
            "ERR Can't execute 'spublish': only (P|S)SUBSCRIBE / (P|S)UNSUBSCRIBE / PING / QUIT / RESET are allowed in this context".to_string(),
        ));
    }
    let receivers = store.spublish(&argv[1], &argv[2]);
    Ok(RespFrame::Integer(receivers as i64))
}

fn parse_score_bound(arg: &[u8]) -> Result<ScoreBound, CommandError> {
    // Upstream Redis 7.2 t_zset.c::zslParseRange emits "ERR min or
    // max is not a float" for malformed score bounds in ZRANGEBYSCORE
    // / ZRANGE-BYSCORE / ZCOUNT / ZRANGESTORE-BYSCORE. The generic
    // ValueNotFloat error wording diverges from that. Map to the
    // upstream wording at parse time so every score-range caller
    // benefits. (br-frankenredis-uczv)
    let bad = || CommandError::Custom("ERR min or max is not a float".to_string());
    let text = std::str::from_utf8(arg).map_err(|_| bad())?.trim();
    if text.eq_ignore_ascii_case("-inf") {
        Ok(ScoreBound::Inclusive(f64::NEG_INFINITY))
    } else if text.eq_ignore_ascii_case("+inf") || text.eq_ignore_ascii_case("inf") {
        Ok(ScoreBound::Inclusive(f64::INFINITY))
    } else if let Some(rest) = text.strip_prefix('(') {
        let val = rest.trim().parse::<f64>().map_err(|_| bad())?;
        if val.is_nan() {
            return Err(bad());
        }
        Ok(ScoreBound::Exclusive(val))
    } else {
        let val = text.parse::<f64>().map_err(|_| bad())?;
        if val.is_nan() {
            return Err(bad());
        }
        Ok(ScoreBound::Inclusive(val))
    }
}

fn setex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // SETEX key seconds value
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SETEX"));
    }
    let seconds = parse_expire_time_arg(&argv[2], "setex")?;
    // (br-frankenredis-setexrange) — reject when seconds*1000
    // would overflow LLONG_MAX, matching upstream
    // t_string.c::getExpireMillisecondsOrReply.
    if seconds > i64::MAX as u64 / 1000 {
        return Err(CommandError::Custom(
            "ERR invalid expire time in 'setex' command".to_string(),
        ));
    }
    let px = seconds.saturating_mul(1000);
    store.set(argv[1].clone(), argv[3].clone(), Some(px), now_ms);
    Ok(RespFrame::SimpleString("OK".to_string()))
}

