/// Check if the argument count (including command name) satisfies the command's arity.
/// Returns Ok(()) if valid, Err(command_name) if arity mismatch.
pub fn check_command_arity(name: &[u8], argc: usize) -> Result<(), &'static str> {
    let name_str = match std::str::from_utf8(name) {
        Ok(s) => s,
        Err(_) => return Err(""),
    };
    let Some(&(cmd_name, arity, ..)) = COMMAND_TABLE
        .iter()
        .find(|&&(n, ..)| n.eq_ignore_ascii_case(name_str))
    else {
        return Err(""); // Unknown command — caller handles separately
    };
    let argc = argc as i64;
    if arity > 0 {
        // Exact arity required.
        if argc != arity {
            return Err(cmd_name);
        }
    } else {
        // Minimum arity (abs value).
        if argc < -arity {
            return Err(cmd_name);
        }
    }
    Ok(())
}

/// Return the flags string for a given command name.
#[must_use]
pub fn get_command_flags(name: &[u8]) -> Option<&'static str> {
    let name_str = std::str::from_utf8(name).ok()?;
    COMMAND_TABLE
        .iter()
        .find(|&&(n, ..)| n.eq_ignore_ascii_case(name_str))
        .map(|&(_, _, flags, ..)| flags)
}

fn command_writes_or_may_replicate_in_readonly_script(argv: &[Vec<u8>]) -> bool {
    let Some(raw_cmd) = argv.first() else {
        return false;
    };

    if get_command_flags(raw_cmd)
        .is_some_and(|flags| flags.split_whitespace().any(|flag| flag == "write"))
    {
        return true;
    }

    raw_cmd.eq_ignore_ascii_case(b"PUBLISH") || raw_cmd.eq_ignore_ascii_case(b"SPUBLISH")
}

const ACL_CATEGORIES: &[&str] = &[
    "keyspace",
    "read",
    "write",
    "set",
    "sortedset",
    "list",
    "hash",
    "string",
    "bitmap",
    "hyperloglog",
    "geo",
    "stream",
    "pubsub",
    "admin",
    "fast",
    "slow",
    "blocking",
    "dangerous",
    "connection",
    "transaction",
    "scripting",
    "server",
    "generic",
];

struct AclCategoryMaps {
    by_category: HashMap<&'static str, Vec<&'static str>>,
    by_command: HashMap<&'static str, Vec<&'static str>>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum DispatchAclPermissionError {
    Command,
    Key(Vec<u8>),
    Channel(Vec<u8>),
}

static ACL_CATEGORY_MAPS: OnceLock<AclCategoryMaps> = OnceLock::new();

include!(concat!(env!("OUT_DIR"), "/acl_categories.rs"));

fn acl_category_maps() -> &'static AclCategoryMaps {
    ACL_CATEGORY_MAPS.get_or_init(|| {
        let mut by_category: HashMap<&'static str, Vec<&'static str>> = HashMap::new();
        for &cat in ACL_CATEGORIES {
            by_category.insert(cat, Vec::new());
        }

        let mut by_command: HashMap<&'static str, Vec<&'static str>> = HashMap::new();
        for &(name, categories) in UPSTREAM_ACL_CATEGORY_ENTRIES {
            for &cat in categories {
                if let Some(list) = by_category.get_mut(cat) {
                    list.push(name);
                }
            }
            by_command.insert(name, categories.to_vec());
        }
        for &(name, _arity, flags, _first, _last, _step) in COMMAND_TABLE {
            let categories = by_command.entry(name).or_default();
            merge_command_table_acl_categories(categories, flags);
        }

        AclCategoryMaps {
            by_category,
            by_command,
        }
    })
}

/// Return commands that belong to the given ACL category.
/// Redis maps commands to categories based on data type (string, hash, list, set,
/// sortedset, geo, stream, bitmap, hyperloglog), access type (read, write),
/// and command group (admin, fast, slow, pubsub, scripting, transaction, connection,
/// keyspace, generic, blocking, dangerous, server).
pub fn commands_in_acl_category(category: &str) -> &'static [&'static str] {
    let maps = acl_category_maps();
    if let Some(cmds) = maps.by_category.get(category) {
        return cmds.as_slice();
    }
    let cat_lower = category.to_ascii_lowercase();
    maps.by_category
        .get(cat_lower.as_str())
        .map(|cmds| cmds.as_slice())
        .unwrap_or(&[])
}

/// Return ACL categories for a given command name.
/// Pass lowercase command names to avoid allocations on the hot path.
pub fn command_acl_categories(command: &str) -> &'static [&'static str] {
    let maps = acl_category_maps();
    if let Some(cats) = maps.by_command.get(command) {
        return cats.as_slice();
    }
    let cmd_lower = command.to_ascii_lowercase();
    maps.by_command
        .get(cmd_lower.as_str())
        .map(|cats| cats.as_slice())
        .unwrap_or(&[])
}

/// Return whether an ACL command selector is recognized by Redis metadata.
#[must_use]
pub fn is_known_acl_command_selector(command: &str) -> bool {
    get_command_flags(command.as_bytes()).is_some() || !command_acl_categories(command).is_empty()
}

/// Return ACL selectors for a command invocation, most-specific first.
#[must_use]
pub fn acl_command_selectors_for_argv(argv: &[Vec<u8>]) -> Vec<String> {
    let Some(raw_command) = argv.first() else {
        return Vec::new();
    };
    let command = String::from_utf8_lossy(raw_command).to_ascii_lowercase();
    let mut selectors = Vec::with_capacity(2);

    if let Some(raw_subcommand) = argv.get(1) {
        let subcommand = String::from_utf8_lossy(raw_subcommand).to_ascii_lowercase();
        let subcommand_selector = format!("{command}|{subcommand}");
        if is_known_acl_command_selector(&subcommand_selector) {
            selectors.push(subcommand_selector);
        }
    }

    selectors.push(command);
    selectors
}

fn merge_command_table_acl_categories(categories: &mut Vec<&'static str>, flags: &str) {
    let has_flag = |target: &str| flags.split_whitespace().any(|flag| flag == target);

    if has_flag("fast") {
        categories.retain(|cat| *cat != "slow");
        push_unique_acl_category(categories, "fast");
    } else {
        categories.retain(|cat| *cat != "fast");
        push_unique_acl_category(categories, "slow");
    }

    if has_flag("readonly") && !categories.contains(&"scripting") {
        push_unique_acl_category(categories, "read");
    }
    if has_flag("write") {
        push_unique_acl_category(categories, "write");
    }
    if has_flag("admin") {
        push_unique_acl_category(categories, "admin");
        push_unique_acl_category(categories, "dangerous");
    }
    if has_flag("pubsub") {
        push_unique_acl_category(categories, "pubsub");
    }
    if has_flag("blocking") {
        push_unique_acl_category(categories, "blocking");
    }
}

fn push_unique_acl_category(categories: &mut Vec<&'static str>, category: &'static str) {
    if !categories.contains(&category) {
        categories.push(category);
    }
}

fn dispatch_acl_is_command_allowed(argv: &[Vec<u8>], permissions: &DispatchAclPermissions) -> bool {
    let selectors = acl_command_selectors_for_argv(argv);
    if selectors.is_empty() {
        return false;
    }

    for selector in &selectors {
        if permissions.denied_commands.contains(selector) {
            return false;
        }
    }

    for selector in &selectors {
        if permissions.allowed_commands.contains(selector) {
            return true;
        }
    }

    if permissions.denied_categories.is_empty() && permissions.allowed_categories.is_empty() {
        return permissions.all_commands;
    }

    let cmd_categories = command_acl_categories(&selectors[0]);
    for denied_cat in &permissions.denied_categories {
        if cmd_categories.contains(&denied_cat.as_str()) {
            return false;
        }
    }

    if !permissions.allowed_categories.is_empty() {
        for allowed_cat in &permissions.allowed_categories {
            if cmd_categories.contains(&allowed_cat.as_str()) {
                return true;
            }
        }
    }

    permissions.all_commands
}

fn dispatch_acl_channel_permission_error_for_argv(
    argv: &[Vec<u8>],
    permissions: &DispatchAclPermissions,
) -> Option<Vec<u8>> {
    let command = argv.first()?;

    if command.eq_ignore_ascii_case(b"PUBLISH") || command.eq_ignore_ascii_case(b"SPUBLISH") {
        let channel = argv.get(1)?;
        return (!permissions.all_channels
            && !permissions
                .channel_patterns
                .iter()
                .any(|pattern| glob_match(pattern, channel)))
        .then(|| channel.clone());
    }

    if command.eq_ignore_ascii_case(b"SUBSCRIBE") || command.eq_ignore_ascii_case(b"SSUBSCRIBE") {
        for channel in argv.iter().skip(1) {
            if !permissions.all_channels
                && !permissions
                    .channel_patterns
                    .iter()
                    .any(|pattern| glob_match(pattern, channel))
            {
                return Some(channel.clone());
            }
        }
        return None;
    }

    if command.eq_ignore_ascii_case(b"PSUBSCRIBE") {
        for pattern in argv.iter().skip(1) {
            if !permissions.all_channels
                && !permissions
                    .channel_patterns
                    .iter()
                    .any(|allowed| allowed == pattern)
            {
                return Some(pattern.clone());
            }
        }
    }

    None
}

fn dispatch_acl_permission_error_for_argv(
    argv: &[Vec<u8>],
    permissions: &DispatchAclPermissions,
) -> Option<DispatchAclPermissionError> {
    let cmd = argv.first()?;
    if !dispatch_acl_is_command_allowed(argv, permissions) {
        return Some(DispatchAclPermissionError::Command);
    }
    if check_command_arity(cmd, argv.len()).is_err() {
        return None;
    }
    for key_index in command_key_indexes(argv) {
        if let Some(key) = argv.get(key_index)
            && !permissions.all_keys
            && !permissions
                .key_patterns
                .iter()
                .any(|pattern| glob_match(pattern, key))
        {
            return Some(DispatchAclPermissionError::Key(key.clone()));
        }
    }
    dispatch_acl_channel_permission_error_for_argv(argv, permissions)
        .map(DispatchAclPermissionError::Channel)
}

fn command_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() == 1 {
        // COMMAND with no sub-command: return full command info for all commands
        let entries: Vec<RespFrame> = COMMAND_TABLE
            .iter()
            .map(|&(name, arity, flags, first_key, last_key, step)| {
                command_info_entry(name, arity, flags, first_key, last_key, step)
            })
            .collect();
        return Ok(RespFrame::Array(Some(entries)));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("COUNT") {
        // Upstream commands.def declares COMMAND COUNT with exact
        // arity 2, so trailing args trigger the table-level
        // 'wrong number of arguments for command|count command'
        // wording. (br-frankenredis-commandcount)
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "COMMAND",
                subcommand: sub.to_string(),
            });
        }
        Ok(RespFrame::Integer(COMMAND_TABLE.len() as i64))
    } else if sub.eq_ignore_ascii_case("LIST") {
        // COMMAND LIST [FILTERBY MODULE modname | ACLCAT category | PATTERN pattern]
        // Upstream server.c::commandListCommand requires either
        // exactly 'COMMAND LIST' (argc==2) or
        // 'COMMAND LIST FILTERBY <type> <value>' (argc==5);
        // anything else falls through to addReplyErrorObject(c,
        // shared.syntaxerr). (br-frankenredis-commandlist)
        if argv.len() != 2
            && !(argv.len() >= 4
                && std::str::from_utf8(&argv[2])
                    .ok()
                    .is_some_and(|s| s.eq_ignore_ascii_case("FILTERBY")))
        {
            return Ok(RespFrame::Error("ERR syntax error".to_string()));
        }
        if argv.len() >= 4
            && std::str::from_utf8(&argv[2])
                .ok()
                .is_some_and(|s| s.eq_ignore_ascii_case("FILTERBY"))
        {
            let filter_type =
                std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if filter_type.eq_ignore_ascii_case("MODULE") {
                if argv.len() != 5 {
                    return Ok(RespFrame::Error("ERR syntax error".to_string()));
                }
                // We have no modules — return empty list
                return Ok(RespFrame::Array(Some(Vec::new())));
            } else if filter_type.eq_ignore_ascii_case("ACLCAT") {
                if argv.len() != 5 {
                    return Ok(RespFrame::Error("ERR syntax error".to_string()));
                }
                let category =
                    std::str::from_utf8(&argv[4]).map_err(|_| CommandError::InvalidUtf8Argument)?;
                let cmds = commands_in_acl_category(category);
                let names: Vec<RespFrame> = cmds
                    .iter()
                    .map(|name| RespFrame::BulkString(Some(name.as_bytes().to_vec())))
                    .collect();
                return Ok(RespFrame::Array(Some(names)));
            } else if filter_type.eq_ignore_ascii_case("PATTERN") {
                if argv.len() != 5 {
                    return Ok(RespFrame::Error("ERR syntax error".to_string()));
                }
                let pattern = &argv[4];
                let names: Vec<RespFrame> = COMMAND_TABLE
                    .iter()
                    .filter(|&&(name, ..)| fr_store::glob_match(pattern, name.as_bytes()))
                    .map(|&(name, ..)| RespFrame::BulkString(Some(name.as_bytes().to_vec())))
                    .collect();
                return Ok(RespFrame::Array(Some(names)));
            } else {
                return Ok(RespFrame::Error("ERR syntax error".to_string()));
            }
        }
        let names: Vec<RespFrame> = COMMAND_TABLE
            .iter()
            .map(|&(name, ..)| RespFrame::BulkString(Some(name.as_bytes().to_vec())))
            .collect();
        Ok(RespFrame::Array(Some(names)))
    } else if sub.eq_ignore_ascii_case("INFO") {
        if argv.len() < 3 {
            let entries: Vec<RespFrame> = COMMAND_TABLE
                .iter()
                .map(|&(name, arity, flags, first_key, last_key, step)| {
                    command_info_entry(name, arity, flags, first_key, last_key, step)
                })
                .collect();
            return Ok(RespFrame::Array(Some(entries)));
        }
        let mut entries = Vec::new();
        for arg in &argv[2..] {
            let cmd_name =
                std::str::from_utf8(arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
            let found = COMMAND_TABLE
                .iter()
                .find(|&&(name, ..)| name.eq_ignore_ascii_case(cmd_name));
            match found {
                Some(&(name, arity, flags, first_key, last_key, step)) => {
                    entries.push(command_info_entry(
                        name, arity, flags, first_key, last_key, step,
                    ));
                }
                None => entries.push(RespFrame::BulkString(None)),
            }
        }
        Ok(RespFrame::Array(Some(entries)))
    } else if sub.eq_ignore_ascii_case("DOCS") {
        // Upstream server.c::commandDocsCommand wraps the outer reply
        // and each per-command entry in addReplyMapLen — RESP3 wire
        // shape is a Map of {command_name → command_doc_map};
        // RESP2 stays the flat 2N alternating-element Array. Same
        // shape pattern as i40x2/e4njz/udl3y/asvh1/5d04d/ndz0j/5h86s/
        // cz712/ec2rf. (frankenredis-q11am)
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let docs_pairs: Vec<(RespFrame, RespFrame)> = if argv.len() == 2 {
            COMMAND_TABLE
                .iter()
                .map(|&(name, arity, flags, first_key, last_key, step)| {
                    (
                        RespFrame::BulkString(Some(name.as_bytes().to_vec())),
                        command_docs_entry(name, arity, flags, first_key, last_key, step, resp),
                    )
                })
                .collect()
        } else {
            argv[2..]
                .iter()
                .filter_map(|arg| {
                    let cmd_name = std::str::from_utf8(arg).ok()?;
                    let &(name, arity, flags, first_key, last_key, step) = COMMAND_TABLE
                        .iter()
                        .find(|&&(name, ..)| name.eq_ignore_ascii_case(cmd_name))?;
                    Some((
                        RespFrame::BulkString(Some(name.as_bytes().to_vec())),
                        command_docs_entry(name, arity, flags, first_key, last_key, step, resp),
                    ))
                })
                .collect()
        };
        if resp == 3 {
            Ok(RespFrame::Map(Some(docs_pairs)))
        } else {
            let mut flat = Vec::with_capacity(docs_pairs.len() * 2);
            for (k, v) in docs_pairs {
                flat.push(k);
                flat.push(v);
            }
            Ok(RespFrame::Array(Some(flat)))
        }
    } else if sub.eq_ignore_ascii_case("GETKEYS") {
        // COMMAND GETKEYS <command> [args...]
        if argv.len() < 3 {
            // Upstream's commands.def declares COMMAND|GETKEYS with
            // arity = -3, so the WrongArity reply uses the
            // subcommand-form name. (br-frankenredis-cmdgka)
            return Ok(RespFrame::Error(
                "ERR wrong number of arguments for 'command|getkeys' command".to_string(),
            ));
        }
        match command_key_references(&argv[2..]) {
            Ok(references) => Ok(RespFrame::Array(Some(
                references
                    .into_iter()
                    .map(|key| RespFrame::BulkString(Some(argv[2 + key.index].clone())))
                    .collect(),
            ))),
            Err(err) => Ok(command_key_lookup_error_frame(err)),
        }
    } else if sub.eq_ignore_ascii_case("GETKEYSANDFLAGS") {
        // COMMAND GETKEYSANDFLAGS <command> [args...]
        if argv.len() < 3 {
            // (br-frankenredis-cmdgka)
            return Ok(RespFrame::Error(
                "ERR wrong number of arguments for 'command|getkeysandflags' command".to_string(),
            ));
        }
        match command_key_references(&argv[2..]) {
            Ok(references) => Ok(RespFrame::Array(Some(
                references
                    .into_iter()
                    .map(|key| {
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(argv[2 + key.index].clone())),
                            RespFrame::Array(Some(
                                key.flags
                                    .iter()
                                    .map(|flag| RespFrame::SimpleString((*flag).to_string()))
                                    .collect(),
                            )),
                        ]))
                    })
                    .collect(),
            ))),
            Err(err) => Ok(command_key_lookup_error_frame(err)),
        }
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "COMMAND",
                subcommand: "HELP".to_string(),
            });
        }
        // (frankenredis-vtege) Mirror upstream server.c::commandHelp
        // Command line-for-line + addReplyHelp envelope. Frames are
        // SimpleString (was BulkString — diverged from every other
        // HELP handler in fr that uses hello_simple).
        Ok(RespFrame::Array(Some(vec![
            hello_simple("COMMAND <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("(no subcommand)"),
            hello_simple("    Return details about all Redis commands."),
            hello_simple("COUNT"),
            hello_simple("    Return the total number of commands in this Redis server."),
            hello_simple("LIST"),
            hello_simple("    Return a list of all commands in this Redis server."),
            hello_simple("INFO [<command-name> ...]"),
            hello_simple("    Return details about multiple Redis commands."),
            hello_simple("    If no command names are given, documentation details for all"),
            hello_simple("    commands are returned."),
            hello_simple("DOCS [<command-name> ...]"),
            hello_simple("    Return documentation details about multiple Redis commands."),
            hello_simple("    If no command names are given, documentation details for all"),
            hello_simple("    commands are returned."),
            hello_simple("GETKEYS <full-command>"),
            hello_simple("    Return the keys from a full Redis command."),
            hello_simple("GETKEYSANDFLAGS <full-command>"),
            hello_simple("    Return the keys and the access flags from a full Redis command."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "COMMAND",
            subcommand: sub.to_string(),
        })
    }
}

fn is_command_info_subcommand(name: &str) -> bool {
    name.starts_with("command|")
}

fn command_info_flags(name: &str, flags: &str) -> Vec<RespFrame> {
    let flags = if name == "command" || is_command_info_subcommand(name) {
        "loading stale"
    } else {
        flags
    };
    flags
        .split_whitespace()
        .map(|flag| RespFrame::SimpleString(flag.to_string()))
        .collect()
}

fn command_info_categories(name: &str) -> Vec<RespFrame> {
    if name == "command" || is_command_info_subcommand(name) {
        return vec![hello_simple("@slow"), hello_simple("@connection")];
    }
    command_acl_categories(name)
        .iter()
        .map(|category| RespFrame::SimpleString(format!("@{category}")))
        .collect()
}

fn command_info_tips(name: &str) -> Vec<RespFrame> {
    match name {
        "command" | "command|info" | "command|list" | "command|docs" => {
            vec![hello_bulk("nondeterministic_output_order")]
        }
        _ => Vec::new(),
    }
}

fn command_info_key_specs(
    name: &str,
    flags: &str,
    first_key: i64,
    last_key: i64,
    step: i64,
) -> Vec<RespFrame> {
    if first_key == 0 && last_key == 0 {
        return Vec::new();
    }

    let key_flags: Vec<&str> = if flags.split_whitespace().any(|flag| flag == "readonly") {
        vec!["RO", "access"]
    } else if matches!(
        name,
        "append"
            | "geoadd"
            | "hset"
            | "hmset"
            | "lpush"
            | "lpushx"
            | "mset"
            | "msetnx"
            | "rpush"
            | "rpushx"
            | "sadd"
            | "set"
            | "setnx"
            | "xadd"
            | "zadd"
    ) {
        vec!["RW", "insert"]
    } else {
        vec!["RW", "access"]
    };
    let relative_last_key = if last_key >= first_key {
        last_key - first_key
    } else {
        last_key
    };

    vec![RespFrame::Array(Some(vec![
        hello_bulk("flags"),
        RespFrame::Array(Some(key_flags.into_iter().map(hello_simple).collect())),
        hello_bulk("begin_search"),
        RespFrame::Array(Some(vec![
            hello_bulk("type"),
            hello_bulk("index"),
            hello_bulk("spec"),
            RespFrame::Array(Some(vec![
                hello_bulk("index"),
                RespFrame::Integer(first_key),
            ])),
        ])),
        hello_bulk("find_keys"),
        RespFrame::Array(Some(vec![
            hello_bulk("type"),
            hello_bulk("range"),
            hello_bulk("spec"),
            RespFrame::Array(Some(vec![
                hello_bulk("lastkey"),
                RespFrame::Integer(relative_last_key),
                hello_bulk("keystep"),
                RespFrame::Integer(step),
                hello_bulk("limit"),
                RespFrame::Integer(0),
            ])),
        ])),
    ]))]
}

fn command_info_subcommand_entry(name: &str, arity: i64) -> RespFrame {
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(name.as_bytes().to_vec())),
        RespFrame::Integer(arity),
        RespFrame::Array(Some(command_info_flags(name, ""))),
        RespFrame::Integer(0),
        RespFrame::Integer(0),
        RespFrame::Integer(0),
        RespFrame::Array(Some(command_info_categories(name))),
        RespFrame::Array(Some(command_info_tips(name))),
        RespFrame::Array(Some(Vec::new())),
        RespFrame::Array(Some(Vec::new())),
    ]))
}

fn command_info_subcommands(name: &str) -> Vec<RespFrame> {
    if name != "command" {
        return Vec::new();
    }

    vec![
        command_info_subcommand_entry("command|count", 2),
        command_info_subcommand_entry("command|getkeys", -3),
        command_info_subcommand_entry("command|docs", -2),
        command_info_subcommand_entry("command|getkeysandflags", -3),
        command_info_subcommand_entry("command|list", -2),
        command_info_subcommand_entry("command|help", 2),
        command_info_subcommand_entry("command|info", -2),
    ]
}

/// Build a Redis COMMAND INFO entry.
fn command_info_entry(
    name: &str,
    arity: i64,
    flags: &str,
    first_key: i64,
    last_key: i64,
    step: i64,
) -> RespFrame {
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(name.as_bytes().to_vec())),
        RespFrame::Integer(arity),
        RespFrame::Array(Some(command_info_flags(name, flags))),
        RespFrame::Integer(first_key),
        RespFrame::Integer(last_key),
        RespFrame::Integer(step),
        RespFrame::Array(Some(command_info_categories(name))),
        RespFrame::Array(Some(command_info_tips(name))),
        RespFrame::Array(Some(command_info_key_specs(
            name, flags, first_key, last_key, step,
        ))),
        RespFrame::Array(Some(command_info_subcommands(name))),
    ]))
}

fn command_docs_entry(
    name: &str,
    arity: i64,
    flags: &str,
    first_key: i64,
    last_key: i64,
    step: i64,
    resp_protocol_version: i64,
) -> RespFrame {
    let group = command_group_for_docs(name, flags);
    // Look up upstream metadata harvested at build time from
    // legacy_redis_code/redis/src/commands/*.json. The table is
    // sorted-by-name so binary_search_by is O(log n). Empty strings
    // mean the upstream JSON omitted that field — we mirror the
    // omission rather than fabricating a value. (frankenredis-f39s3)
    let upstream = UPSTREAM_COMMAND_DOCS_META
        .binary_search_by(|(entry_name, _, _, _)| entry_name.cmp(&name))
        .ok()
        .map(|idx| UPSTREAM_COMMAND_DOCS_META[idx]);

    let summary_owned;
    let summary: &str = match upstream {
        Some((_, s, _, _)) if !s.is_empty() => s,
        _ => {
            summary_owned = format!("{} command `{name}`.", command_group_summary_prefix(group));
            &summary_owned
        }
    };

    // Build entries in upstream's field order: summary, since, group,
    // complexity, arguments. Optional fields (since, complexity) are
    // emitted only when the upstream JSON had a value.
    let mut entry: Vec<RespFrame> = Vec::with_capacity(12);
    entry.push(hello_bulk("summary"));
    entry.push(hello_bulk(summary));
    if let Some((_, _, _, since)) = upstream
        && !since.is_empty()
    {
        entry.push(hello_bulk("since"));
        entry.push(hello_bulk(since));
    }
    entry.push(hello_bulk("group"));
    entry.push(hello_bulk(group));
    if let Some((_, _, complexity, _)) = upstream
        && !complexity.is_empty()
    {
        entry.push(hello_bulk("complexity"));
        entry.push(hello_bulk(complexity));
    }
    // History is emitted between complexity and arguments to match
    // upstream t_string.c::commandDocsCommand emission order. Only
    // commands with at least one entry in UPSTREAM_COMMAND_DOCS_HISTORY
    // get the field; the rest skip it. Each entry is a 2-element array
    // [version, message] mirroring the JSON shape. (frankenredis-az2a4)
    if let Ok(idx) =
        UPSTREAM_COMMAND_DOCS_HISTORY.binary_search_by(|(entry_name, _)| entry_name.cmp(&name))
    {
        let history = UPSTREAM_COMMAND_DOCS_HISTORY[idx].1;
        if !history.is_empty() {
            entry.push(hello_bulk("history"));
            let history_frames: Vec<RespFrame> = history
                .iter()
                .map(|(version, message)| {
                    RespFrame::Array(Some(vec![hello_bulk(version), hello_bulk(message)]))
                })
                .collect();
            entry.push(RespFrame::Array(Some(history_frames)));
        }
    }
    entry.push(hello_bulk("arguments"));
    entry.push(RespFrame::Array(Some(command_docs_arguments(
        arity, first_key, last_key, step,
    ))));
    // (frankenredis-q11am) Upstream server.c::commandDocsCommand
    // wraps each per-command entry in addReplyMapLen — RESP3 wire
    // shape is a Map of (key, value) pairs; RESP2 stays the flat
    // alternating Array. Pair up the entry vec when emitting Map.
    if resp_protocol_version == 3 {
        assert!(
            entry.len().is_multiple_of(2),
            "command_docs_entry must produce balanced k/v pairs"
        );
        let mut pairs = Vec::with_capacity(entry.len() / 2);
        let mut iter = entry.into_iter();
        while let (Some(k), Some(v)) = (iter.next(), iter.next()) {
            pairs.push((k, v));
        }
        RespFrame::Map(Some(pairs))
    } else {
        RespFrame::Array(Some(entry))
    }
}

fn command_docs_arguments(arity: i64, first_key: i64, last_key: i64, step: i64) -> Vec<RespFrame> {
    let fixed_arg_count = if arity > 0 { arity - 1 } else { (-arity) - 1 };
    let mut docs = Vec::new();
    for position in 1..=fixed_arg_count {
        let name = if is_key_argument_position(position, fixed_arg_count, first_key, last_key, step)
        {
            if arity < 0 && position == fixed_arg_count && last_key < 0 {
                "key [key ...]".to_string()
            } else {
                "key".to_string()
            }
        } else {
            format!("arg{position}")
        };
        let arg_type = if name.starts_with("key") {
            "key"
        } else {
            "string"
        };
        let mut entry = vec![
            hello_bulk("name"),
            hello_bulk(&name),
            hello_bulk("type"),
            hello_bulk(arg_type),
        ];
        if arity < 0 && position == fixed_arg_count {
            entry.push(hello_bulk("optional"));
            entry.push(RespFrame::Integer(1));
        }
        docs.push(RespFrame::Array(Some(entry)));
    }
    docs
}

fn is_key_argument_position(
    position: i64,
    argc_without_command: i64,
    first_key: i64,
    last_key: i64,
    step: i64,
) -> bool {
    if first_key <= 0 || step <= 0 {
        return false;
    }
    let actual_last = if last_key < 0 {
        argc_without_command + last_key
    } else {
        last_key
    };
    position >= first_key && position <= actual_last && (position - first_key) % step == 0
}

fn command_group_for_docs(name: &str, flags: &str) -> &'static str {
    let flag_list: Vec<&str> = flags.split_whitespace().collect();
    if flag_list.contains(&"pubsub") {
        "pubsub"
    } else if flag_list.contains(&"scripting") {
        "scripting"
    } else if matches!(name, "multi" | "exec" | "discard" | "watch" | "unwatch") {
        "transactions"
    } else if matches!(
        name,
        "auth" | "hello" | "quit" | "reset" | "client" | "echo" | "ping"
    ) {
        "connection"
    } else if matches!(name, "cluster" | "asking" | "readonly" | "readwrite") {
        "cluster"
    } else if matches!(
        name,
        "config"
            | "acl"
            | "save"
            | "bgsave"
            | "bgrewriteaof"
            | "shutdown"
            | "lastsave"
            | "monitor"
            | "slowlog"
            | "debug"
            | "latency"
            | "role"
            | "info"
            | "command"
            | "module"
            | "sentinel"
            | "failover"
            | "replconf"
            | "psync"
            | "sync"
            | "replicaof"
            | "slaveof"
            | "wait"
            | "waitaof"
    ) {
        "server"
    } else if matches!(
        name,
        "expire"
            | "pexpire"
            | "expireat"
            | "pexpireat"
            | "persist"
            | "ttl"
            | "pttl"
            | "expiretime"
            | "pexpiretime"
            | "keys"
            | "randomkey"
            | "scan"
            | "dbsize"
            | "type"
            | "rename"
            | "renamenx"
            | "move"
            | "copy"
            | "dump"
            | "restore"
            | "unlink"
            | "touch"
            | "sort"
            | "sort_ro"
            | "object"
            | "memory"
            | "flushdb"
            | "flushall"
            | "select"
            | "swapdb"
    ) {
        "generic"
    } else if name.starts_with('h') {
        "hash"
    } else if name.starts_with('l')
        || matches!(name, "blpop" | "brpop" | "blmove" | "blmpop" | "brpoplpush")
    {
        "list"
    } else if name.starts_with('s') {
        "set"
    } else if name.starts_with('z') || matches!(name, "bzpopmin" | "bzpopmax" | "bzmpop") {
        "sorted_set"
    } else if name.starts_with('x') {
        "stream"
    } else if name.starts_with("geo") {
        "geo"
    } else if name.starts_with("pf") {
        "hyperloglog"
    } else if name.starts_with("bit") || matches!(name, "setbit" | "getbit") {
        "bitmap"
    } else {
        "string"
    }
}

fn command_group_summary_prefix(group: &str) -> &'static str {
    match group {
        "connection" => "Connection-management",
        "transactions" => "Transaction-control",
        "sorted_set" => "Sorted-set",
        _ => {
            if group.is_empty() {
                "General"
            } else {
                match group {
                    "string" => "String",
                    "generic" => "Generic",
                    "server" => "Server",
                    "hash" => "Hash",
                    "list" => "List",
                    "set" => "Set",
                    "stream" => "Stream",
                    "geo" => "Geo",
                    "bitmap" => "Bitmap",
                    "hyperloglog" => "HyperLogLog",
                    "pubsub" => "Pub/sub",
                    "scripting" => "Scripting",
                    "cluster" => "Cluster",
                    _ => "General",
                }
            }
        }
    }
}

fn command_getkeysandflags_flags(flags: &str) -> &'static [&'static str] {
    let flag_list: Vec<&str> = flags.split_whitespace().collect();
    if flag_list.contains(&"readonly") {
        &["RO", "access"]
    } else if flag_list.contains(&"write") {
        &["RW", "access", "update"]
    } else {
        &["access"]
    }
}

fn config_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("CONFIG"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("GET") {
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        let mut entries = Vec::new();
        for arg in &argv[2..] {
            let raw_pattern =
                std::str::from_utf8(arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
            let pattern = raw_pattern.to_ascii_lowercase();
            config_collect_store_entries(&pattern, store, &mut entries);
        }
        Ok(RespFrame::Array(Some(entries)))
    } else if sub.eq_ignore_ascii_case("SET") {
        if argv.len() < 4 || !argv.len().is_multiple_of(2) {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        config_apply_store_sets(&argv[2..], store)?;
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("RESETSTAT") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        store.reset_info_stats();
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("REWRITE") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Err(CommandError::Custom(
            "ERR The server is running without a config file".to_string(),
        ))
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "HELP".to_string(),
            });
        }
        // (frankenredis-kuthf) Mirror upstream config.c::configHelpCommand
        // (vendored Redis 7.2.4) line-for-line. Frames are SimpleString
        // (was BulkString) and the body uses upstream's single-pattern
        // / single-directive wording (the multi-arg forms are runtime
        // capabilities, not part of the 7.2.4 HELP text).
        Ok(RespFrame::Array(Some(vec![
            hello_simple("CONFIG <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("GET <pattern>"),
            hello_simple(
                "    Return parameters matching the glob-like <pattern> and their values.",
            ),
            hello_simple("SET <directive> <value>"),
            hello_simple("    Set the configuration <directive> to <value>."),
            hello_simple("RESETSTAT"),
            hello_simple("    Reset statistics reported by the INFO command."),
            hello_simple("REWRITE"),
            hello_simple("    Rewrite the configuration file."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "CONFIG",
            subcommand: sub.to_string(),
        })
    }
}

