/// Names of dynamically-managed params that `config_collect_store_entries` handles.
/// We skip these when iterating static defaults to avoid duplicate entries.
const CONFIG_DYNAMIC_PARAM_NAMES: &[&str] = &[
    "hash-max-listpack-entries",
    "hash-max-listpack-value",
    "hash-max-ziplist-entries",
    "hash-max-ziplist-value",
    "list-max-listpack-entries",
    "list-max-listpack-value",
    "list-max-listpack-size",
    "list-max-ziplist-size",
    "set-max-intset-entries",
    "set-max-listpack-entries",
    "zset-max-listpack-entries",
    "zset-max-listpack-value",
    "zset-max-ziplist-entries",
    "zset-max-ziplist-value",
    "lfu-decay-time",
    "maxmemory-policy",
];

/// Collect store-accessible CONFIG parameters matching a glob pattern.
///
/// This provides real CONFIG GET values for parameters stored on `Store` when
/// called via `dispatch_argv` (e.g., from Lua `redis.call("CONFIG", "GET", ...)`).
/// Runtime-level parameters (maxmemory, hz, slowlog, etc.) are only available
/// through the runtime's CONFIG handler.
fn config_collect_store_entries(pattern: &str, store: &Store, entries: &mut Vec<RespFrame>) {
    fn matches(pattern: &str, name: &str) -> bool {
        glob_match(pattern.as_bytes(), name.as_bytes())
    }
    fn push_pair(entries: &mut Vec<RespFrame>, name: &str, value: &str) {
        entries.push(RespFrame::BulkString(Some(name.as_bytes().to_vec())));
        entries.push(RespFrame::BulkString(Some(value.as_bytes().to_vec())));
    }

    let usize_params: &[(&str, usize)] = &[
        ("hash-max-listpack-entries", store.hash_max_listpack_entries),
        ("hash-max-listpack-value", store.hash_max_listpack_value),
        ("list-max-listpack-entries", store.list_max_listpack_entries),
        ("list-max-listpack-value", store.list_max_listpack_value),
        ("set-max-intset-entries", store.set_max_intset_entries),
        ("set-max-listpack-entries", store.set_max_listpack_entries),
        ("zset-max-listpack-entries", store.zset_max_listpack_entries),
        ("zset-max-listpack-value", store.zset_max_listpack_value),
        // Ziplist aliases (same live values)
        ("hash-max-ziplist-entries", store.hash_max_listpack_entries),
        ("hash-max-ziplist-value", store.hash_max_listpack_value),
        ("zset-max-ziplist-entries", store.zset_max_listpack_entries),
        ("zset-max-ziplist-value", store.zset_max_listpack_value),
    ];
    for &(name, value) in usize_params {
        if matches(pattern, name) {
            push_pair(entries, name, &value.to_string());
        }
    }
    if matches(pattern, "list-max-listpack-size") {
        push_pair(
            entries,
            "list-max-listpack-size",
            &store.list_max_listpack_size.to_string(),
        );
    }
    if matches(pattern, "list-max-ziplist-size") {
        push_pair(
            entries,
            "list-max-ziplist-size",
            &store.list_max_listpack_size.to_string(),
        );
    }
    if matches(pattern, "maxmemory-policy") {
        push_pair(
            entries,
            "maxmemory-policy",
            store.maxmemory_policy.as_config_str(),
        );
    }
    if matches(pattern, "lfu-decay-time") {
        push_pair(entries, "lfu-decay-time", &store.lfu_decay_time.to_string());
    }

    // Emit static defaults for params not dynamically managed.
    for &(name, default_value) in CONFIG_STATIC_DEFAULTS {
        if CONFIG_DYNAMIC_PARAM_NAMES.contains(&name) {
            continue;
        }
        if matches(pattern, name) {
            push_pair(entries, name, default_value);
        }
    }
}

/// Apply CONFIG SET for store-accessible parameters.
///
/// Unknown parameters are silently accepted (the runtime handles them).
fn config_apply_store_sets(pairs: &[Vec<u8>], store: &mut Store) -> Result<(), CommandError> {
    let mut i = 0;
    while i + 1 < pairs.len() {
        let name = std::str::from_utf8(&pairs[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let val =
            std::str::from_utf8(&pairs[i + 1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let lower = name.to_ascii_lowercase();

        match lower.as_str() {
            "hash-max-listpack-entries" | "hash-max-ziplist-entries" => {
                store.hash_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "hash-max-listpack-value" | "hash-max-ziplist-value" => {
                store.hash_max_listpack_value = parse_config_usize(lower.as_str(), val)?;
            }
            "list-max-listpack-entries" => {
                store.list_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "list-max-listpack-value" => {
                store.list_max_listpack_value = parse_config_usize(lower.as_str(), val)?;
            }
            "list-max-listpack-size" | "list-max-ziplist-size" => {
                store.list_max_listpack_size = parse_config_i64(lower.as_str(), val)?;
            }
            "set-max-intset-entries" => {
                store.set_max_intset_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "set-max-listpack-entries" => {
                store.set_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "zset-max-listpack-entries" | "zset-max-ziplist-entries" => {
                store.zset_max_listpack_entries = parse_config_usize(lower.as_str(), val)?;
            }
            "zset-max-listpack-value" | "zset-max-ziplist-value" => {
                store.zset_max_listpack_value = parse_config_usize(lower.as_str(), val)?;
            }
            "maxmemory-policy" => {
                store.maxmemory_policy =
                    MaxmemoryPolicy::from_config_str(val).ok_or_else(|| {
                        // Upstream config.c emits the full list of
                        // accepted enum values in the "CONFIG SET
                        // failed (possibly related to argument X) -
                        // argument(s) must be one of the following:
                        // ..." template. (br-frankenredis-2di1)
                        CommandError::Custom(
                            "ERR CONFIG SET failed (possibly related to argument 'maxmemory-policy') - argument(s) must be one of the following: volatile-lru, volatile-lfu, volatile-random, volatile-ttl, allkeys-lru, allkeys-lfu, allkeys-random, noeviction"
                                .to_string(),
                        )
                    })?;
            }
            "lfu-decay-time" => {
                store.lfu_decay_time =
                    u64::try_from(parse_config_usize(lower.as_str(), val)?).unwrap_or(u64::MAX);
            }
            _ => {
                // Unknown params are silently accepted — the runtime layer
                // handles server-level params like maxmemory, hz, slowlog, etc.
            }
        }
        i += 2;
    }
    Ok(())
}

fn parse_config_parse_error(name: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR CONFIG SET failed (possibly related to argument '{name}') - argument couldn't be parsed into an integer"
    ))
}

fn parse_config_range_error(name: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR CONFIG SET failed (possibly related to argument '{name}') - argument must be between 0 and 9223372036854775807 inclusive"
    ))
}

fn parse_config_i64(name: &str, val: &str) -> Result<i64, CommandError> {
    parse_i64_arg(val.as_bytes()).map_err(|_| parse_config_parse_error(name))
}

fn parse_config_usize(name: &str, val: &str) -> Result<usize, CommandError> {
    let parsed = parse_i64_arg(val.as_bytes()).map_err(|_| parse_config_parse_error(name))?;
    if parsed < 0 {
        return Err(parse_config_range_error(name));
    }
    usize::try_from(parsed).map_err(|_| parse_config_range_error(name))
}

fn client_info_line(store: &Store, sub: &str) -> Vec<u8> {
    let ctx = &store.dispatch_client_ctx;
    let name = ctx
        .client_name
        .as_ref()
        .map(|name| String::from_utf8_lossy(name).to_string())
        .unwrap_or_default();
    let user = String::from_utf8_lossy(&ctx.authenticated_user);
    let lib_name = ctx.client_lib_name.as_deref().unwrap_or("");
    let lib_ver = ctx.client_lib_ver.as_deref().unwrap_or("");
    let redir = client_tracking_getredir_value(&ctx.client_tracking);
    // Field order matches upstream Redis 7.2 networking.c::catClientInfoString.
    // See client_info_line_for_session in fr-runtime for the rationale.
    // (br-frankenredis-4upy)
    format!(
        "id={} addr={} laddr=127.0.0.1:{} fd=0 name={} age={} idle={} flags={} db={} sub={} psub={} ssub={} multi={} qbuf=0 qbuf-free=0 argv-mem=0 multi-mem=0 rbs=0 rbp=0 obl=0 oll=0 omem=0 tot-mem=0 events=r cmd=client|{} user={} redir={} resp={} lib-name={} lib-ver={}\r\n",
        ctx.client_id,
        ctx.peer_addr,
        store.server_port,
        name,
        ctx.age_seconds,
        ctx.idle_seconds,
        ctx.flags,
        ctx.db_index,
        ctx.channel_subscriptions,
        ctx.pattern_subscriptions,
        ctx.shard_subscriptions,
        ctx.multi_count,
        sub.to_ascii_lowercase(),
        user,
        redir,
        ctx.resp_protocol_version,
        lib_name,
        lib_ver,
    )
    .into_bytes()
}

fn client_wrong_subcommand_arity(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR wrong number of arguments for 'client|{}' command",
        subcommand.to_ascii_lowercase()
    ))
}

