    #[test]
    fn copy_via_dispatch_supports_cross_db_target() {
        // (frankenredis-op84s) Lua redis.call('COPY', src, dst, 'DB', N)
        // and AOF replay route through dispatch_argv. The earlier
        // copy_cmd hard-coded 'db != 0' as out-of-range so cross-db
        // COPY was impossible on these paths even though the Store
        // engine namespaces keys per-DB via encode_db_key.
        let mut store = Store::new();
        store.set(
            fr_store::encode_db_key(0, b"src"),
            b"payload".to_vec(),
            None,
            0,
        );

        let out = dispatch_argv(
            &[
                b"COPY".to_vec(),
                b"src".to_vec(),
                b"dst".to_vec(),
                b"DB".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("copy with DB option");
        assert_eq!(out, RespFrame::Integer(1));
        // Source still in db 0; destination materialised in db 1.
        assert_eq!(
            store
                .get(&fr_store::encode_db_key(0, b"src"), 0)
                .expect("get src")
                .as_deref(),
            Some(&b"payload"[..])
        );
        assert_eq!(
            store
                .get(&fr_store::encode_db_key(1, b"dst"), 0)
                .expect("get dst")
                .as_deref(),
            Some(&b"payload"[..])
        );
    }

    #[test]
    fn copy_via_dispatch_rejects_out_of_range_db() {
        // (frankenredis-op84s) Range check is now against
        // store.database_count rather than a hard-coded 'db != 0'
        // sentinel. Pin that any db beyond database_count is rejected
        // with the upstream wording and that source data is untouched.
        let mut store = Store::new();
        store.set(
            fr_store::encode_db_key(0, b"src"),
            b"payload".to_vec(),
            None,
            0,
        );

        let err = dispatch_argv(
            &[
                b"COPY".to_vec(),
                b"src".to_vec(),
                b"dst".to_vec(),
                b"DB".to_vec(),
                b"999".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("out-of-range db must error");
        assert!(matches!(
            err,
            CommandError::Custom(ref s) if s == "ERR DB index is out of range"
        ));
        assert!(store.exists(&fr_store::encode_db_key(0, b"src"), 0));
    }

    #[test]
    fn copy_via_dispatch_same_key_cross_db_succeeds() {
        // (frankenredis-op84s) source == destination is only an error
        // when the source AND destination DBs match. Cross-db same-name
        // COPY must succeed (matches upstream cluster.c::copyCommand).
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"foo"), b"v".to_vec(), None, 0);

        let out = dispatch_argv(
            &[
                b"COPY".to_vec(),
                b"foo".to_vec(),
                b"foo".to_vec(),
                b"DB".to_vec(),
                b"2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("cross-db same-name copy");
        assert_eq!(out, RespFrame::Integer(1));
        assert!(store.exists(&fr_store::encode_db_key(0, b"foo"), 0));
        assert!(store.exists(&fr_store::encode_db_key(2, b"foo"), 0));
    }

    #[test]
    fn copy_via_dispatch_same_key_same_db_emits_upstream_error() {
        // (frankenredis-op84s) The source-equals-destination guard must
        // still fire when both DBs match, even with a non-zero DB
        // option. Pins the upstream error wording.
        let mut store = Store::new();
        store.dispatch_client_ctx.db_index = 1;
        store.set(fr_store::encode_db_key(1, b"foo"), b"v".to_vec(), None, 0);

        let out = dispatch_argv(
            &[
                b"COPY".to_vec(),
                b"foo".to_vec(),
                b"foo".to_vec(),
                b"DB".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("dispatch returns Ok-with-error");
        assert_eq!(
            out,
            RespFrame::Error("ERR source and destination objects are the same".to_string())
        );
    }

    #[test]
    fn flushdb_via_dispatch_only_clears_selected_db() {
        // (frankenredis-rdz52) Lua redis.call('FLUSHDB'), AOF replay, and
        // MULTI/EXEC all route FLUSHDB through dispatch_argv. The
        // dispatch context's db_index must scope the wipe so unrelated
        // databases are untouched. Previously fr-command::flushdb called
        // Store::flushdb() (which has FLUSHALL semantics despite the
        // name) and silently destroyed every other database.
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"k0"), b"v0".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(1, b"k1"), b"v1".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(2, b"k2"), b"v2".to_vec(), None, 0);

        store.dispatch_client_ctx.db_index = 1;
        let out = dispatch_argv(&[b"FLUSHDB".to_vec()], &mut store, 0).expect("flushdb db 1");
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));

        // db 1 wiped, db 0 + db 2 untouched.
        assert!(!store.exists(&fr_store::encode_db_key(1, b"k1"), 0));
        assert!(store.exists(&fr_store::encode_db_key(0, b"k0"), 0));
        assert!(store.exists(&fr_store::encode_db_key(2, b"k2"), 0));
    }

    #[test]
    fn flushall_via_dispatch_clears_every_db() {
        // (frankenredis-rdz52) FLUSHALL must wipe every database
        // regardless of the dispatch context's selected db. Companion
        // pin to flushdb_via_dispatch_only_clears_selected_db.
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"k0"), b"v0".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(1, b"k1"), b"v1".to_vec(), None, 0);

        store.dispatch_client_ctx.db_index = 1;
        let out = dispatch_argv(&[b"FLUSHALL".to_vec()], &mut store, 0).expect("flushall");
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));

        assert!(!store.exists(&fr_store::encode_db_key(0, b"k0"), 0));
        assert!(!store.exists(&fr_store::encode_db_key(1, b"k1"), 0));
    }

    #[test]
