    #[test]
    fn expire_option_compatibility_rules_match_redis() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("set");

        let nx_xx = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"5".to_vec(),
                b"NX".to_vec(),
                b"XX".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("nx+xx should fail");
        assert_eq!(
            nx_xx,
            super::CommandError::Custom(
                "ERR NX and XX, GT or LT options at the same time are not compatible".to_string()
            )
        );

        let gt_lt = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"5".to_vec(),
                b"GT".to_vec(),
                b"LT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("gt+lt should fail");
        assert_eq!(
            gt_lt,
            super::CommandError::Custom(
                "ERR GT and LT options at the same time are not compatible".to_string()
            )
        );

        let unknown = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"5".to_vec(),
                b"ZZ".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("unknown option should fail");
        assert_eq!(
            unknown,
            super::CommandError::Custom("ERR Unsupported option ZZ".to_string())
        );

        let xx_gt = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"10".to_vec(),
                b"XX".to_vec(),
                b"GT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xx+gt should be accepted");
        assert_eq!(xx_gt, RespFrame::Integer(0));

        let nx_xx_gt = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"10".to_vec(),
                b"NX".to_vec(),
                b"XX".to_vec(),
                b"GT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("nx cannot combine with xx/gt");
        assert_eq!(
            nx_xx_gt,
            super::CommandError::Custom(
                "ERR NX and XX, GT or LT options at the same time are not compatible".to_string()
            )
        );
    }

    #[test]
    fn expire_option_errors_beat_invalid_integer() {
        // (frankenredis-6uyqo) Upstream expire.c::expireGenericCommand
        // calls parseExtendedExpireArgumentsOrReply BEFORE parsing
        // argv[2] as the time. fr was inverting this — a malformed
        // time-arg surfaced 'value is not an integer or out of range'
        // even when the trailing flags would have produced a more
        // specific error. Pin upstream's precedence on three flavors:
        // unsupported option, NX+XX conflict, GT+LT conflict.
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("set");

        // Unsupported option beats integer parse.
        let err = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"NOTANINT".to_vec(),
                b"BADOPT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("unsupported option should fire first");
        assert_eq!(
            err,
            super::CommandError::Custom("ERR Unsupported option BADOPT".to_string())
        );

        // NX+XX conflict beats integer parse.
        let err = dispatch_argv(
            &[
                b"EXPIRE".to_vec(),
                b"k".to_vec(),
                b"NOTANINT".to_vec(),
                b"NX".to_vec(),
                b"XX".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("NX+XX should fire first");
        assert_eq!(
            err,
            super::CommandError::Custom(
                "ERR NX and XX, GT or LT options at the same time are not compatible".to_string()
            )
        );

        // GT+LT conflict beats integer overflow on AT-form too.
        let err = dispatch_argv(
            &[
                b"EXPIREAT".to_vec(),
                b"k".to_vec(),
                b"99999999999999999999".to_vec(),
                b"GT".to_vec(),
                b"LT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("GT+LT should fire first");
        assert_eq!(
            err,
            super::CommandError::Custom(
                "ERR GT and LT options at the same time are not compatible".to_string()
            )
        );

        // Sanity: with a valid integer + bad option, error is still about the option.
        let err = dispatch_argv(
            &[
                b"PEXPIRE".to_vec(),
                b"k".to_vec(),
                b"5000".to_vec(),
                b"BADOPT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("bad option should still fire");
        assert_eq!(
            err,
            super::CommandError::Custom("ERR Unsupported option BADOPT".to_string())
        );
    }

