    #[test]
    fn hexpire_nx_xx_gt_lt_flag_matrix_matches_upstream_codes() {
        let mut store = seed_hash_field_ttl_store();
        // NX on a field with no TTL → applies.
        let nx_first = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"60".to_vec(),
                b"NX".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hexpire nx first");
        assert_eq!(
            nx_first,
            RespFrame::Array(Some(vec![RespFrame::Integer(1)]))
        );
        // Second NX → blocked.
        let nx_second = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"120".to_vec(),
                b"NX".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hexpire nx second");
        assert_eq!(
            nx_second,
            RespFrame::Array(Some(vec![RespFrame::Integer(0)]))
        );
        // GT shorter → blocked.
        let gt_shorter = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"30".to_vec(),
                b"GT".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hexpire gt shorter");
        assert_eq!(
            gt_shorter,
            RespFrame::Array(Some(vec![RespFrame::Integer(0)]))
        );
        // GT longer → applies.
        let gt_longer = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"600".to_vec(),
                b"GT".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hexpire gt longer");
        assert_eq!(
            gt_longer,
            RespFrame::Array(Some(vec![RespFrame::Integer(1)]))
        );
        // LT shorter → applies.
        let lt_shorter = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"90".to_vec(),
                b"LT".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hexpire lt shorter");
        assert_eq!(
            lt_shorter,
            RespFrame::Array(Some(vec![RespFrame::Integer(1)]))
        );
        // XX on a never-set-again field: seed f2 and attempt XX.
        let xx_blocked = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"60".to_vec(),
                b"XX".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hexpire xx blocked");
        assert_eq!(
            xx_blocked,
            RespFrame::Array(Some(vec![RespFrame::Integer(0)]))
        );
    }

