    #[test]
    fn hexpire_family_wrong_arity_and_syntax() {
        let mut store = seed_hash_field_ttl_store();
        // Missing FIELDS token.
        let missing_fields = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"60".to_vec(),
                b"GARBAGE".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(missing_fields, CommandError::SyntaxError);
        // Numfields mismatch.
        let mismatch = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"60".to_vec(),
                b"FIELDS".to_vec(),
                b"3".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            mismatch,
            CommandError::Custom(
                "ERR Parameter `numFields` is more than number of arguments".to_string()
            )
        );
        // numfields < 1.
        let zero = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"60".to_vec(),
                b"FIELDS".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            zero,
            CommandError::Custom("ERR Parameter `numFields` should be greater than 0".to_string())
        );
        // Negative seconds.
        let negative = dispatch_argv(
            &[
                b"HEXPIRE".to_vec(),
                b"h".to_vec(),
                b"-5".to_vec(),
                b"FIELDS".to_vec(),
                b"1".to_vec(),
                b"f1".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            negative,
            CommandError::Custom("ERR invalid expire time in 'hexpire' command".to_string())
        );
    }

