    #[test]
    fn lmove_command() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"RPUSH".to_vec(),
                b"src".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
                b"c".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("rpush src");
        dispatch_argv(
            &[b"RPUSH".to_vec(), b"dst".to_vec(), b"x".to_vec()],
            &mut store,
            0,
        )
        .expect("rpush dst");

        let out = dispatch_argv(
            &[
                b"LMOVE".to_vec(),
                b"src".to_vec(),
                b"dst".to_vec(),
                b"LEFT".to_vec(),
                b"RIGHT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("lmove left-right");
        assert_eq!(out, RespFrame::BulkString(Some(b"a".to_vec())));

        let out = dispatch_argv(
            &[
                b"LMOVE".to_vec(),
                b"src".to_vec(),
                b"dst".to_vec(),
                b"RIGHT".to_vec(),
                b"LEFT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("lmove right-left");
        assert_eq!(out, RespFrame::BulkString(Some(b"c".to_vec())));

        let out = dispatch_argv(
            &[
                b"LRANGE".to_vec(),
                b"src".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("lrange src");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"b".to_vec()))]))
        );

        let out = dispatch_argv(
            &[
                b"LRANGE".to_vec(),
                b"dst".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("lrange dst");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"c".to_vec())),
                RespFrame::BulkString(Some(b"x".to_vec())),
                RespFrame::BulkString(Some(b"a".to_vec())),
            ]))
        );
    }

