        assert_eq!(out, RespFrame::Integer(2));

        let out = dispatch_argv(
            &[b"SISMEMBER".to_vec(), b"s".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .expect("sismember yes");
