    #[test]
    fn geoadd_geodist_geohash_and_geopos() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
                b"15.087269".to_vec(),
                b"37.502669".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd");
        assert_eq!(out, RespFrame::Integer(2));

        let dist = dispatch_argv(
            &[
                b"GEODIST".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geodist");
        assert_eq!(dist, RespFrame::BulkString(Some(b"166.2742".to_vec())));

        let hashes = dispatch_argv(
            &[
                b"GEOHASH".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
                b"Missing".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geohash");
        assert_eq!(
            hashes,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sqc8b49rnys".to_vec())),
                RespFrame::BulkString(Some(b"sqdtr74hyu0".to_vec())),
                RespFrame::BulkString(None),
            ]))
        );

        let pos = dispatch_argv(
            &[
                b"GEOPOS".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geopos");
        let RespFrame::Array(Some(items)) = pos else {
            panic!("geopos should return array"); // ubs:ignore — AI triage
        };
        assert_eq!(items.len(), 2);
        for item in items {
            let RespFrame::Array(Some(coords)) = item else {
                panic!("geopos entry should be coord array"); // ubs:ignore — AI triage
            };
            assert_eq!(coords.len(), 2);
            let RespFrame::BulkString(Some(longitude_raw)) = &coords[0] else {
                panic!("geopos longitude should be bulk"); // ubs:ignore — AI triage
            };
            let RespFrame::BulkString(Some(latitude_raw)) = &coords[1] else {
                panic!("geopos latitude should be bulk"); // ubs:ignore — AI triage
            };
            let longitude = std::str::from_utf8(longitude_raw)
                .expect("longitude utf8")
                .parse::<f64>()
                .expect("longitude float");
            let latitude = std::str::from_utf8(latitude_raw)
                .expect("latitude utf8")
                .parse::<f64>()
                .expect("latitude float");
            assert!((-180.0..=180.0).contains(&longitude));
            assert!((-85.051_128_78..=85.051_128_78).contains(&latitude));
        }
    }

