    #[test]
    fn xpending_reports_summary_and_detailed_pending_entries() {
        let mut store = Store::new();
        for (id, value) in [("1000-0", "v0"), ("1000-1", "v1"), ("1000-2", "v2")] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"s".to_vec(),
                    id.as_bytes().to_vec(),
                    b"field".to_vec(),
                    value.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("xadd");
        }
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"COUNT".to_vec(),
                b"2".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            10,
        )
        .expect("xreadgroup first");
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            20,
        )
        .expect("xreadgroup replay");
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            30,
        )
        .expect("xreadgroup second consumer");

        let summary = dispatch_argv(
            &[b"XPENDING".to_vec(), b"s".to_vec(), b"g1".to_vec()],
            &mut store,
            40,
        )
        .expect("xpending summary");
        assert_eq!(
            summary,
            RespFrame::Array(Some(vec![
                RespFrame::Integer(3),
                RespFrame::BulkString(Some(b"1000-0".to_vec())),
                RespFrame::BulkString(Some(b"1000-2".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"c1".to_vec())),
                        RespFrame::Integer(2),
                    ])),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"c2".to_vec())),
                        RespFrame::Integer(1),
                    ])),
                ])),
            ]))
        );

        let detail = dispatch_argv(
            &[
                b"XPENDING".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"10".to_vec(),
            ],
            &mut store,
            40,
        )
        .expect("xpending detail");
        assert_eq!(
            detail,
            RespFrame::Array(Some(vec![
                // Pending replay does NOT increment delivery count or update idle time
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(30), // idle since initial delivery at t=10
                    RespFrame::Integer(1),  // delivery count stays at 1
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-1".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(30),
                    RespFrame::Integer(1),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-2".to_vec())),
                    RespFrame::BulkString(Some(b"c2".to_vec())),
                    RespFrame::Integer(10),
                    RespFrame::Integer(1),
                ])),
            ]))
        );

        let filtered = dispatch_argv(
            &[
                b"XPENDING".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"10".to_vec(),
                b"c1".to_vec(),
            ],
            &mut store,
            40,
        )
        .expect("xpending filtered");
        assert_eq!(
            filtered,
            RespFrame::Array(Some(vec![
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(30),
                    RespFrame::Integer(1),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-1".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(30),
                    RespFrame::Integer(1),
                ])),
            ]))
        );
    }

