    #[test]
    fn xgroup_create_and_xinfo_groups_report_created_group() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"field1".to_vec(),
                b"value1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 1");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1001-0".to_vec(),
                b"field2".to_vec(),
                b"value2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 2");

        let create = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"$".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");
        assert_eq!(create, RespFrame::SimpleString("OK".to_string()));

        let groups = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups");
        assert_eq!(
            groups,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"name".to_vec())),
                RespFrame::BulkString(Some(b"g1".to_vec())),
                RespFrame::BulkString(Some(b"consumers".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"pending".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
                RespFrame::BulkString(Some(b"1001-0".to_vec())),
                RespFrame::BulkString(Some(b"entries-read".to_vec())),
                RespFrame::BulkString(None),
                // (frankenredis-9wr6) post-mut9 lag emission: integer
                // gap between group cursor and stream tail. Fresh
                // group on a 1-entry stream with last-delivered-id at
                // the tail → 0.
                RespFrame::BulkString(Some(b"lag".to_vec())),
                RespFrame::Integer(0),
            ]))]))
        );

        let duplicate = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup duplicate");
        assert_eq!(
            duplicate,
            RespFrame::Error("BUSYGROUP Consumer Group name already exists".to_string())
        );

        let stream_info = dispatch_argv(
            &[b"XINFO".to_vec(), b"STREAM".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo stream");
        let RespFrame::Array(Some(items)) = stream_info else {
            panic!("expected array"); // ubs:ignore — AI triage
        };
        let mut groups_count = None;
        let mut idx = 0usize;
        while idx + 1 < items.len() {
            if items[idx] == RespFrame::BulkString(Some(b"groups".to_vec())) {
                groups_count = Some(items[idx + 1].clone());
                break;
            }
            idx += 2;
        }
        assert_eq!(groups_count, Some(RespFrame::Integer(1)));
    }

    #[test]
    fn xgroup_validation_missing_mkstream_wrongtype_and_syntax() {
        let mut store = Store::new();

        let missing = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"missing".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup missing key");
        // Upstream xgroupCommand emits the verbose "requires the key
        // to exist" message rather than the generic "ERR no such
        // key". (br-frankenredis-qcmh)
        assert_eq!(
            missing,
            RespFrame::Error("ERR The XGROUP subcommand requires the key to exist. Note that for CREATE you may want to use the MKSTREAM option to create an empty stream automatically.".to_string())
        );

        let mkstream = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"missing".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
                b"MKSTREAM".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup mkstream create");
        assert_eq!(mkstream, RespFrame::SimpleString("OK".to_string()));

        let groups = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"missing".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups after mkstream");
        assert_eq!(
            groups,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"name".to_vec())),
                RespFrame::BulkString(Some(b"g1".to_vec())),
                RespFrame::BulkString(Some(b"consumers".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"pending".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
                RespFrame::BulkString(Some(b"0-0".to_vec())),
                RespFrame::BulkString(Some(b"entries-read".to_vec())),
                RespFrame::BulkString(None),
                // (frankenredis-9wr6) post-mut9 lag emission. MKSTREAM
                // group on an empty stream is at the tail → 0.
                RespFrame::BulkString(Some(b"lag".to_vec())),
                RespFrame::Integer(0),
            ]))]))
        );

        let invalid_id = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"missing".to_vec(),
                b"g2".to_vec(),
                b"bad-id".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup invalid id");
        assert_eq!(
            invalid_id,
            RespFrame::Error(
                "ERR Invalid stream ID specified as stream command argument".to_string()
            )
        );

        let syntax = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"HELP".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xgroup help with extra args");
        assert!(matches!(
            syntax,
            CommandError::WrongSubcommandArity {
                command: "XGROUP",
                ..
            }
        ));

        let arity = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xgroup arity");
        // XGROUP CREATE has arity -5 in upstream commands.def, so
        // argc<5 emits the table-level 'wrong number of arguments
        // for xgroup|create command' wording. (br-frankenredis-xgrouparity)
        assert_eq!(
            arity,
            CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: "CREATE".to_string(),
            }
        );

        store.set(b"str".to_vec(), b"value".to_vec(), None, 0);
        let wrongtype = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"str".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
                b"MKSTREAM".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xgroup wrongtype");
        assert!(matches!(
            wrongtype,
            CommandError::Store(fr_store::StoreError::WrongType)
        ));
    }

    #[test]
    fn xgroup_destroy_removes_group_and_reports_counts() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        let removed = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"DESTROY".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup destroy");
        assert_eq!(removed, RespFrame::Integer(1));

        let groups = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups");
        assert_eq!(groups, RespFrame::Array(Some(Vec::new())));

        let removed_missing = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"DESTROY".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup destroy missing group");
        assert_eq!(removed_missing, RespFrame::Integer(0));

        let missing_key = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"DESTROY".to_vec(),
                b"missing".to_vec(),
                b"g1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup destroy missing key");
        // Upstream xgroupCommand DESTROY rejects missing keys with the
        // verbose key-required error; matches the rest of the XGROUP
        // family (CREATE/SETID/DELCONSUMER). (frankenredis-n4qd)
        assert_eq!(
            missing_key,
            RespFrame::Error(
                "ERR The XGROUP subcommand requires the key to exist. Note that for CREATE you may want to use the MKSTREAM option to create an empty stream automatically."
                    .to_string()
            )
        );
    }

