    #[test]
    fn memory_subcommands_reject_invalid_syntax() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);

        // (br-frankenredis-marg) — DOCTOR/MALLOC-STATS/PURGE/STATS/
        // HELP with extra args use the subcommand-specific
        // wrong-arity reply. (br-frankenredis-musamp0) — USAGE
        // SAMPLES 0 is accepted; only negative values surface
        // SyntaxError.
        let wrong_arity_cases = [
            (
                vec![b"MEMORY".to_vec(), b"DOCTOR".to_vec(), b"extra".to_vec()],
                "DOCTOR",
            ),
            (
                vec![
                    b"MEMORY".to_vec(),
                    b"MALLOC-STATS".to_vec(),
                    b"extra".to_vec(),
                ],
                "MALLOC-STATS",
            ),
            (
                vec![b"MEMORY".to_vec(), b"PURGE".to_vec(), b"extra".to_vec()],
                "PURGE",
            ),
            (
                vec![b"MEMORY".to_vec(), b"STATS".to_vec(), b"extra".to_vec()],
                "STATS",
            ),
            (
                vec![b"MEMORY".to_vec(), b"HELP".to_vec(), b"extra".to_vec()],
                "HELP",
            ),
        ];
        for (argv, sub) in &wrong_arity_cases {
            let err = dispatch_argv(argv, &mut store, 0).expect_err("memory wrong-arity");
            assert_eq!(
                err,
                CommandError::WrongSubcommandArity {
                    command: "MEMORY",
                    subcommand: sub.to_string(),
                },
                "argv={argv:?}"
            );
        }
        let syntax_cases = [
            vec![
                b"MEMORY".to_vec(),
                b"USAGE".to_vec(),
                b"k".to_vec(),
                b"SAMPLES".to_vec(),
                b"-1".to_vec(),
            ],
            vec![
                b"MEMORY".to_vec(),
                b"USAGE".to_vec(),
                b"k".to_vec(),
                b"BADOPT".to_vec(),
                b"1".to_vec(),
            ],
            vec![
                b"MEMORY".to_vec(),
                b"USAGE".to_vec(),
                b"k".to_vec(),
                b"SAMPLES".to_vec(),
            ],
        ];
        for argv in &syntax_cases {
            let err = dispatch_argv(argv, &mut store, 0).expect_err("memory syntax error");
            assert_eq!(err, CommandError::SyntaxError, "argv={argv:?}");
        }
        // SAMPLES 0 is now accepted (matches upstream).
        let usage_zero = dispatch_argv(
            &[
                b"MEMORY".to_vec(),
                b"USAGE".to_vec(),
                b"k".to_vec(),
                b"SAMPLES".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("memory usage samples 0");
        assert!(matches!(usage_zero, RespFrame::Integer(_)));

        // MEMORY with unknown subcommand returns an error frame (not CommandError)
        let bogus = dispatch_argv(&[b"MEMORY".to_vec(), b"BOGUS".to_vec()], &mut store, 0)
            .expect("memory bogus");
        assert!(matches!(bogus, RespFrame::Error(_)));
    }

    #[test]
    fn memory_stats_under_resp3_returns_map_shape() {
        // (frankenredis-udl3y) Upstream object.c::memoryCommand uses
        // addReplyMapLen, so the RESP3 wire shape is a Map of (key,
        // value) pairs. fr was emitting Array regardless of the
        // dispatch context's protocol version. Same shape pattern
        // as ACL GETUSER (e4njz) and CLIENT TRACKINGINFO (i40x2).
        let mut store = Store::new();
        store.dispatch_client_ctx.resp_protocol_version = 3;
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("memory stats");
        let RespFrame::Map(Some(entries)) = out else {
            panic!("RESP3 MEMORY STATS must be a Map, got {out:?}"); // ubs:ignore — AI triage
        };
        // Pairs are balanced; first three keys are the standard
        // upstream openers.
        assert!(entries.len() >= 20, "expected >= 20 stats entries");
        let keys_first_3: Vec<&RespFrame> = entries.iter().take(3).map(|(k, _)| k).collect();
        assert_eq!(
            keys_first_3[0],
            &RespFrame::BulkString(Some(b"peak.allocated".to_vec()))
        );
        assert_eq!(
            keys_first_3[1],
            &RespFrame::BulkString(Some(b"total.allocated".to_vec()))
        );
        assert_eq!(
            keys_first_3[2],
            &RespFrame::BulkString(Some(b"startup.allocated".to_vec()))
        );
    }

    #[test]
    fn memory_stats_db_sub_map_shape_matches_protocol() {
        // (frankenredis-ndz0j) Upstream object.c:1602 emits per-db
        // sub-maps via addReplyMapLen(c, 3) inside the outer Map.
        // udl3y converted the OUTER level only; the inner db.0
        // value was still a flat 6-element Array under RESP3.
        // Pin both shapes here.
        // (frankenredis-0lsoy) Upstream skips empty dbs — seed a key
        // in db 0 first so the db.0 entry is emitted.
        let mut store = Store::new();
        store.dispatch_client_ctx.resp_protocol_version = 3;
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("set k v");
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("memory stats resp3");
        let RespFrame::Map(Some(entries)) = out else {
            panic!("RESP3 outer must be Map"); // ubs:ignore — AI triage
        };
        let db0 = entries
            .iter()
            .find(|(k, _)| matches!(k, RespFrame::BulkString(Some(b)) if b.as_slice() == b"db.0"))
            .map(|(_, v)| v)
            .expect("db.0 entry present under RESP3");
        let RespFrame::Map(Some(db0_pairs)) = db0 else {
            panic!("RESP3 db.0 value must be Map (was {db0:?})"); // ubs:ignore — AI triage
        };
        assert_eq!(db0_pairs.len(), 3);
        assert_eq!(
            db0_pairs[0].0,
            RespFrame::BulkString(Some(b"overhead.hashtable.main".to_vec()))
        );
        assert_eq!(
            db0_pairs[2].0,
            RespFrame::BulkString(Some(b"overhead.hashtable.slot-to-keys".to_vec()))
        );

        // RESP2 keeps the flat 6-element Array.
        let mut store = Store::new();
        // (frankenredis-0lsoy) Same skip-empty-dbs rule; seed a key.
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("set k v");
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("memory stats resp2");
        let RespFrame::Array(Some(items)) = out else {
            panic!("RESP2 must be flat Array"); // ubs:ignore — AI triage
        };
        // Find db.0 in the flat array — it's followed by the Array
        // value at the next index.
        let db0_idx = items
            .iter()
            .position(|frame| matches!(frame, RespFrame::BulkString(Some(b)) if b.as_slice() == b"db.0"))
            .expect("db.0 key present under RESP2");
        let db0_value = &items[db0_idx + 1];
        let RespFrame::Array(Some(db0_inner)) = db0_value else {
            panic!("RESP2 db.0 value must be Array (was {db0_value:?})"); // ubs:ignore — AI triage
        };
        assert_eq!(db0_inner.len(), 6, "flat 6-element shape under RESP2");
        assert_eq!(
            db0_inner[0],
            RespFrame::BulkString(Some(b"overhead.hashtable.main".to_vec()))
        );
    }

    #[test]
    fn memory_stats_under_resp2_stays_flat_array() {
        // (frankenredis-udl3y) RESP2 stays a flat Array of alternating
        // k/v entries — companion pin to the RESP3 test.
        let mut store = Store::new();
        // Default protocol_version = 2 (Store::new()).
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("memory stats");
        let RespFrame::Array(Some(items)) = out else {
            panic!("RESP2 MEMORY STATS must be a flat Array, got {out:?}"); // ubs:ignore — AI triage
        };
        // Flat shape: every other element is a key.
        assert!(items.len() >= 40);
        assert_eq!(
            items[0],
            RespFrame::BulkString(Some(b"peak.allocated".to_vec()))
        );
        assert_eq!(
            items[2],
            RespFrame::BulkString(Some(b"total.allocated".to_vec()))
        );
    }

