    #[test]
    fn subscribe_family_rejects_scripts_after_arity_validation() {
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let err = dispatch_argv(&[b"SUBSCRIBE".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(err, CommandError::WrongArity("SUBSCRIBE"));

        let err = dispatch_argv(&[b"PSUBSCRIBE".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(err, CommandError::WrongArity("PSUBSCRIBE"));

        let err = dispatch_argv(&[b"SSUBSCRIBE".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(err, CommandError::WrongArity("SSUBSCRIBE"));

        for argv in [
            vec![b"SUBSCRIBE".to_vec(), b"ch1".to_vec()],
            vec![b"SUBSCRIBE".to_vec(), b"ch1".to_vec(), b"ch2".to_vec()],
            vec![b"UNSUBSCRIBE".to_vec()],
            vec![b"UNSUBSCRIBE".to_vec(), b"ch1".to_vec()],
            vec![b"UNSUBSCRIBE".to_vec(), b"ch1".to_vec(), b"ch2".to_vec()],
            vec![b"PSUBSCRIBE".to_vec(), b"news.*".to_vec()],
            vec![
                b"PSUBSCRIBE".to_vec(),
                b"news.*".to_vec(),
                b"events.*".to_vec(),
            ],
            vec![b"PUNSUBSCRIBE".to_vec()],
            vec![b"PUNSUBSCRIBE".to_vec(), b"news.*".to_vec()],
            vec![
                b"PUNSUBSCRIBE".to_vec(),
                b"news.*".to_vec(),
                b"events.*".to_vec(),
            ],
            vec![b"SSUBSCRIBE".to_vec(), b"shard1".to_vec()],
            vec![
                b"SSUBSCRIBE".to_vec(),
                b"shard1".to_vec(),
                b"shard2".to_vec(),
            ],
            vec![b"SUNSUBSCRIBE".to_vec()],
            vec![b"SUNSUBSCRIBE".to_vec(), b"shard1".to_vec()],
            vec![
                b"SUNSUBSCRIBE".to_vec(),
                b"shard1".to_vec(),
                b"shard2".to_vec(),
            ],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()),
                "argv: {argv:?}"
            );
        }
    }

    #[test]
    fn subscribe_multiple_channels() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[
                b"SUBSCRIBE".to_vec(),
                b"ch1".to_vec(),
                b"ch2".to_vec(),
                b"ch3".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("subscribe multi");
        match out {
            RespFrame::Sequence(ref arr) => {
                assert_eq!(arr.len(), 3);
                for (i, item) in arr.iter().enumerate() {
                    match item {
                        RespFrame::Array(Some(sub)) => {
                            assert_eq!(sub.len(), 3);
                            assert_eq!(sub[2], RespFrame::Integer((i + 1) as i64));
                        }
                        other => panic!("expected array, got {other:?}"), // ubs:ignore — AI triage
                    }
                }
            }
            other => panic!("expected RESP sequence, got {other:?}"), // ubs:ignore — AI triage
        }
        assert_eq!(
            out.to_bytes(),
            b"*3\r\n$9\r\nsubscribe\r\n$3\r\nch1\r\n:1\r\n*3\r\n$9\r\nsubscribe\r\n$3\r\nch2\r\n:2\r\n*3\r\n$9\r\nsubscribe\r\n$3\r\nch3\r\n:3\r\n"
                .to_vec()
        );
    }

    #[test]
    fn publish_to_direct_subscriber() {
        let mut store = Store::new();
        store.subscribe(b"news".to_vec());
        let out = dispatch_argv(
            &[b"PUBLISH".to_vec(), b"news".to_vec(), b"hello".to_vec()],
            &mut store,
            0,
        )
        .expect("publish");
        assert_eq!(out, RespFrame::Integer(1));
        // Check pending messages
        let pending = store.drain_pending_pubsub();
        assert_eq!(pending.len(), 1);
        assert_eq!(
            pending[0],
            fr_store::PubSubMessage::Message {
                channel: b"news".to_vec(),
                data: b"hello".to_vec(),
            }
        );
    }

