    /// Lock the text corpus used by `fuzz_command_option_parsers`.
    ///
    /// Seeds start with `FR_OPTION_SEED` and then contain one
    /// `ACCEPT|...` or `REJECT|...` command per line. The fuzz
    /// target has a fast path for this format so these human-readable
    /// seeds exercise deep option-parser branches immediately before
    /// libFuzzer mutates into the arbitrary structured path.
    #[test]
    fn fuzz_command_option_parsers_corpus_matches_documented_contract() -> Result<(), String> {
        use std::collections::BTreeSet;
        use std::path::Path;

        let corpus_root = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../../fuzz/corpus/fuzz_command_option_parsers");
        if !corpus_root.exists() {
            return Ok(());
        }

        fn read_seed(corpus_root: &Path, name: &str, expected: &str) -> Vec<Vec<u8>> {
            let body = std::fs::read_to_string(corpus_root.join(name))
                .unwrap_or_else(|err| panic!("read seed {name}: {err}"));
            let mut lines = body.lines();
            assert_eq!(
                lines.next(),
                Some("FR_OPTION_SEED"),
                "seed {name} must start with the text corpus header"
            );
            for line in lines {
                let line = line.trim();
                if line.is_empty() || line.starts_with('#') {
                    continue;
                }
                let (kind, argv_text) = line
                    .split_once('|')
                    .unwrap_or_else(|| panic!("seed {name} must contain KIND|argv"));
                assert_eq!(kind, expected, "seed {name} has wrong expectation kind");
                return argv_text
                    .split_ascii_whitespace()
                    .map(|token| token.as_bytes().to_vec())
                    .collect();
            }
            panic!("seed {name} must contain one command line")
        }

        fn seeded_option_store(now_ms: u64) -> Store {
            let mut store = Store::new();
            store.set(b"scan:str".to_vec(), b"v".to_vec(), None, now_ms);
            let _ = store.hset(b"h", b"field1".to_vec(), b"value1".to_vec(), now_ms);
            let _ = store.hset(b"h", b"field2".to_vec(), b"value2".to_vec(), now_ms);
            let _ = store.lpush(b"scan:list", &[b"item".to_vec()], now_ms);
            let _ = store.zadd(
                b"zset",
                &[
                    (1.0, b"alpha".to_vec()),
                    (2.0, b"beta".to_vec()),
                    (3.0, b"gamma".to_vec()),
                    (4.0, b"delta".to_vec()),
                ],
                now_ms,
            );
            let _ = store.zadd(
                b"zs1",
                &[(1.0, b"a".to_vec()), (3.0, b"c".to_vec())],
                now_ms,
            );
            let _ = store.zadd(
                b"zs2",
                &[(2.0, b"b".to_vec()), (4.0, b"c".to_vec())],
                now_ms,
            );
            let _ = store.xadd(b"s", (1, 0), &[(b"f".to_vec(), b"1".to_vec())], now_ms);
            let _ = store.xadd(b"s", (2, 0), &[(b"f".to_vec(), b"2".to_vec())], now_ms);
            let _ = store.xgroup_create(b"s", b"g", (0, 0), false, now_ms);
            let geo_seed = vec![
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"palermo".to_vec(),
                b"15.087269".to_vec(),
                b"37.502669".to_vec(),
                b"catania".to_vec(),
            ];
            let _ = dispatch_argv(&geo_seed, &mut store, now_ms);
            let _ = store.lpush(b"source", &[b"payload".to_vec()], now_ms);
            store
        }

        fn is_rejection_for_seed(result: &Result<RespFrame, CommandError>) -> bool {
            matches!(result, Err(_) | Ok(RespFrame::Error(_)))
        }

        let accepts: &[&str] = &[
            "zrange_withscores_limit.seed",
            "zrange_limit_then_withscores.seed",
            "geo_count_any_withcoord.seed",
            "geo_desc_withdist_hash.seed",
            "xread_bare_ms.seed",
            "xrange_bare_bounds.seed",
            "xgroup_setid_explicit.seed",
            "zunionstore_weights_aggregate.seed",
            "scan_match_count_type.seed",
            "hscan_match_count.seed",
            "eval_no_keys.seed",
            "eval_two_keys.seed",
            "brpoplpush_decimal_timeout.seed",
        ];
        assert!(
            accepts.len() >= 10,
            "command option parser corpus must include >= 10 accept seeds"
        );
        let mut now_ms = 1_u64;
        for name in accepts {
            let argv = read_seed(&corpus_root, name, "ACCEPT");
            let mut store = seeded_option_store(now_ms);
            let result = dispatch_argv(&argv, &mut store, now_ms);
            assert!(
                !is_rejection_for_seed(&result),
                "seed {name} must accept: argv={argv:?}, result={result:?}"
            );
            now_ms = now_ms.saturating_add(7);
        }

        let rejects: &[&str] = &[
            "zrange_missing_limit_count.seed",
            "geo_count_zero.seed",
            "geo_missing_count_value.seed",
            "xread_invalid_id.seed",
            "xgroup_setid_invalid.seed",
            "zunionstore_missing_weight.seed",
            "zunionstore_invalid_aggregate.seed",
            "scan_missing_match.seed",
            "hscan_zero_count.seed",
            "eval_negative_numkeys.seed",
            "brpoplpush_nan_timeout.seed",
        ];
        for name in rejects {
            let argv = read_seed(&corpus_root, name, "REJECT");
            let mut store = seeded_option_store(now_ms);
            let before = store.state_digest();
            let result = dispatch_argv(&argv, &mut store, now_ms);
            assert!(
                is_rejection_for_seed(&result),
                "seed {name} must reject: argv={argv:?}, result={result:?}"
            );
            assert_eq!(
                before,
                store.state_digest(),
                "reject seed {name} must not mutate store"
            );
            now_ms = now_ms.saturating_add(7);
        }

        let listed: BTreeSet<&str> = accepts.iter().chain(rejects.iter()).copied().collect();
        for entry in std::fs::read_dir(&corpus_root)
            .map_err(|err| format!("read fuzz_command_option_parsers corpus: {err}"))?
        {
            let entry =
                entry.map_err(|err| format!("read fuzz_command_option_parsers entry: {err}"))?;
            if !entry
                .file_type()
                .map_err(|err| format!("read seed file type: {err}"))?
                .is_file()
            {
                continue;
            }
            let name = entry.file_name().into_string().map_err(|name| {
                format!("fuzz_command_option_parsers seed filename is not UTF-8: {name:?}")
            })?;
            assert!(
                listed.contains(name.as_str()),
                "seed {name} must be listed as accept or reject"
            );
        }

        Ok(())
    }

    #[test]
    fn eval_executes_lua() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[b"EVAL".to_vec(), b"return 1".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect("eval");
        assert_eq!(out, RespFrame::Integer(1));
    }

    /// Lock the contract for the structured corpus seeds in
    /// `fuzz/corpus/fuzz_lua_eval/`. The fuzz target dispatches the
    /// first byte two ways (`mode % 2`):
    ///
    ///   0 → fuzz_raw_lua (body fed to eval_script)
    ///   1 → fuzz_structured_lua (arbitrary)
    ///
    /// The seed generator `fuzz/scripts/gen_lua_eval_seeds.py`
    /// writes mode-byte = 0x00 seeds covering each meaningful Lua
    /// path the harness exercises. Verifies:
    ///
    ///   1. Every seed exercises `eval_script` without panicking.
    ///   2. Representative deterministic seeds produce the exact
    ///      expected `RespFrame` so the corpus locks the eval
    ///      result.
    ///
    /// Lock the contract for the structured corpus seeds in
    /// `fuzz/corpus/fuzz_migrate_request/`. The fuzz target's
    /// `raw_argv` pre-pends `MIGRATE` to the seed body, then
    /// splits on `\\n`/`\\r`/`\\0` into argv tokens. The
    /// accept-class invariant is canonical round-trip:
    /// parse → canonical-render → reparse → same struct.
    ///
    /// The seed generator
    /// (`fuzz/scripts/gen_migrate_request_seeds.py`) covers each
    /// MIGRATE option combination + every documented rejection
    /// branch. This test locks: every corpus file is classified;
    /// every accept seed parses; every reject seed surfaces an Err;
    /// specific reject cases hit the canonical wording.
    #[test]
    fn fuzz_migrate_request_corpus_matches_documented_contract() -> Result<(), String> {
        use crate::parse_migrate_request;
        use std::path::Path;

        let corpus_root =
            Path::new(env!("CARGO_MANIFEST_DIR")).join("../../fuzz/corpus/fuzz_migrate_request");
        if !corpus_root.exists() {
            return Ok(());
        }

        // The harness's raw_argv splits on \n / \r / 0 WITHOUT
        // filtering empties (the empty key arg in KEYS mode
        // depends on this). Strip a single trailing empty segment
        // (from the seed's trailing newline) so seeds remain
        // human-readable text files.
        fn argv_from(body: &[u8]) -> Vec<Vec<u8>> {
            let mut argv = vec![b"MIGRATE".to_vec()];
            let mut segments: Vec<&[u8]> = body
                .split(|byte| matches!(*byte, b'\n' | b'\r' | 0))
                .collect();
            if let Some(last) = segments.last()
                && last.is_empty()
            {
                segments.pop();
            }
            for segment in segments {
                argv.push(segment.to_vec());
            }
            argv
        }

        fn read_argv(corpus_root: &Path, name: &str) -> Vec<Vec<u8>> {
            let bytes = std::fs::read(corpus_root.join(name))
                .unwrap_or_else(|err| panic!("read seed {name}: {err}"));
            argv_from(&bytes)
        }

        let accepts: &[&str] = &[
            "minimal_no_options",
            "with_copy",
            "with_replace",
            "with_copy_and_replace",
            "with_auth",
            "with_auth2",
            "with_auth_and_replace",
            "with_auth2_and_copy",
            "keys_mode_two_keys",
            "keys_mode_single_key",
            "keys_mode_with_auth",
            "keys_mode_with_auth2_and_replace",
            "ipv4_host",
            "ipv6_loopback_host",
            "hostname_with_dots",
            "db_index_max",
            "negative_timeout_clamps",
            "zero_timeout_clamps",
            "large_timeout",
            "auth_password_with_special_chars",
            "keys_mode_long_list",
            "auth2_replace.txt",
            "basic_keys_mode.txt",
            // The trailing token after KEYS is NOT an option; it
            // becomes another key (KEYS consumes everything left).
            "unknown_option_after_keys",
            // Port is intentionally NOT validated at parse time —
            // upstream Redis migrateCommand skips port validation
            // when the key is missing (returns NOKEY first), so
            // parse_migrate_request preserves the raw `port_arg`
            // bytes and validation is deferred to dispatch. See
            // `migrate_missing_key_skips_port_validation_like_redis`.
            "invalid_port",
        ];
        assert!(
            accepts.len() >= 14,
            "fuzz_migrate_request accept seeds must have >= 14 entries"
        );
        for name in accepts {
            let argv = read_argv(&corpus_root, name);
            parse_migrate_request(&argv)
                .unwrap_or_else(|err| panic!("seed {name} must parse: {err:?}"));
        }

        // Pinned semantic checks for representative seeds.

        // negative_timeout_clamps: timeout_ms <= 0 must clamp to
        // 1000ms per Redis spec (timeout 0 means default 1s).
        let argv = read_argv(&corpus_root, "negative_timeout_clamps");
        let request = parse_migrate_request(&argv).unwrap();
        assert_eq!(
            request.timeout,
            std::time::Duration::from_millis(1000),
            "negative timeout must clamp to 1000ms"
        );
        let argv = read_argv(&corpus_root, "zero_timeout_clamps");
        let request = parse_migrate_request(&argv).unwrap();
        assert_eq!(
            request.timeout,
            std::time::Duration::from_millis(1000),
            "zero timeout must clamp to 1000ms"
        );

        // KEYS mode collects the trailing keys.
        let argv = read_argv(&corpus_root, "keys_mode_two_keys");
        let request = parse_migrate_request(&argv).unwrap();
        assert_eq!(request.keys, vec![b"k1".to_vec(), b"k2".to_vec()]);

        // AUTH2 captures both username and password.
        let argv = read_argv(&corpus_root, "with_auth2");
        let request = parse_migrate_request(&argv).unwrap();
        assert_eq!(request.auth_username, Some(b"user".to_vec()));
        assert_eq!(request.auth_password, Some(b"password".to_vec()));

        // COPY + REPLACE flags pass through.
        let argv = read_argv(&corpus_root, "with_copy_and_replace");
        let request = parse_migrate_request(&argv).unwrap();
        assert!(request.copy);
        assert!(request.replace);

        // Reject-class.
        let rejects: &[&str] = &[
            "too_few_args",
            "invalid_db_index",
            "invalid_timeout",
            "auth_missing_password",
            "auth2_missing_username_and_password",
            "auth2_missing_password",
            "keys_with_non_empty_key_arg",
            "unknown_option",
            "missing_auth2_password.txt",
            // unknown_option_after_keys is intentionally NOT a
            // reject: once KEYS is hit, the parser consumes all
            // remaining argv as keys (matches upstream Redis
            // semantics), so trailing tokens are interpreted as
            // additional key names rather than option tokens.
        ];
        for name in rejects {
            let argv = read_argv(&corpus_root, name);
            assert!(
                parse_migrate_request(&argv).is_err(),
                "seed {name} must reject (got Ok)"
            );
        }

        let listed_seeds: std::collections::BTreeSet<&str> =
            accepts.iter().chain(rejects.iter()).copied().collect();
        for entry in std::fs::read_dir(&corpus_root)
            .map_err(|err| format!("read fuzz_migrate_request corpus: {err}"))?
        {
            let entry = entry.map_err(|err| format!("read fuzz_migrate_request entry: {err}"))?;
            if !entry
                .file_type()
                .map_err(|err| format!("read fuzz_migrate_request seed file type: {err}"))?
                .is_file()
            {
                continue;
            }
            let name = entry.file_name().into_string().map_err(|name| {
                format!("fuzz_migrate_request seed filename is not UTF-8: {name:?}")
            })?;
            assert!(
                listed_seeds.contains(name.as_str()),
                "fuzz_migrate_request seed {name} must be listed as accept or reject"
            );
        }

        // KEYS with a non-empty key arg must surface the canonical
        // upstream wording.
        let argv = read_argv(&corpus_root, "keys_with_non_empty_key_arg");
        let err = parse_migrate_request(&argv).expect_err("KEYS with non-empty key must reject");
        let detail = format!("{err:?}");
        assert!(
            detail.contains("KEYS") && detail.contains("empty"),
            "KEYS-non-empty-key-arg wording must mention KEYS+empty: {detail}"
        );
        Ok(())
    }

    /// Lock the contract for the structured corpus seeds in
    /// `fuzz/corpus/fuzz_client_tracking/`. The fuzz target parses
    /// each input via `argv_from_raw` (whitespace-split tokens)
    /// and feeds the argv through `parse_client_tracking_state`.
    /// The accept-class invariant is canonical round-trip: parse →
    /// canonical-render → reparse must produce the same state.
    ///
    /// The seed generator
    /// (`fuzz/scripts/gen_client_tracking_seeds.py`) covers each
    /// CLIENT TRACKING option combination + each documented
    /// rejection branch.
    #[test]
    fn fuzz_client_tracking_corpus_matches_documented_contract() {
        use crate::parse_client_tracking_state;
        use std::path::Path;

        let corpus_root =
            Path::new(env!("CARGO_MANIFEST_DIR")).join("../../fuzz/corpus/fuzz_client_tracking");
        if !corpus_root.exists() {
            return;
        }

        // Mirror argv_from_raw: split on whitespace + NUL into
        // tokens, no quoting.
        fn argv_from(body: &[u8]) -> Vec<Vec<u8>> {
            let mut argv = Vec::new();
            let mut current: Vec<u8> = Vec::new();
            for &byte in body {
                if byte == 0 || byte.is_ascii_whitespace() {
                    if !current.is_empty() {
                        argv.push(std::mem::take(&mut current));
                    }
                } else {
                    current.push(byte);
                }
            }
            if !current.is_empty() {
                argv.push(current);
            }
            argv
        }

        fn read_argv(corpus_root: &Path, name: &str) -> Vec<Vec<u8>> {
            let bytes = std::fs::read(corpus_root.join(name))
                .unwrap_or_else(|err| panic!("read seed {name}: {err}"));
            argv_from(&bytes)
        }

        // Accept-class: every seed must parse cleanly.
        let accepts: &[&str] = &[
            "tracking_off.txt",
            "tracking_on_plain.txt",
            "tracking_on_bcast.txt",
            "tracking_on_optin.txt",
            "tracking_on_optout.txt",
            "tracking_on_noloop.txt",
            "tracking_on_bcast_one_prefix.txt",
            "tracking_on_bcast_two_prefixes.txt",
            "tracking_on_bcast_three_prefixes.txt",
            "tracking_on_bcast_noloop.txt",
            "tracking_on_optin_noloop.txt",
            "tracking_on_optout_noloop.txt",
            "tracking_on_redirect.txt",
            "tracking_on_redirect_bcast_prefix.txt",
            "tracking_on_redirect_optin_noloop.txt",
            "tracking_lowercase.txt",
            "tracking_mixed_case.txt",
            "tracking_uppercase_prefix_value.txt",
            "tracking_on_bcast_prefix_with_colon.txt",
            "tracking_on_bcast_empty_prefix.txt",
        ];
        assert!(
            accepts.len() >= 14,
            "fuzz_client_tracking accept seeds must have >= 14 entries"
        );
        for name in accepts {
            let argv = read_argv(&corpus_root, name);
            parse_client_tracking_state(&argv)
                .unwrap_or_else(|err| panic!("seed {name} must parse: {err:?}"));
        }

        let quoted_empty_prefix = read_argv(&corpus_root, "tracking_on_bcast_empty_prefix.txt");
        let state = parse_client_tracking_state(&quoted_empty_prefix)
            .expect("quoted empty-prefix seed must parse");
        assert!(
            state.prefixes.contains(b"\"\"".as_slice()),
            "raw corpus seed uses literal quote bytes because argv_from_raw has no quoting"
        );

        let state = parse_client_tracking_state(&[
            b"CLIENT".to_vec(),
            b"TRACKING".to_vec(),
            b"ON".to_vec(),
            b"BCAST".to_vec(),
            b"PREFIX".to_vec(),
            Vec::new(),
        ])
        .expect("real empty PREFIX argv must parse");
        assert!(
            state.prefixes.contains(&Vec::<u8>::new()),
            "explicit argv path must lock true empty-prefix semantics"
        );

        // Reject-class: each must surface an error.
        let rejects: &[&str] = &[
            "tracking_no_mode_arg.txt",
            "tracking_on_bcast_optin_conflict.txt",
            "tracking_on_bcast_optout_conflict.txt",
            "tracking_on_optin_optout_conflict.txt",
            "tracking_on_prefix_without_bcast.txt",
            "tracking_on_redirect_missing_arg.txt",
            "tracking_on_redirect_zero.txt",
            "tracking_on_prefix_missing_arg.txt",
            "tracking_bogus_mode.txt",
            "tracking_on_redirect_negative_id.txt",
            "tracking_on_redirect_nonnumeric.txt",
        ];
        for name in rejects {
            let argv = read_argv(&corpus_root, name);
            assert!(
                parse_client_tracking_state(&argv).is_err(),
                "seed {name} must reject (got Ok)"
            );
        }

        // Specific reject-wording pins for the documented branches.
        let bcast_optin_argv = read_argv(&corpus_root, "tracking_on_bcast_optin_conflict.txt");
        let err = parse_client_tracking_state(&bcast_optin_argv)
            .expect_err("BCAST+OPTIN conflict must reject");
        assert!(
            format!("{err:?}").contains("BCAST"),
            "BCAST+OPTIN error wording must mention BCAST: {err:?}"
        );

        let prefix_no_bcast = read_argv(&corpus_root, "tracking_on_prefix_without_bcast.txt");
        let err = parse_client_tracking_state(&prefix_no_bcast)
            .expect_err("PREFIX-without-BCAST must reject");
        assert!(
            format!("{err:?}").contains("PREFIX"),
            "PREFIX-without-BCAST wording must mention PREFIX: {err:?}"
        );
    }

    /// Lock the contract for the structured corpus seeds in
    /// `fuzz/corpus/fuzz_client_reply/`. The fuzz target parses
    /// each input as newline-separated argv and feeds every
    /// command through `apply_client_reply_state`, asserting the
    /// real impl matches the harness's shadow model.
    ///
    /// The seed generator (`fuzz/scripts/gen_client_reply_seeds.py`)
    /// covers each CLIENT REPLY transition + interaction with
    /// non-CLIENT-REPLY commands. This test pins:
    ///
    ///   1. Every accept seed runs through the parser without
    ///      returning Err (the per-command result is `Ok(())`
    ///      regardless of the post-state shape).
    ///   2. Pinned representative seeds drive the documented
    ///      state transitions: ON → off=false; OFF → off=true,
    ///      suppress=true; SKIP → skip_next=true, suppress=true;
    ///      a non-CLIENT-REPLY command after OFF stays suppressed
    ///      until the next ON.
    ///   3. Reject seeds (wrong arity, invalid mode token) surface
    ///      a CommandError without panicking.
    #[test]
    fn fuzz_client_reply_corpus_matches_documented_contract() {
        use crate::apply_client_reply_state;
        use fr_store::ClientReplyState;
        use std::path::Path;

        let corpus_root =
            Path::new(env!("CARGO_MANIFEST_DIR")).join("../../fuzz/corpus/fuzz_client_reply");
        if !corpus_root.exists() {
            return;
        }

        // Mirror the harness's commands_from_raw parser: split on
        // \n and \0 into commands; whitespace-separated argv per
        // command. Empty argv lines are skipped.
        fn parse_commands(body: &[u8]) -> Vec<Vec<Vec<u8>>> {
            let mut commands = Vec::new();
            let mut current_command: Vec<Vec<u8>> = Vec::new();
            let mut current_arg: Vec<u8> = Vec::new();
            let flush_arg = |cmd: &mut Vec<Vec<u8>>, arg: &mut Vec<u8>| {
                if !arg.is_empty() {
                    cmd.push(std::mem::take(arg));
                }
            };
            let flush_command = |cmds: &mut Vec<Vec<Vec<u8>>>, cmd: &mut Vec<Vec<u8>>| {
                if !cmd.is_empty() {
                    cmds.push(std::mem::take(cmd));
                }
            };
            for &byte in body {
                if byte == b'\n' || byte == 0 {
                    flush_arg(&mut current_command, &mut current_arg);
                    flush_command(&mut commands, &mut current_command);
                } else if byte.is_ascii_whitespace() {
                    flush_arg(&mut current_command, &mut current_arg);
                } else {
                    current_arg.push(byte);
                }
            }
            flush_arg(&mut current_command, &mut current_arg);
            flush_command(&mut commands, &mut current_command);
            commands
        }

        fn read_seed(corpus_root: &Path, name: &str) -> Vec<u8> {
            std::fs::read(corpus_root.join(name))
                .unwrap_or_else(|err| panic!("read seed {name}: {err}"))
        }

        // Accept-class: every command in every seed must return
        // Ok(()). State drift is checked by the fuzz target itself
        // against the shadow model; here we just lock the no-error
        // property on real ground truth.
        let accepts: &[&str] = &[
            "empty.txt",
            "whitespace_only.txt",
            "reply_on_alone.txt",
            "reply_off_alone.txt",
            "reply_skip_alone.txt",
            "on_off_on_cycle.txt",
            "off_then_command.txt",
            "skip_then_one_command.txt",
            "skip_then_two_commands.txt",
            "off_command_then_on.txt",
            "lowercase_subcommand.txt",
            "mixed_case_subcommand.txt",
            "uppercase_value.txt",
            "mixed_case_value.txt",
            "multiple_skips_only_one_persists.txt",
            "client_other_subcommand_mixed.txt",
            "echo_hello_alone.txt",
            "ping_alone.txt",
            "ping_then_echo.txt",
            "long_alternating_off_on.txt",
            "many_skips_with_intervening_commands.txt",
            "nul_separator_in_stream.txt",
        ];
        assert!(
            accepts.len() >= 14,
            "fuzz_client_reply accept seeds must have >= 14 entries"
        );
        for name in accepts {
            let body = read_seed(&corpus_root, name);
            let commands = parse_commands(&body);
            let mut state = ClientReplyState::default();
            for argv in &commands {
                apply_client_reply_state(argv, &mut state).unwrap_or_else(|err| {
                    panic!("seed {name} argv {argv:?} must apply cleanly: {err:?}")
                });
            }
        }

        // Pinned state-transition expectations.

        // ON sets off=false, skip_next=false, suppress=false.
        let mut state = ClientReplyState::default();
        for argv in parse_commands(&read_seed(&corpus_root, "reply_on_alone.txt")) {
            apply_client_reply_state(&argv, &mut state).unwrap();
        }
        assert!(!state.off);
        assert!(!state.skip_next);
        assert!(!state.suppress_current_response);

        // OFF sets off=true, suppress=true (the OFF reply itself
        // is also suppressed).
        let mut state = ClientReplyState::default();
        for argv in parse_commands(&read_seed(&corpus_root, "reply_off_alone.txt")) {
            apply_client_reply_state(&argv, &mut state).unwrap();
        }
        assert!(state.off);
        assert!(state.suppress_current_response);

        // SKIP sets skip_next=true, suppress=true (one-shot).
        let mut state = ClientReplyState::default();
        for argv in parse_commands(&read_seed(&corpus_root, "reply_skip_alone.txt")) {
            apply_client_reply_state(&argv, &mut state).unwrap();
        }
        assert!(!state.off);
        assert!(state.skip_next);
        assert!(state.suppress_current_response);

        // SKIP → PING → PING: only the FIRST PING is suppressed,
        // the second responds. After the sequence, skip_next is
        // false.
        let mut state = ClientReplyState::default();
        let cmds = parse_commands(&read_seed(&corpus_root, "skip_then_two_commands.txt"));
        // command 0: SKIP (skip_next=true, suppress=true)
        apply_client_reply_state(&cmds[0], &mut state).unwrap();
        assert!(state.skip_next);
        assert!(state.suppress_current_response);
        // command 1: PING (consumes skip_next, suppress=true)
        apply_client_reply_state(&cmds[1], &mut state).unwrap();
        assert!(!state.skip_next, "skip_next must clear after first command");
        assert!(state.suppress_current_response);
        // command 2: PING (no suppression any more)
        apply_client_reply_state(&cmds[2], &mut state).unwrap();
        assert!(!state.suppress_current_response);

        // OFF → command → ON: off stays true through the
        // non-CLIENT-REPLY command, then ON clears it.
        let mut state = ClientReplyState::default();
        let cmds = parse_commands(&read_seed(&corpus_root, "off_command_then_on.txt"));
        apply_client_reply_state(&cmds[0], &mut state).unwrap(); // OFF
        assert!(state.off);
        apply_client_reply_state(&cmds[1], &mut state).unwrap(); // GET k1
        assert!(state.off);
        assert!(state.suppress_current_response);
        apply_client_reply_state(&cmds[2], &mut state).unwrap(); // ON
        assert!(!state.off);

        // ── Reject-class: parser must return Err.
        let rejects: &[&str] = &[
            "reply_no_mode_arg.txt",
            "reply_extra_arg.txt",
            "reply_bogus_mode.txt",
            "reply_with_two_extras.txt",
            "reply_empty_mode.txt",
            "reply_lowercase_invalid_mode.txt",
            "reply_numeric_mode.txt",
        ];
        for name in rejects {
            let body = read_seed(&corpus_root, name);
            let commands = parse_commands(&body);
            let mut at_least_one_err = false;
            let mut state = ClientReplyState::default();
            for argv in &commands {
                if apply_client_reply_state(argv, &mut state).is_err() {
                    at_least_one_err = true;
                }
            }
            assert!(
                at_least_one_err,
                "seed {name} must surface at least one Err"
            );
        }
    }

    #[test]
    fn fuzz_lua_eval_corpus_matches_documented_contract() {
        use std::path::Path;

        let corpus_root =
            Path::new(env!("CARGO_MANIFEST_DIR")).join("../../fuzz/corpus/fuzz_lua_eval");
        if !corpus_root.exists() {
            return;
        }

        fn read_body(corpus_root: &Path, name: &str) -> Vec<u8> {
            let bytes = std::fs::read(corpus_root.join(name))
                .unwrap_or_else(|err| panic!("read seed {name}: {err}"));
            assert!(
                !bytes.is_empty(),
                "seed {name} is shorter than the mode byte"
            );
            assert_eq!(
                bytes[0], 0x00,
                "seed {name} mode byte must be 0x00 (fuzz_raw_lua path)"
            );
            bytes[1..].to_vec()
        }

        // The fuzz harness wires keys=["key"] and argv=["arg"];
        // mirror that here so seeds exercise the same code path.
        let keys = vec![b"key".to_vec()];
        let argv = vec![b"arg".to_vec()];

        // The new structured seeds (whose names appear in the
        // generator script) have the mode-byte 0x00 prefix. Older
        // seeds without the prefix are intentionally left in tree
        // — libfuzzer treats them as additional starting points
        // for mutation; they exercise the syntax-error path
        // instead of the valid-script path. Filter to seeds that
        // match the documented contract.
        let mode_prefixed: &[&str] = &[
            "empty.lua",
            "return_integer.lua",
            "return_string.lua",
            "return_bool.lua",
            "return_nil.lua",
            "arithmetic.lua",
            "modulo.lua",
            "string_length.lua",
            "string_concat.lua",
            "if_else.lua",
            "numeric_for_sum.lua",
            "local_alias.lua",
            "table_index.lua",
            "ipairs_iter.lua",
            "pairs_iter.lua",
            "keys_argv_echo.lua",
            "redis_call_set_get.lua",
            "redis_status_reply.lua",
            "redis_error_reply.lua",
            "redis_sha1hex.lua",
            "cjson_roundtrip.lua",
            "pcall_redis_call_failure.lua",
            "shebang_header_redis7.lua",
            "syntax_error_paren.lua",
            "undefined_global.lua",
            "explicit_error.lua",
            "infinite_while_true.lua",
            "table_index_out_of_range.lua",
            "long_concat.lua",
            "nested_function.lua",
        ];
        assert!(
            mode_prefixed.len() >= 14,
            "fuzz_lua_eval mode-prefixed seed list must have >= 14 entries; got {}",
            mode_prefixed.len()
        );
        for name in mode_prefixed {
            let body = read_body(&corpus_root, name);
            let mut store = Store::new();
            // Just exercise — don't bind. Invariant is "no panic".
            let _ = eval_script(&body, &keys, &argv, &mut store, 0);
        }

        // Representative deterministic seeds: pin the eval result
        // so the corpus exercises what the file names claim.
        let cases: &[(&str, RespFrame)] = &[
            ("return_integer.lua", RespFrame::Integer(42)),
            ("arithmetic.lua", RespFrame::Integer(7)),
            ("modulo.lua", RespFrame::Integer(1)),
            ("string_length.lua", RespFrame::Integer(3)),
            (
                "string_concat.lua",
                RespFrame::BulkString(Some(b"abc".to_vec())),
            ),
            ("if_else.lua", RespFrame::BulkString(Some(b"less".to_vec()))),
            ("numeric_for_sum.lua", RespFrame::Integer(15)),
            ("local_alias.lua", RespFrame::Integer(8)),
            (
                "table_index.lua",
                RespFrame::BulkString(Some(b"b".to_vec())),
            ),
            ("ipairs_iter.lua", RespFrame::Integer(60)),
            ("nested_function.lua", RespFrame::Integer(11)),
        ];
        for (name, expected) in cases {
            let body = read_body(&corpus_root, name);
            let mut store = Store::new();
            let result = eval_script(&body, &keys, &argv, &mut store, 0)
                .unwrap_or_else(|err| panic!("seed {name} must eval cleanly: {err}"));
            assert_eq!(
                &result, expected,
                "seed {name} eval result drifted (got {result:?}, expected {expected:?})"
            );
        }
    }

