    #[test]
    fn eval_tracks_script_propagation_targets_across_set_repl_changes() {
        let mut store = Store::new();
        let reply = dispatch_argv(
            &[
                b"EVAL".to_vec(),
                b"redis.call('SET','a','1')\nredis.set_repl(redis.REPL_NONE)\nredis.call('SET','b','2')\nredis.set_repl(redis.REPL_AOF)\nredis.call('SET','c','3')\nredis.set_repl(redis.REPL_REPLICA)\nredis.call('SET','d','4')\nredis.set_repl(redis.REPL_ALL)\nredis.call('SET','e','5')\nreturn redis.REPL_REPLICA + redis.REPL_SLAVE"
                    .to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("eval should succeed");
        // Upstream PROPAGATE_REPL = 2, so REPL_REPLICA + REPL_SLAVE = 4.
        // (br-frankenredis-replconst)
        assert_eq!(reply, RespFrame::Integer(4));

        let actual: Vec<(Vec<Vec<u8>>, u8)> = store
            .script_propagation_records
            .iter()
            .map(|record| (record.argv.clone(), record.targets))
            .collect();
        assert_eq!(
            actual,
            vec![
                (
                    vec![b"SET".to_vec(), b"a".to_vec(), b"1".to_vec()],
                    SCRIPT_PROPAGATE_ALL,
                ),
                (vec![b"SET".to_vec(), b"b".to_vec(), b"2".to_vec()], 0,),
                (
                    vec![b"SET".to_vec(), b"c".to_vec(), b"3".to_vec()],
                    SCRIPT_PROPAGATE_AOF,
                ),
                (
                    vec![b"SET".to_vec(), b"d".to_vec(), b"4".to_vec()],
                    SCRIPT_PROPAGATE_REPLICA,
                ),
                (
                    vec![b"SET".to_vec(), b"e".to_vec(), b"5".to_vec()],
                    SCRIPT_PROPAGATE_ALL,
                ),
            ]
        );
    }

    #[test]
    fn nested_scripting_commands_return_noscript_after_arity_check() {
        // (frankenredis-7j2cw) Upstream commands.def marks
        // EVAL/EVALSHA/FCALL/FCALL_RO with CMD_NOSCRIPT, and
        // script.c::scriptCommand at legacy_redis_code/redis/src/
        // script.c:524-532 evaluates arity FIRST and CMD_NOSCRIPT
        // SECOND — both before the handler runs. So inside a
        // script: arity wins over noscript, but noscript wins over
        // every handler-level parse / shebang / lookup error.
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let arity_cases = [
            (
                vec![b"EVAL".to_vec(), b"return 1".to_vec()],
                CommandError::WrongArity("EVAL"),
            ),
            (
                vec![b"EVALSHA".to_vec(), b"deadbeef".to_vec()],
                CommandError::WrongArity("EVALSHA"),
            ),
            (
                vec![b"FCALL_RO".to_vec(), b"func".to_vec()],
                CommandError::WrongArity("fcall_ro"),
            ),
        ];
        for (argv, expected) in arity_cases {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(err, expected, "argv: {argv:?}");
        }

        // Every arity-correct scripted EVAL/EVALSHA/FCALL/FCALL_RO
        // call — including bad numkeys — surfaces the noscript
        // reply (was returning InvalidInteger / 'Bad number of keys
        // provided' before frankenredis-7j2cw moved the guard up).
        let noscript_cases = [
            vec![b"EVAL".to_vec(), b"return 1".to_vec(), b"abc".to_vec()],
            vec![b"EVALSHA".to_vec(), b"deadbeef".to_vec(), b"abc".to_vec()],
            vec![b"FCALL".to_vec(), b"func".to_vec(), b"abc".to_vec()],
            vec![b"FCALL_RO".to_vec(), b"func".to_vec(), b"abc".to_vec()],
            vec![b"EVAL".to_vec(), b"return 1".to_vec(), b"0".to_vec()],
            vec![b"EVAL_RO".to_vec(), b"return 1".to_vec(), b"0".to_vec()],
            vec![b"EVALSHA".to_vec(), b"deadbeef".to_vec(), b"0".to_vec()],
            vec![b"EVALSHA_RO".to_vec(), b"deadbeef".to_vec(), b"0".to_vec()],
            vec![b"FCALL".to_vec(), b"func".to_vec(), b"0".to_vec()],
            vec![b"FCALL_RO".to_vec(), b"func".to_vec(), b"0".to_vec()],
        ];
        for argv in noscript_cases {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()),
                "argv: {argv:?}"
            );
        }
    }

    #[test]
    fn script_and_function_subcommands_run_noscript_guard_before_option_parsing() {
        // (frankenredis-yrm7e) Upstream commands.def lines 5318-5322
        // mark SCRIPT FLUSH/DEBUG with CMD_NOSCRIPT, lines 5138-5146
        // mark FUNCTION LIST/FLUSH with CMD_NOSCRIPT. script.c
        // evaluates the flag before any handler-level mode / option
        // validation, so a scripted call with bad args must surface
        // the noscript reply rather than the mode/syntax error.
        let mut store = Store::new();
        store.script_nesting_level = 1;
        for argv in [
            vec![b"SCRIPT".to_vec(), b"FLUSH".to_vec(), b"NOSUCH".to_vec()],
            vec![b"SCRIPT".to_vec(), b"DEBUG".to_vec(), b"MAYBE".to_vec()],
            vec![b"FUNCTION".to_vec(), b"LIST".to_vec(), b"NOSUCH".to_vec()],
            vec![b"FUNCTION".to_vec(), b"FLUSH".to_vec(), b"NOSUCH".to_vec()],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("noscript should win");
            assert_eq!(
                err,
                CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()),
                "argv: {argv:?}"
            );
        }
    }

