    #[test]
    fn shutdown_rejected_from_scripts_after_arity_check() {
        // Upstream Redis 7.2 server.c::processCommand evaluates CMD_NOSCRIPT
        // (commands.def:10793 for SHUTDOWN) BEFORE running shutdownCommand,
        // so the option-parsing loop and flag-conflict check in
        // shutdownCommand only execute once the script-context check has
        // let the command through. fr-command must mirror that ordering: a
        // scripted call with conflicting flags returns NOSCRIPT, not
        // SyntaxError. (frankenredis-avxsq)
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let err = dispatch_argv(
            &[b"SHUTDOWN".to_vec(), b"ABORT".to_vec(), b"NOW".to_vec()],
            &mut store,
            0,
        )
        .expect_err("abort mixed with flags should still be NOSCRIPT under script");
        assert_eq!(
            err,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        let err = dispatch_argv(
            &[b"SHUTDOWN".to_vec(), b"SAVE".to_vec(), b"NOSAVE".to_vec()],
            &mut store,
            0,
        )
        .expect_err("save and nosave together should still be NOSCRIPT under script");
        assert_eq!(
            err,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        let bare =
            dispatch_argv(&[b"SHUTDOWN".to_vec()], &mut store, 0).expect_err("shutdown noscript");
        assert_eq!(
            bare,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        let abort = dispatch_argv(&[b"SHUTDOWN".to_vec(), b"ABORT".to_vec()], &mut store, 0)
            .expect_err("shutdown abort noscript");
        assert_eq!(
            abort,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );
    }

    #[test]
    fn move_same_db_returns_redis_error() {
        // Upstream Redis 7.2 db.c::moveCommand checks for same-db
        // BEFORE consulting key existence, so 'MOVE missing 0' from
        // db 0 emits "ERR source and destination objects are the
        // same" rather than 0. The previous fr-command::move_cmd was
        // a stub that returned Integer(0) regardless. Verified via
        // redis-cli -p 16701. (frankenredis-w9yzb)
        let mut store = Store::new();
        let err = dispatch_argv(
            &[b"MOVE".to_vec(), b"key".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect_err("same-db should error");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR source and destination objects are the same".to_string())
        );
    }

    #[test]
    fn move_cross_db_actually_transfers_key() {
        // Lua redis.call('MOVE', ...) and AOF replay both route
        // through dispatch_argv → move_cmd, so this path must
        // actually move keys between databases (not silently no-op
        // as the prior stub did). (frankenredis-w9yzb)
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"foo"), b"bar".to_vec(), None, 0);
        assert!(store.exists(&fr_store::encode_db_key(0, b"foo"), 0));

        let out = dispatch_argv(
            &[b"MOVE".to_vec(), b"foo".to_vec(), b"1".to_vec()],
            &mut store,
            0,
        )
        .expect("move");
        assert_eq!(out, RespFrame::Integer(1));
        assert!(!store.exists(&fr_store::encode_db_key(0, b"foo"), 0));
        assert!(store.exists(&fr_store::encode_db_key(1, b"foo"), 0));
    }

