    #[test]
    fn wait_clamps_negative_numreplicas_and_uses_timeout_specific_errors() {
        let mut store = Store::new();

        let invalid_numreplicas = dispatch_argv(
            &[b"WAIT".to_vec(), b"abc".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(invalid_numreplicas, CommandError::InvalidInteger);

        let negative = dispatch_argv(
            &[b"WAIT".to_vec(), b"-1".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect("negative numreplicas should clamp to zero");
        assert_eq!(negative, RespFrame::Integer(0));

        let invalid_timeout = dispatch_argv(
            &[b"WAIT".to_vec(), b"0".to_vec(), b"abc".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            invalid_timeout,
            CommandError::Custom("ERR timeout is not an integer or out of range".to_string())
        );
    }

    #[test]
    fn wait_rejects_script_context_and_extra_args() {
        // (frankenredis-o7kay) Upstream commands.def declares WAIT
        // with arity=3 (exact) and CMD_NOSCRIPT, so trailing args
        // surface the wrong-arity reply and any Lua call must hit
        // the script_noscript guard.
        let mut store = Store::new();

        // Trailing args → WrongArity (was silently accepted).
        let extra = dispatch_argv(
            &[
                b"WAIT".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(extra, CommandError::WrongArity("WAIT"));

        // Inside a Lua script, WAIT must surface the noscript reply.
        store.script_nesting_level = 1;
        let scripted = dispatch_argv(
            &[b"WAIT".to_vec(), b"0".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            scripted,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );
    }

    #[test]
    fn waitaof_and_failover_noscript_guard_precedes_argument_parsing() {
        // (frankenredis-d021m) Upstream commands.def declares both
        // WAITAOF and FAILOVER with CMD_NOSCRIPT, so processCommand
        // emits the noscript reply before any argument parsing runs.
        // Inside a Lua script, scripted bad-arg calls must surface
        // the noscript error rather than the parse / syntax error.
        let mut store = Store::new();
        store.script_nesting_level = 1;

        // WAITAOF with a non-integer numlocal still surfaces the
        // noscript reply because the guard fires before parse_i64_arg.
        let waitaof_scripted = dispatch_argv(
            &[
                b"WAITAOF".to_vec(),
                b"abc".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            waitaof_scripted,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        // FAILOVER with an unknown option should also short-circuit
        // to the noscript reply (was returning SyntaxError because
        // the option-parser ran first).
        let failover_scripted = dispatch_argv(
            &[b"FAILOVER".to_vec(), b"NOSUCH".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            failover_scripted,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );
    }

