    #[test]
    fn slowlog_get_accepts_minus_one_and_rejects_invalid_shapes() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[b"SLOWLOG".to_vec(), b"GET".to_vec(), b"-1".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Array(Some(Vec::new())));

        let err = dispatch_argv(
            &[b"SLOWLOG".to_vec(), b"GET".to_vec(), b"-2".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR count should be greater than or equal to -1".to_string())
        );

        // (frankenredis-iglto) Non-integer count must surface the same
        // canonical wording — upstream's getRangeLongFromObjectOrReply
        // uses the msg argument for both parse failure and out-of-range.
        for bad in [b"abc".as_slice(), b"".as_slice(), b"1.5".as_slice()] {
            let err = dispatch_argv(
                &[b"SLOWLOG".to_vec(), b"GET".to_vec(), bad.to_vec()],
                &mut store,
                0,
            )
            .unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(
                    "ERR count should be greater than or equal to -1".to_string()
                ),
                "input: {bad:?}"
            );
        }

        let err = dispatch_argv(
            &[
                b"SLOWLOG".to_vec(),
                b"GET".to_vec(),
                b"1".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::WrongSubcommandArity {
                command: "SLOWLOG",
                subcommand: "GET".to_string(),
            }
        );
    }

