    #[test]
    fn hrandfield_zrandmember_with_pair_modifier_enforce_half_long_range() {
        // (frankenredis-sntxr) Upstream restricts count to
        // [-LONG_MAX/2, LONG_MAX/2] when WITHVALUES (HRANDFIELD) /
        // WITHSCORES (ZRANDMEMBER) is set, so count*2 in the reply
        // length can't overflow. Pin both commands rejecting just-
        // outside-half boundary values with the upstream error
        // wording, while accepting at-half values.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"HSET".to_vec(),
                b"h".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hset");
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd");

        let half = i64::MAX / 2;
        let just_over = (half + 1).to_string().into_bytes();
        let just_under = (-(half) - 1).to_string().into_bytes();
        let expected_err =
            CommandError::Custom("ERR value is out of range".to_string());

        // HRANDFIELD WITHVALUES rejects (LONG_MAX/2 + 1).
        let err = dispatch_argv(
            &[
                b"HRANDFIELD".to_vec(),
                b"h".to_vec(),
                just_over.clone(),
                b"WITHVALUES".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, expected_err);

        // HRANDFIELD WITHVALUES rejects -(LONG_MAX/2 + 1).
        let err = dispatch_argv(
            &[
                b"HRANDFIELD".to_vec(),
                b"h".to_vec(),
                just_under.clone(),
                b"WITHVALUES".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, expected_err);

        // ZRANDMEMBER WITHSCORES rejects same boundaries.
        let err = dispatch_argv(
            &[
                b"ZRANDMEMBER".to_vec(),
                b"z".to_vec(),
                just_over,
                b"WITHSCORES".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, expected_err);

        let err = dispatch_argv(
            &[
                b"ZRANDMEMBER".to_vec(),
                b"z".to_vec(),
                just_under,
                b"WITHSCORES".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, expected_err);

        // Sanity: at the half boundary, neither variant rejects.
        // half=4611686018427387903 is too large to actually dispatch
        // through HRANDFIELD/ZRANDMEMBER (would allocate huge result
        // vec), so the in-range case is exercised by the dispatch
        // tests for typical small values elsewhere in this module.
    }

    #[test]
    fn lpos_rank_rejects_i64_min_with_upstream_out_of_range_error() {
        // (frankenredis-xiome) Upstream t_list.c::lposCommand uses
        // getRangeLongFromObjectOrReply(c, argv, -LONG_MAX, LONG_MAX,
        // ...) which rejects only i64::MIN. fr was accepting it and
        // silently returning empty (skip overflow never matched any
        // element). Pin the upstream error wording.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"RPUSH".to_vec(),
                b"l".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
                b"c".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("rpush");

        let i64_min = b"-9223372036854775808";
        let err = dispatch_argv(
            &[
                b"LPOS".to_vec(),
                b"l".to_vec(),
                b"a".to_vec(),
                b"RANK".to_vec(),
                i64_min.to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom(format!(
                "ERR value is out of range, value must between {} and {}",
                -i64::MAX,
                i64::MAX
            ))
        );

        // RANK = -1 (legitimate) still works.
        let out = dispatch_argv(
            &[
                b"LPOS".to_vec(),
                b"l".to_vec(),
                b"a".to_vec(),
                b"RANK".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("rank -1 must succeed");
        assert_eq!(out, RespFrame::Integer(0));

        // RANK = 0 still hits the bespoke 'RANK can't be zero' error.
        let err = dispatch_argv(
            &[
                b"LPOS".to_vec(),
                b"l".to_vec(),
                b"a".to_vec(),
                b"RANK".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("rank 0 returns Error frame");
        let RespFrame::Error(msg) = err else {
            panic!("expected Error frame for RANK 0"); // ubs:ignore — AI triage
        };
        assert!(msg.starts_with("ERR RANK can't be zero"));
    }

    #[test]
    fn randmember_family_rejects_i64_min_count_to_prevent_dos() {
        // (frankenredis-wsqf2) i64::MIN passed as a negative count
        // would call .unsigned_abs() and loop ~9.2 quintillion times,
        // hanging the server. Upstream getRangeLongFromObjectOrReply
        // restricts to [-LONG_MAX, LONG_MAX] which excludes only
        // i64::MIN. Pin that all three *RANDMEMBER commands reject
        // i64::MIN with the upstream "value is out of range" wording.
        let mut store = Store::new();

        // Seed each container so the count handler is reached.
        dispatch_argv(&[b"SADD".to_vec(), b"s".to_vec(), b"a".to_vec()], &mut store, 0)
            .expect("sadd");
        dispatch_argv(
            &[
                b"HSET".to_vec(),
                b"h".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hset");
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd");

        let i64_min = b"-9223372036854775808";
        let expected_err = CommandError::Custom(format!(
            "ERR value is out of range, value must between {} and {}",
            -i64::MAX,
            i64::MAX
        ));

        for argv in [
            vec![b"SRANDMEMBER".to_vec(), b"s".to_vec(), i64_min.to_vec()],
            vec![b"HRANDFIELD".to_vec(), b"h".to_vec(), i64_min.to_vec()],
            vec![b"ZRANDMEMBER".to_vec(), b"z".to_vec(), i64_min.to_vec()],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err, expected_err,
                "expected upstream out-of-range error for {argv:?}"
            );
        }

        // Sanity: -1 and i64::MAX still work (in-range).
        for cmd in [b"SRANDMEMBER".as_slice(), b"HRANDFIELD", b"ZRANDMEMBER"] {
            let key: &[u8] = match cmd {
                b"SRANDMEMBER" => b"s",
                b"HRANDFIELD" => b"h",
                b"ZRANDMEMBER" => b"z",
                _ => unreachable!(),
            };
            for count_str in [&b"-1"[..], b"9223372036854775807"] {
                // i64::MAX
                let argv = vec![cmd.to_vec(), key.to_vec(), count_str.to_vec()];
                // Don't actually execute i64::MAX (would still take a long
                // time) — just check that parse_i64_arg_long_range accepts.
                if count_str == b"-1" {
                    dispatch_argv(&argv, &mut store, 0).expect("count -1 must succeed");
                } else {
                    // i64::MAX accepted by helper (don't dispatch — would
                    // be slow). Helper is module-private; rely on
                    // i64::MIN rejection above as the primary guard.
                }
            }
        }
    }

    #[test]
    fn info_persistence_reports_live_aof_rewrites_counter() {
        // (frankenredis-f1f8f) aof_rewrites was hardcoded to 0 even
        // though Store::record_aof_rewrite fires on every BGREWRITEAOF.
        // Pin baseline (0) and post-rewrite live state (3 after three
        // record_aof_rewrite calls).
        let mut store = Store::new();

        let out = dispatch_argv(
            &[b"INFO".to_vec(), b"persistence".to_vec()],
            &mut store,
            0,
        )
        .expect("info persistence baseline");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(info.contains("aof_rewrites:0\r\n"));

        // Trigger three rewrites.
        store.record_aof_rewrite(1_000);
        store.record_aof_rewrite(2_000);
        store.record_aof_rewrite(3_000);

        let out = dispatch_argv(
            &[b"INFO".to_vec(), b"persistence".to_vec()],
            &mut store,
            4_000,
        )
        .expect("info persistence after rewrites");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(
            info.contains("aof_rewrites:3\r\n"),
            "expected aof_rewrites:3 in: {info}"
        );
    }

    #[test]
    fn info_server_reports_runtime_os_and_arch_bits() {
        // (frankenredis-efkwg) INFO Server's `os:` and `arch_bits:`
        // were hardcoded ("Linux", 64). Replaced with runtime values
        // from std::env::consts::OS and std::mem::size_of::<usize>().
        let mut store = Store::new();
        let out = dispatch_argv(&[b"INFO".to_vec(), b"server".to_vec()], &mut store, 0)
            .expect("info server");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");

        // Map the same way the handler does so the assertion is
        // stable across Linux / macOS / Windows / *BSD targets.
        let expected_os = match std::env::consts::OS {
            "linux" => "Linux",
            "macos" => "Darwin",
            "windows" => "Windows",
            "freebsd" => "FreeBSD",
            "openbsd" => "OpenBSD",
            "netbsd" => "NetBSD",
            "dragonfly" => "DragonFly",
            "solaris" => "SunOS",
            other => other,
        };
        assert!(
            info.contains(&format!("os:{expected_os}\r\n")),
            "expected os:{expected_os} in: {info}"
        );

        // arch_bits derives from pointer width.
        let expected_arch_bits = std::mem::size_of::<usize>() * 8;
        assert!(
            info.contains(&format!("arch_bits:{expected_arch_bits}\r\n")),
            "expected arch_bits:{expected_arch_bits} in: {info}"
        );

        // (frankenredis-ksl7m) multiplexing_api derives from the
        // platform's mio backend. Same mapping as the handler so the
        // assertion is stable across Linux / macOS / *BSD / Solaris /
        // Windows.
        let expected_multiplexing = match std::env::consts::OS {
            "linux" | "android" => "epoll",
            "macos" | "ios" | "freebsd" | "openbsd" | "netbsd" | "dragonfly" => "kqueue",
            "solaris" | "illumos" => "evport",
            "windows" => "IOCP",
            _ => "select",
        };
        assert!(
            info.contains(&format!("multiplexing_api:{expected_multiplexing}\r\n")),
            "expected multiplexing_api:{expected_multiplexing} in: {info}"
        );
    }

    #[test]
    fn xinfo_help_matches_vendored_724_wording_with_simple_string_frames() {
        // (frankenredis-tnscz) XINFO HELP now mirrors vendored Redis
        // 7.2.4 t_stream.c::xinfoCommand line-for-line. Three contracts
        // pinned: every frame is SimpleString (was BulkString — same
        // as the 0o9vo / vtege / kuthf / s574p cluster), descriptions
        // match upstream's terser wording exactly, and the STREAM
        // line preserves upstream's missing-closing-bracket typo.
        let mut store = Store::new();
        let out = dispatch_argv(&[b"XINFO".to_vec(), b"HELP".to_vec()], &mut store, 0).unwrap();
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array"); // ubs:ignore — AI triage
        };

        for (i, frame) in items.iter().enumerate() {
            assert!(
                matches!(frame, RespFrame::SimpleString(_)),
                "frame {i} must be SimpleString, got {frame:?}"
            );
        }

        // Standard envelope.
        assert_eq!(
            items[0],
            RespFrame::SimpleString(
                "XINFO <subcommand> [<arg> [value] [opt] ...]. Subcommands are:".to_string()
            )
        );

        // Upstream 7.2.4 descriptions (terser).
        assert!(items.contains(&RespFrame::SimpleString(
            "    Show the stream consumer groups.".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Show information about the stream.".to_string()
        )));

        // Preserve upstream's missing-closing-bracket typo for parity.
        assert!(items.contains(&RespFrame::SimpleString(
            "STREAM <key> [FULL [COUNT <count>]".to_string()
        )));

        // Old paraphrased wording must NOT be present.
        assert!(!items.iter().any(|f| matches!(
            f,
            RespFrame::SimpleString(s) if s == "    Show groups of stream <key>."
        )));
        assert!(!items.iter().any(|f| matches!(
            f,
            RespFrame::SimpleString(s) if s == "    Show information about stream <key>."
        )));
        // Both-brackets-closed wording must NOT be present (upstream typo
        // preservation).
        assert!(!items.iter().any(|f| matches!(
            f,
            RespFrame::SimpleString(s) if s.contains("[COUNT <count>]]")
        )));

        // Trailing HELP block.
        assert!(items.contains(&RespFrame::SimpleString("HELP".to_string())));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Print this help.".to_string()
        )));
    }

    #[test]
    fn xgroup_help_matches_vendored_724_wording_with_simple_string_frames() {
        // (frankenredis-s574p) XGROUP HELP now mirrors vendored Redis
        // 7.2.4 t_stream.c::xgroupCommand line-for-line. Three
        // contracts pinned: every frame is SimpleString (was
        // BulkString — same as 0o9vo / vtege / kuthf), placeholders
        // use upstream syntax (<id|$>, <consumer>), and CREATE/SETID
        // surface the MKSTREAM / ENTRIESREAD option detail.
        let mut store = Store::new();
        let out = dispatch_argv(&[b"XGROUP".to_vec(), b"HELP".to_vec()], &mut store, 0).unwrap();
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array"); // ubs:ignore — AI triage
        };

        for (i, frame) in items.iter().enumerate() {
            assert!(
                matches!(frame, RespFrame::SimpleString(_)),
                "frame {i} must be SimpleString, got {frame:?}"
            );
        }

        // Standard envelope.
        assert_eq!(
            items[0],
            RespFrame::SimpleString(
                "XGROUP <subcommand> [<arg> [value] [opt] ...]. Subcommands are:".to_string()
            )
        );

        // Upstream 7.2.4 placeholder syntax + option detail.
        assert!(items.contains(&RespFrame::SimpleString(
            "CREATE <key> <groupname> <id|$> [option]".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString("    * MKSTREAM".to_string())));
        assert!(items.contains(&RespFrame::SimpleString(
            "      Create the empty stream if it does not exist.".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "    * ENTRIESREAD entries_read".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "SETID <key> <groupname> <id|$> [ENTRIESREAD entries_read]".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Set the current group ID and entries_read counter.".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Remove the specified consumer.".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Remove the specified group.".to_string()
        )));

        // Old paraphrased wording must NOT be present.
        assert!(!items.iter().any(|f| matches!(
            f,
            RespFrame::SimpleString(s) if s.contains("<consumername>")
        )));
        assert!(!items.iter().any(|f| matches!(
            f,
            RespFrame::SimpleString(s) if s.contains("<id-or-$>")
        )));
        assert!(!items.iter().any(|f| matches!(
            f,
            RespFrame::SimpleString(s) if s == "    Destroy a consumer group."
        )));

        // Trailing HELP block.
        assert!(items.contains(&RespFrame::SimpleString("HELP".to_string())));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Print this help.".to_string()
        )));
    }

