        assert_eq!(
            items[0],
            RespFrame::SimpleString(
                "CONFIG <subcommand> [<arg> [value] [opt] ...]. Subcommands are:".to_string()
            )
        );

        // Upstream 7.2.4 wording — single pattern / single directive.
        assert!(items.contains(&RespFrame::SimpleString("GET <pattern>".to_string())));
