    #[test]
    fn function_admin_subcommands_rejected_from_scripts_after_arity_check() {
        // (frankenredis-yrm7e) Upstream commands.def lines 5138-5146
        // mark FUNCTION DELETE/DUMP/FLUSH/KILL/LIST/LOAD/RESTORE/STATS
        // with CMD_NOSCRIPT. Mirror script.c's arity-then-noscript
        // ordering: arity wins over noscript, noscript wins over
        // every handler-level mode/option/extra-arg error.
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let stats_arity = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"STATS".to_vec(), b"extra".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            stats_arity,
            CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "STATS".to_string(),
            }
        );

        let library =
            b"#!lua name=scriptlib\nredis.register_function('echo', function(keys, args) return args[1] end)";
        for argv in [
            vec![b"FUNCTION".to_vec(), b"LIST".to_vec()],
            vec![b"FUNCTION".to_vec(), b"LIST".to_vec(), b"NOSUCH".to_vec()],
            vec![b"FUNCTION".to_vec(), b"STATS".to_vec()],
            vec![b"FUNCTION".to_vec(), b"LOAD".to_vec(), library.to_vec()],
            vec![b"FUNCTION".to_vec(), b"DELETE".to_vec(), b"mylib".to_vec()],
            vec![b"FUNCTION".to_vec(), b"DUMP".to_vec()],
            vec![b"FUNCTION".to_vec(), b"FLUSH".to_vec()],
            vec![b"FUNCTION".to_vec(), b"FLUSH".to_vec(), b"BOGUS".to_vec()],
            vec![b"FUNCTION".to_vec(), b"KILL".to_vec()],
            vec![
                b"FUNCTION".to_vec(),
                b"RESTORE".to_vec(),
                b"payload".to_vec(),
            ],
            vec![
                b"FUNCTION".to_vec(),
                b"RESTORE".to_vec(),
                b"payload".to_vec(),
                b"FLUSH".to_vec(),
                b"EXTRA".to_vec(),
            ],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()),
                "argv: {argv:?}"
            );
        }
    }

    #[test]
    fn function_list_and_stats_match_redis_reply_shapes() {
        let mut store = Store::new();
        let library = b"#!lua name=mylib\nredis.register_function('myfunc', function(keys, args) return args[1] end)";

        let out = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"LOAD".to_vec(), library.to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(b"mylib".to_vec())));

        let list = dispatch_argv(&[b"FUNCTION".to_vec(), b"LIST".to_vec()], &mut store, 0)
            .expect("function list");
        assert_eq!(
            list,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"library_name".to_vec())),
                RespFrame::BulkString(Some(b"mylib".to_vec())),
                RespFrame::BulkString(Some(b"engine".to_vec())),
                RespFrame::BulkString(Some(b"LUA".to_vec())),
                RespFrame::BulkString(Some(b"functions".to_vec())),
                RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"name".to_vec())),
                    RespFrame::BulkString(Some(b"myfunc".to_vec())),
                    RespFrame::BulkString(Some(b"description".to_vec())),
                    RespFrame::BulkString(None),
                    RespFrame::BulkString(Some(b"flags".to_vec())),
                    RespFrame::Array(Some(Vec::new())),
                ]))])),
            ]))]))
        );

        let stats = dispatch_argv(&[b"FUNCTION".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("function stats");
        // PINNED 2026-04-23 — running_script is RESP2 nil (BulkString(None))
        // when no script is running, matching the implementation at
        // lib.rs:6394 and the stock redis:7.4 / redis:7.2.4 live-oracle
        // probe (redis-cli --no-raw FUNCTION STATS returns "(nil)" in the
        // running_script slot on an idle server). An earlier commit
        // (fd17b66) self-contradictorily flipped this test to Integer(0)
        // while the impl and its PINNED comment still asserted nil; this
        // resolves the drift by realigning the test with both. See
        // br-frankenredis-j4vq.
        assert_eq!(
            stats,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"running_script".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::BulkString(Some(b"engines".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"LUA".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"libraries_count".to_vec())),
                        RespFrame::Integer(1),
                        RespFrame::BulkString(Some(b"functions_count".to_vec())),
                        RespFrame::Integer(1),
                    ])),
                ])),
            ]))
        );
    }

