    #[test]
    fn function_and_script_parity_errors_match_vendored_redis() {
        let mut store = Store::new();
        let err = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua\nredis.register_function('f', function(keys, args) return 1 end)".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR Library name was not given".to_string())
        );

        let kill = dispatch_argv(&[b"FUNCTION".to_vec(), b"KILL".to_vec()], &mut store, 0).unwrap();
        assert_eq!(
            kill,
            RespFrame::Error("NOTBUSY No scripts in execution right now.".to_string())
        );

        let cases = [
            (
                vec![b"FUNCTION".to_vec(), b"DELETE".to_vec()],
                "ERR wrong number of arguments for 'function|delete' command",
            ),
            (
                vec![b"FUNCTION".to_vec(), b"KILL".to_vec(), b"extra".to_vec()],
                "ERR wrong number of arguments for 'function|kill' command",
            ),
            (
                vec![b"FUNCTION".to_vec(), b"LOAD".to_vec()],
                "ERR wrong number of arguments for 'function|load' command",
            ),
            (
                vec![b"FUNCTION".to_vec(), b"RESTORE".to_vec()],
                "ERR wrong number of arguments for 'function|restore' command",
            ),
            (
                vec![
                    b"FUNCTION".to_vec(),
                    b"RESTORE".to_vec(),
                    b"payload".to_vec(),
                    b"FLUSH".to_vec(),
                    b"EXTRA".to_vec(),
                ],
                "ERR unknown subcommand or wrong number of arguments for 'RESTORE'. Try FUNCTION HELP.",
            ),
            (
                vec![b"SCRIPT".to_vec(), b"EXISTS".to_vec()],
                "ERR wrong number of arguments for 'script|exists' command",
            ),
            (
                vec![b"SCRIPT".to_vec(), b"LOAD".to_vec()],
                "ERR wrong number of arguments for 'script|load' command",
            ),
        ];
        for (argv, expected) in cases {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err.to_resp(),
                RespFrame::Error(expected.to_string()),
                "argv: {argv:?}"
            );
        }
    }

    #[test]
    fn fcall_lookup_precedes_numkeys_validation_and_ro_alias_matches_redis() {
        let mut store = Store::new();
        let lookup_first_cases = [
            vec![b"FCALL".to_vec(), b"myfunc".to_vec(), b"abc".to_vec()],
            vec![b"FCALL".to_vec(), b"myfunc".to_vec(), b"-1".to_vec()],
            vec![b"FCALL".to_vec(), b"myfunc".to_vec(), b"5".to_vec()],
            vec![b"FCALL_RO".to_vec(), b"myfunc".to_vec(), b"abc".to_vec()],
            vec![b"FCALL_RO".to_vec(), b"myfunc".to_vec(), b"-1".to_vec()],
            vec![b"FCALL_RO".to_vec(), b"myfunc".to_vec(), b"5".to_vec()],
        ];
        for argv in lookup_first_cases {
            let out = dispatch_argv(&argv, &mut store, 0).unwrap();
            assert_eq!(
                out,
                RespFrame::Error("ERR Function not found".to_string()),
                "argv: {argv:?}"
            );
        }

        let arity_cases = [
            vec![b"FCALL_RO".to_vec()],
            vec![b"FCALL_RO".to_vec(), b"func".to_vec()],
        ];
        for argv in arity_cases {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(
                err.to_resp(),
                RespFrame::Error(
                    "ERR wrong number of arguments for 'fcall_ro' command".to_string()
                ),
                "argv: {argv:?}"
            );
        }
    }

    #[test]
    fn fcall_non_integer_numkeys_uses_upstream_specific_wording() {
        // (frankenredis-ascgr) Upstream functions.c::fcallCommandGeneric
        // line 638-641 emits 'Bad number of keys provided' when argv[2]
        // can't be parsed as an integer — distinct from EVAL's generic
        // 'value is not an integer or out of range'. fr was sharing the
        // EVAL-shaped parse_eval_args helper, which leaked the EVAL
        // wording into FCALL's parse path. The lookup happens BEFORE
        // numkeys parsing in upstream, so this only fires when the
        // function exists.
        let mut store = Store::new();
        // Load a trivial function so the lookup succeeds and the
        // numkeys parser actually runs. FCALL_RO has its own
        // write-flag pre-check that fires before the numkeys parse
        // (fr does not currently surface the no-writes flag from the
        // Lua source — separate gap, out of scope here), so this
        // regression test only exercises FCALL. The numkeys parsing
        // path is identical for both, so a single FCALL probe pins
        // the wording.
        dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=lib\nredis.register_function('f', function() return 1 end)"
                    .to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("FUNCTION LOAD seed");

        let out = dispatch_argv(
            &[b"FCALL".to_vec(), b"f".to_vec(), b"NOTANINT".to_vec()],
            &mut store,
            0,
        )
        .expect_err("non-integer numkeys must error after function lookup");
        assert_eq!(
            out,
            CommandError::Custom("ERR Bad number of keys provided".to_string())
        );
    }

