    #[test]
    fn client_commands_use_dispatch_client_context() {
        let mut store = Store::new();
        store.dispatch_client_ctx.client_id = 42;
        store.dispatch_client_ctx.client_name = Some(b"alpha".to_vec());
        store.dispatch_client_ctx.client_lib_name = Some("redis-rs".to_string());
        store.dispatch_client_ctx.client_lib_ver = Some("1.2.3".to_string());
        store.dispatch_client_ctx.db_index = 5;
        store.dispatch_client_ctx.peer_addr = "10.0.0.9:7777".to_string();
        store.dispatch_client_ctx.authenticated_user = b"alice".to_vec();
        store.dispatch_client_ctx.resp_protocol_version = 3;
        store.dispatch_client_ctx.channel_subscriptions = 2;
        store.dispatch_client_ctx.pattern_subscriptions = 1;
        store.dispatch_client_ctx.shard_subscriptions = 4;
        store.dispatch_client_ctx.multi_count = 3;
        store.dispatch_client_ctx.watch_count = 2;

        let out = dispatch_argv(&[b"CLIENT".to_vec(), b"GETNAME".to_vec()], &mut store, 0).unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(b"alpha".to_vec())));

        let out = dispatch_argv(&[b"CLIENT".to_vec(), b"ID".to_vec()], &mut store, 0).unwrap();
        assert_eq!(out, RespFrame::Integer(42));

        let out = dispatch_argv(&[b"CLIENT".to_vec(), b"INFO".to_vec()], &mut store, 0).unwrap();
        let RespFrame::BulkString(Some(payload)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(payload).expect("utf8");
        assert!(info.contains("id=42 "), "{info}");
        assert!(info.contains("addr=10.0.0.9:7777 "), "{info}");
        assert!(info.contains("name=alpha "), "{info}");
        assert!(info.contains("db=5 "), "{info}");
        assert!(info.contains("sub=2 "), "{info}");
        assert!(info.contains("psub=1 "), "{info}");
        assert!(info.contains("ssub=4 "), "{info}");
        assert!(info.contains("multi=3 "), "{info}");
        // Upstream Redis 7.2 dropped the `watch=N` field from CLIENT INFO.
        assert!(!info.contains("watch="), "{info}");
        assert!(info.contains("argv-mem=0 "), "{info}");
        assert!(info.contains("multi-mem=0 "), "{info}");
        assert!(info.contains("rbs=0 "), "{info}");
        assert!(info.contains("rbp=0 "), "{info}");
        assert!(info.contains("user=alice "), "{info}");
        assert!(info.contains("redir=-1 "), "{info}");
        assert!(info.contains("resp=3 "), "{info}");
        assert!(info.contains("lib-name=redis-rs "), "{info}");
        assert!(info.ends_with("lib-ver=1.2.3\r\n"), "{info}");
    }

    #[test]
    fn client_setinfo_matches_runtime_contract() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"SETINFO".to_vec(),
                b"LIB-NAME".to_vec(),
                b"redis-py".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        assert_eq!(
            store.dispatch_client_ctx.client_lib_name.as_deref(),
            Some("redis-py")
        );

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"SETINFO".to_vec(),
                b"lib-ver".to_vec(),
                b"5.0.1".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        assert_eq!(
            store.dispatch_client_ctx.client_lib_ver.as_deref(),
            Some("5.0.1")
        );

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"SETINFO".to_vec(),
                b"UNKNOWN".to_vec(),
                b"value".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR Unrecognized option 'UNKNOWN'".to_string())
        );

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"SETINFO".to_vec(),
                b"LIB-NAME".to_vec(),
                b"has space".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom(
                "ERR LIB-NAME cannot contain spaces, newlines or special characters.".to_string()
            )
        );

        // (frankenredis-e2xii) The validation error must echo the
        // user-provided attr verbatim — upstream uses addReplyErrorFormat
        // with the raw argv[2] string, preserving case.
        for (attr_input, expected) in [
            (
                "lib-name",
                "ERR lib-name cannot contain spaces, newlines or special characters.",
            ),
            (
                "Lib-Ver",
                "ERR Lib-Ver cannot contain spaces, newlines or special characters.",
            ),
        ] {
            let err = dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"SETINFO".to_vec(),
                    attr_input.as_bytes().to_vec(),
                    b"has space".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(expected.to_string()),
                "input attr: {attr_input}"
            );
        }
    }

    #[test]
    fn client_help_matches_runtime_shape() {
        // (frankenredis-0o9vo) CLIENT HELP now matches upstream
        // networking.c::clientCommand line-for-line: SimpleString
        // frames + description + indented option detail per
        // subcommand. Pin the new shape: every frame must be
        // SimpleString (not BulkString), the standard envelope
        // header must be present, and at least one description
        // line must accompany each subcommand.
        let mut store = Store::new();
        let out = dispatch_argv(&[b"CLIENT".to_vec(), b"HELP".to_vec()], &mut store, 0).unwrap();
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array"); // ubs:ignore — AI triage
        };

        // Every frame must be SimpleString — was BulkString before fix.
        for (i, frame) in items.iter().enumerate() {
            assert!(
                matches!(frame, RespFrame::SimpleString(_)),
                "frame {i} must be SimpleString, got {frame:?}"
            );
        }

        // Standard envelope from upstream addReplyHelp.
        assert_eq!(
            items[0],
            RespFrame::SimpleString(
                "CLIENT <subcommand> [<arg> [value] [opt] ...]. Subcommands are:".to_string()
            )
        );

        // Subcommand entries must include a description line. Pick
        // a few key ones to spot-check.
        assert!(items.contains(&RespFrame::SimpleString("SETINFO <option> <value>".to_string())));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Set client meta attr. Options are:".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "UNBLOCK <clientid> [TIMEOUT|ERROR]".to_string()
        )));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Unblock the specified blocked client.".to_string()
        )));

        // Trailing 'HELP' / '    Print this help.' from upstream
        // addReplyHelp.
        assert!(items.contains(&RespFrame::SimpleString("HELP".to_string())));
        assert!(items.contains(&RespFrame::SimpleString(
            "    Print this help.".to_string()
        )));

        // Sanity on length: upstream emits ~50 lines (subcommand +
        // description + options); fr now has 53.
        assert!(
            items.len() >= 50,
            "expected ~50+ help lines, got {}",
            items.len()
        );
    }

    #[test]
    fn client_unblock_validates_id_and_mode() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[b"CLIENT".to_vec(), b"UNBLOCK".to_vec(), b"42".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(0));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"UNBLOCK".to_vec(),
                b"42".to_vec(),
                b"ERROR".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(0));

        // (br-frankenredis-cliunblockid) — upstream silently
        // returns 0 for UNBLOCK 0 / negatives since no client can
        // match; only non-numeric IDs surface InvalidInteger.
        let zero_ok = dispatch_argv(
            &[b"CLIENT".to_vec(), b"UNBLOCK".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(zero_ok, RespFrame::Integer(0));
        let neg_ok = dispatch_argv(
            &[b"CLIENT".to_vec(), b"UNBLOCK".to_vec(), b"-1".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(neg_ok, RespFrame::Integer(0));

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"UNBLOCK".to_vec(),
                b"42".to_vec(),
                b"WAT".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom(CLIENT_UNBLOCK_REASON_INVALID.to_string())
        );
    }

    #[test]
    fn client_unblock_rejected_from_scripts_after_arity_check() {
        // (frankenredis-ym2iw) Upstream commands.def line 1556 marks
        // CLIENT UNBLOCK with CMD_NOSCRIPT (arity = -3). Arity wins
        // over noscript; noscript wins over integer / mode validation.
        let mut store = Store::new();
        store.script_nesting_level = 1;

        let arity = dispatch_argv(&[b"CLIENT".to_vec(), b"UNBLOCK".to_vec()], &mut store, 0)
            .expect_err("client unblock arity");
        assert_eq!(arity, client_wrong_subcommand_arity("UNBLOCK"));

        // Every arity-correct scripted call — including non-numeric
        // ids and invalid modes — surfaces the noscript reply rather
        // than InvalidInteger / CLIENT_UNBLOCK_REASON_INVALID.
        for argv in [
            vec![b"CLIENT".to_vec(), b"UNBLOCK".to_vec(), b"0".to_vec()],
            vec![b"CLIENT".to_vec(), b"UNBLOCK".to_vec(), b"42".to_vec()],
            vec![b"CLIENT".to_vec(), b"UNBLOCK".to_vec(), b"abc".to_vec()],
            vec![
                b"CLIENT".to_vec(),
                b"UNBLOCK".to_vec(),
                b"42".to_vec(),
                b"TIMEOUT".to_vec(),
            ],
            vec![
                b"CLIENT".to_vec(),
                b"UNBLOCK".to_vec(),
                b"42".to_vec(),
                b"ERROR".to_vec(),
            ],
            vec![
                b"CLIENT".to_vec(),
                b"UNBLOCK".to_vec(),
                b"42".to_vec(),
                b"WAT".to_vec(),
            ],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("client unblock noscript");
            assert_eq!(
                err,
                CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()),
                "argv: {argv:?}"
            );
        }
    }

    #[test]
    fn client_list_supports_type_and_id_filters() {
        let mut store = Store::new();
        store.dispatch_client_ctx.client_id = 77;
        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"LIST".to_vec(),
                b"TYPE".to_vec(),
                b"NORMAL".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::BulkString(Some(payload)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        assert!(String::from_utf8_lossy(&payload).contains("id=77 "));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"LIST".to_vec(),
                b"TYPE".to_vec(),
                b"REPLICA".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(Vec::new())));

        store.dispatch_client_ctx.is_pubsub = true;
        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"LIST".to_vec(),
                b"TYPE".to_vec(),
                b"PUBSUB".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::BulkString(Some(payload)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        assert!(String::from_utf8_lossy(&payload).contains("id=77 "));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"LIST".to_vec(),
                b"ID".to_vec(),
                b"77".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::BulkString(Some(payload)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        assert!(String::from_utf8_lossy(&payload).contains("id=77 "));

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"LIST".to_vec(),
                b"TYPE".to_vec(),
                b"BOGUS".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR Unknown client type 'BOGUS'".to_string())
        );

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"LIST".to_vec(),
                b"ID".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        // (br-frankenredis-lkoh)
        assert_eq!(
            err,
            CommandError::Custom("ERR client-id should be greater than 0".to_string())
        );
    }

