    #[test]
    fn hrandfield_withvalues_resp3_emits_array_of_pairs() {
        // (br-frankenredis-f6z6) Upstream
        // t_hash.c::hrandfieldWithCountCommand wraps each (field, value)
        // in addReplyArrayLen(2) when in RESP3 mode, so the reply is an
        // Array of [field, value] sub-arrays — not a flat alternating-k/v
        // array as in RESP2.
        let mut store = Store::new();
        store.dispatch_client_ctx.resp_protocol_version = 3;
        dispatch_argv(
            &[
                b"HSET".to_vec(),
                b"h".to_vec(),
                b"f1".to_vec(),
                b"v1".to_vec(),
                b"f2".to_vec(),
                b"v2".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let out = dispatch_argv(
            &[
                b"HRANDFIELD".to_vec(),
                b"h".to_vec(),
                b"2".to_vec(),
                b"WITHVALUES".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::Array(Some(pairs)) = out else {
            panic!("expected outer array, got {out:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(pairs.len(), 2, "expected 2 pairs, got {pairs:?}");
        for pair in pairs {
            let RespFrame::Array(Some(kv)) = pair else {
                panic!("each pair must be a 2-element array, got {pair:?}"); // ubs:ignore — AI triage
            };
            assert_eq!(kv.len(), 2);
            assert!(matches!(kv[0], RespFrame::BulkString(Some(_))));
            assert!(matches!(kv[1], RespFrame::BulkString(Some(_))));
        }

        // RESP2 still emits the flat 4-element alternating array.
        store.dispatch_client_ctx.resp_protocol_version = 2;
        let out = dispatch_argv(
            &[
                b"HRANDFIELD".to_vec(),
                b"h".to_vec(),
                b"2".to_vec(),
                b"WITHVALUES".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::Array(Some(arr)) = out else {
            panic!("expected array, got {out:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(arr.len(), 4);
    }

    #[test]
    fn stream_full_group_lag_frame_matches_redis_estimable_cases() {
        assert_eq!(
            stream_full_group_lag_frame(3, 3, Some((1, 1)), Some((3, 1)), (0, 0), (0, 0), None),
            RespFrame::Integer(3)
        );
        assert_eq!(
            stream_full_group_lag_frame(3, 3, Some((1, 1)), Some((3, 1)), (0, 0), (1, 1), None),
            RespFrame::Integer(2)
        );
        assert_eq!(
            stream_full_group_lag_frame(3, 3, Some((1, 1)), Some((3, 1)), (2, 1), (3, 1), None),
            RespFrame::Integer(0)
        );
        assert_eq!(
            stream_full_group_lag_frame(3, 3, Some((1, 1)), Some((3, 1)), (2, 1), (2, 1), None),
            RespFrame::BulkString(None)
        );
        assert_eq!(
            stream_full_group_lag_frame(10, 3, Some((1, 1)), Some((3, 1)), (0, 0), (2, 1), Some(2)),
            RespFrame::Integer(8)
        );
        assert_eq!(
            stream_full_group_lag_frame(4, 3, Some((2, 0)), Some((4, 0)), (1, 0), (3, 0), Some(3)),
            RespFrame::Integer(1)
        );
        assert_eq!(
            stream_full_group_lag_frame(4, 3, Some((2, 0)), Some((4, 0)), (3, 0), (2, 0), Some(2)),
            RespFrame::BulkString(None)
        );
    }

    #[test]
    fn xinfo_stream_full_resp3_emits_map() {
        // (br-frankenredis-f6z6) Upstream xinfoFullCommand uses
        // addReplyMapLen for the FULL form's outer envelope. Match in
        // RESP3 (Map), keep flat alternating-array in RESP2.
        let mut store = Store::new();
        store.dispatch_client_ctx.resp_protocol_version = 3;
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"xs".to_vec(),
                b"*".to_vec(),
                b"a".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"xs".to_vec(),
                b"g".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATECONSUMER".to_vec(),
                b"xs".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"STREAMS".to_vec(),
                b"xs".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            10,
        )
        .unwrap();
        let out = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"STREAM".to_vec(),
                b"xs".to_vec(),
                b"FULL".to_vec(),
            ],
            &mut store,
            25,
        )
        .unwrap();
        let RespFrame::Map(Some(pairs)) = out else {
            panic!("expected RESP3 Map, got {out:?}"); // ubs:ignore — AI triage
        };
        let keys: Vec<&[u8]> = pairs
            .iter()
            .filter_map(|(k, _)| match k {
                RespFrame::BulkString(Some(b)) => Some(b.as_slice()),
                _ => None,
            })
            .collect();
        assert!(keys.contains(&b"length".as_slice()));
        assert!(keys.contains(&b"entries".as_slice()));
        assert!(keys.contains(&b"groups".as_slice()));
        let groups_value = pairs
            .iter()
            .find_map(|(k, v)| match k {
                RespFrame::BulkString(Some(name)) if name == b"groups" => Some(v),
                _ => None,
            })
            .expect("groups entry");
        let RespFrame::Array(Some(groups)) = groups_value else {
            panic!("groups should be an array, got {groups_value:?}"); // ubs:ignore — AI triage
        };
        let [RespFrame::Map(Some(group_pairs))] = groups.as_slice() else {
            panic!("FULL groups should contain RESP3 maps, got {groups:?}"); // ubs:ignore — AI triage
        };
        let group_keys: Vec<&[u8]> = group_pairs
            .iter()
            .filter_map(|(k, _)| match k {
                RespFrame::BulkString(Some(name)) => Some(name.as_slice()),
                _ => None,
            })
            .collect();
        assert_eq!(
            group_keys,
            vec![
                b"name".as_slice(),
                b"last-delivered-id".as_slice(),
                b"entries-read".as_slice(),
                b"lag".as_slice(),
                b"pel-count".as_slice(),
                b"pending".as_slice(),
                b"consumers".as_slice(),
            ]
        );
        let group_pending_value = group_pairs
            .iter()
            .find_map(|(k, v)| match k {
                RespFrame::BulkString(Some(name)) if name == b"pending" => Some(v),
                _ => None,
            })
            .expect("group pending entry");
        let RespFrame::Array(Some(group_pending)) = group_pending_value else {
            panic!("group pending should be an array, got {group_pending_value:?}"); // ubs:ignore — AI triage
        };
        let [RespFrame::Array(Some(group_pending_row))] = group_pending.as_slice() else {
            panic!("group pending should contain one row, got {group_pending:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(group_pending_row.len(), 4);
        assert_eq!(
            group_pending_row.get(1),
            Some(&RespFrame::BulkString(Some(b"c".to_vec())))
        );
        assert_eq!(group_pending_row.get(2), Some(&RespFrame::Integer(10)));
        assert_eq!(group_pending_row.get(3), Some(&RespFrame::Integer(1)));

        let consumers_value = group_pairs
            .iter()
            .find_map(|(k, v)| match k {
                RespFrame::BulkString(Some(name)) if name == b"consumers" => Some(v),
                _ => None,
            })
            .expect("consumers entry");
        let RespFrame::Array(Some(consumers)) = consumers_value else {
            panic!("consumers should be an array, got {consumers_value:?}"); // ubs:ignore — AI triage
        };
        let [RespFrame::Map(Some(consumer_pairs))] = consumers.as_slice() else {
            panic!("FULL consumers should contain RESP3 maps, got {consumers:?}"); // ubs:ignore — AI triage
        };
        let consumer_keys: Vec<&[u8]> = consumer_pairs
            .iter()
            .filter_map(|(k, _)| match k {
                RespFrame::BulkString(Some(name)) => Some(name.as_slice()),
                _ => None,
            })
            .collect();
        assert_eq!(
            consumer_keys,
            vec![
                b"name".as_slice(),
                b"seen-time".as_slice(),
                b"active-time".as_slice(),
                b"pel-count".as_slice(),
                b"pending".as_slice(),
            ]
        );
        let consumer_pending_value = consumer_pairs
            .iter()
            .find_map(|(k, v)| match k {
                RespFrame::BulkString(Some(name)) if name == b"pending" => Some(v),
                _ => None,
            })
            .expect("consumer pending entry");
        let RespFrame::Array(Some(consumer_pending)) = consumer_pending_value else {
            panic!("consumer pending should be an array, got {consumer_pending_value:?}"); // ubs:ignore — AI triage
        };
        let [RespFrame::Array(Some(consumer_pending_row))] = consumer_pending.as_slice() else {
            panic!("consumer pending should contain one row, got {consumer_pending:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(consumer_pending_row.len(), 3);
        assert_eq!(consumer_pending_row.get(1), Some(&RespFrame::Integer(10)));
        assert_eq!(consumer_pending_row.get(2), Some(&RespFrame::Integer(1)));

        let count_zero = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"STREAM".to_vec(),
                b"xs".to_vec(),
                b"FULL".to_vec(),
                b"COUNT".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            25,
        )
        .unwrap();
        let RespFrame::Map(Some(count_zero_pairs)) = count_zero else {
            panic!("expected COUNT 0 RESP3 Map, got {count_zero:?}"); // ubs:ignore — AI triage
        };
        let entries_value = count_zero_pairs
            .iter()
            .find_map(|(k, v)| match k {
                RespFrame::BulkString(Some(name)) if name == b"entries" => Some(v),
                _ => None,
            })
            .expect("entries entry");
        let RespFrame::Array(Some(entries)) = entries_value else {
            panic!("COUNT 0 entries should be an array, got {entries_value:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(entries.len(), 1, "COUNT 0 should mean unlimited");

        // RESP2 emits flat alternating array of the same pairs.
        store.dispatch_client_ctx.resp_protocol_version = 2;
        let out = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"STREAM".to_vec(),
                b"xs".to_vec(),
                b"FULL".to_vec(),
            ],
            &mut store,
            25,
        )
        .unwrap();
        let RespFrame::Array(Some(flat)) = out else {
            panic!("expected RESP2 Array, got {out:?}"); // ubs:ignore — AI triage
        };
        assert!(flat.len().is_multiple_of(2) && flat.len() >= 18);
        let groups_pos = flat
            .iter()
            .position(|frame| *frame == RespFrame::BulkString(Some(b"groups".to_vec())))
            .expect("RESP2 groups key");
        let RespFrame::Array(Some(groups)) = &flat[groups_pos + 1] else {
            panic!(
                "RESP2 groups should be an array, got {:?}",
                flat[groups_pos + 1]
            ); // ubs:ignore — AI triage
        };
        let [RespFrame::Array(Some(group_flat))] = groups.as_slice() else {
            panic!("RESP2 FULL groups should contain alternating arrays, got {groups:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(
            group_flat.first(),
            Some(&RespFrame::BulkString(Some(b"name".to_vec())))
        );
        assert!(group_flat.contains(&RespFrame::BulkString(Some(b"pel-count".to_vec()))));
        assert!(group_flat.contains(&RespFrame::BulkString(Some(b"consumers".to_vec()))));
    }

