    #[test]
    fn object_refcount_reports_int_max_for_shared_integer_objects() {
        // (frankenredis-ljrt6) Upstream tryObjectEncoding interns canonical
        // decimal integers in [0, OBJ_SHARED_INTEGERS=10000) when shared
        // integers are enabled (default maxmemory == 0 or a non-LRU/LFU
        // policy). The interned object's refcount is OBJ_SHARED_REFCOUNT
        // = INT_MAX = i32::MAX.
        let mut store = Store::new();

        // Small integer in [0, 10000) — shared object.
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"5".to_vec()],
            &mut store,
            0,
        )
        .expect("set k 5");
        let out = dispatch_argv(
            &[b"OBJECT".to_vec(), b"REFCOUNT".to_vec(), b"k".to_vec()],
            &mut store,
            1,
        )
        .expect("refcount k");
        assert_eq!(out, RespFrame::Integer(i64::from(i32::MAX)));

        // Boundary: 9999 (shared).
        dispatch_argv(
            &[b"SET".to_vec(), b"hi".to_vec(), b"9999".to_vec()],
            &mut store,
            2,
        )
        .expect("set hi 9999");
        assert_eq!(
            dispatch_argv(
                &[b"OBJECT".to_vec(), b"REFCOUNT".to_vec(), b"hi".to_vec()],
                &mut store,
                3,
            )
            .expect("refcount hi"),
            RespFrame::Integer(i64::from(i32::MAX))
        );

        // Boundary: 10000 (NOT shared — refcount 1).
        dispatch_argv(
            &[b"SET".to_vec(), b"big".to_vec(), b"10000".to_vec()],
            &mut store,
            4,
        )
        .expect("set big 10000");
        assert_eq!(
            dispatch_argv(
                &[
                    b"OBJECT".to_vec(),
                    b"REFCOUNT".to_vec(),
                    b"big".to_vec(),
                ],
                &mut store,
                5,
            )
            .expect("refcount big"),
            RespFrame::Integer(1)
        );

        // Negative integer: NOT shared.
        dispatch_argv(
            &[b"SET".to_vec(), b"neg".to_vec(), b"-1".to_vec()],
            &mut store,
            6,
        )
        .expect("set neg -1");
        assert_eq!(
            dispatch_argv(
                &[
                    b"OBJECT".to_vec(),
                    b"REFCOUNT".to_vec(),
                    b"neg".to_vec(),
                ],
                &mut store,
                7,
            )
            .expect("refcount neg"),
            RespFrame::Integer(1)
        );

        // LRU/LFU policy with maxmemory > 0 disables shared integers.
        store.maxmemory_policy = fr_store::MaxmemoryPolicy::AllkeysLru;
        store.maxmemory_bytes_live = 1024 * 1024;
        dispatch_argv(
            &[b"SET".to_vec(), b"lk".to_vec(), b"7".to_vec()],
            &mut store,
            8,
        )
        .expect("set lk 7");
        assert_eq!(
            dispatch_argv(
                &[b"OBJECT".to_vec(), b"REFCOUNT".to_vec(), b"lk".to_vec()],
                &mut store,
                9,
            )
            .expect("refcount lk under LRU+maxmemory"),
            RespFrame::Integer(1)
        );
    }

    #[test]
    fn object_freq_matches_lfu_policy_gating_and_counter_semantics() {
        let mut store = Store::new();

        dispatch_argv(
            &[b"SET".to_vec(), b"obj".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("seed key");

        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"missing".to_vec()],
            &mut store,
            1,
        )
        .expect("missing freq reply");
        assert_eq!(reply, RespFrame::BulkString(None));

        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            2,
        )
        .expect("non-lfu freq reply");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR An LFU maxmemory policy is not selected, access frequency not tracked. Please note that when switching between policies at runtime LRU and LFU data will take some time to adjust.".to_string()
            )
        );

        dispatch_argv(
            &[
                b"CONFIG".to_vec(),
                b"SET".to_vec(),
                b"maxmemory-policy".to_vec(),
                b"allkeys-lfu".to_vec(),
            ],
            &mut store,
            3,
        )
        .expect("enable lfu");

        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            4,
        )
        .expect("lfu freq reply");
        assert_eq!(reply, RespFrame::Integer(0));

        dispatch_argv(&[b"GET".to_vec(), b"obj".to_vec()], &mut store, 5).expect("get obj");
        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            6,
        )
        .expect("lfu freq after get");
        assert_eq!(reply, RespFrame::Integer(1));

        dispatch_argv(
            &[b"SET".to_vec(), b"obj".to_vec(), b"vv".to_vec()],
            &mut store,
            7,
        )
        .expect("overwrite obj");
        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            8,
        )
        .expect("lfu freq after overwrite");
        assert_eq!(reply, RespFrame::Integer(2));

        dispatch_argv(
            &[
                b"CONFIG".to_vec(),
                b"SET".to_vec(),
                b"maxmemory-policy".to_vec(),
                b"allkeys-lru".to_vec(),
            ],
            &mut store,
            9,
        )
        .expect("disable lfu");
        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            10,
        )
        .expect("non-lfu freq reply after switch");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR An LFU maxmemory policy is not selected, access frequency not tracked. Please note that when switching between policies at runtime LRU and LFU data will take some time to adjust.".to_string()
            )
        );
    }

    #[test]
    fn object_freq_applies_lfu_decay_time_before_reporting() {
        let mut store = Store::new();

        dispatch_argv(
            &[b"SET".to_vec(), b"obj".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("seed key");
        dispatch_argv(
            &[
                b"CONFIG".to_vec(),
                b"SET".to_vec(),
                b"maxmemory-policy".to_vec(),
                b"allkeys-lfu".to_vec(),
                b"lfu-decay-time".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            1,
        )
        .expect("enable lfu with decay");

        dispatch_argv(&[b"GET".to_vec(), b"obj".to_vec()], &mut store, 2).expect("first get");
        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            3,
        )
        .expect("freq after first get");
        assert_eq!(reply, RespFrame::Integer(1));

        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            60_000,
        )
        .expect("freq after decay window");
        assert_eq!(reply, RespFrame::Integer(0));

        dispatch_argv(&[b"GET".to_vec(), b"obj".to_vec()], &mut store, 60_001)
            .expect("get after decay");
        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"FREQ".to_vec(), b"obj".to_vec()],
            &mut store,
            60_002,
        )
        .expect("freq after decayed access");
        assert_eq!(reply, RespFrame::Integer(1));
    }

    #[test]
    fn object_idletime_matches_missing_and_lfu_policy_gating() {
        let mut store = Store::new();

        let reply = dispatch_argv(
            &[
                b"OBJECT".to_vec(),
                b"IDLETIME".to_vec(),
                b"missing".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("missing idletime reply");
        assert_eq!(reply, RespFrame::BulkString(None));

        dispatch_argv(
            &[b"SET".to_vec(), b"obj".to_vec(), b"v".to_vec()],
            &mut store,
            1,
        )
        .expect("seed key");

        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"IDLETIME".to_vec(), b"obj".to_vec()],
            &mut store,
            2_500,
        )
        .expect("non-lfu idletime reply");
        assert_eq!(reply, RespFrame::Integer(2));

        dispatch_argv(
            &[
                b"CONFIG".to_vec(),
                b"SET".to_vec(),
                b"maxmemory-policy".to_vec(),
                b"allkeys-lfu".to_vec(),
            ],
            &mut store,
            2_501,
        )
        .expect("enable lfu");

        let reply = dispatch_argv(
            &[b"OBJECT".to_vec(), b"IDLETIME".to_vec(), b"obj".to_vec()],
            &mut store,
            2_502,
        )
        .expect("lfu idletime reply");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR An LFU maxmemory policy is selected, idle time not tracked. Please note that when switching between policies at runtime LRU and LFU data will take some time to adjust.".to_string()
            )
        );
    }

